function hideAllScreens() {
    const screens = document.querySelectorAll('.screen');
    screens.forEach((screen) => {
        screen.classList.remove('active', 'auth-screen-enter');
    });
    const app = document.getElementById('app');
    if (app) app.classList.remove('wide', 'auth-mode');
}

function activateScreen(screenId, options = {}) {
    const screen = document.getElementById(screenId);
    if (!screen) return false;
    hideAllScreens();
    screen.classList.add('active');
    const app = document.getElementById('app');
    if (app && screen.classList.contains('auth-screen')) {
        app.classList.add('auth-mode');
    }

    if (options.animate) {
        screen.classList.remove('auth-screen-enter');
        void screen.offsetWidth;
        screen.classList.add('auth-screen-enter');
        setTimeout(() => screen.classList.remove('auth-screen-enter'), 340);
    }

    return true;
}

function clearDashboardRuntimeTimers() {
    if (trainerDashboardRefreshTimer) {
        clearTimeout(trainerDashboardRefreshTimer);
        trainerDashboardRefreshTimer = null;
    }
    if (studentDashboardRefreshTimer) {
        clearTimeout(studentDashboardRefreshTimer);
        studentDashboardRefreshTimer = null;
    }
    if (typeof syncPullTimer !== 'undefined' && syncPullTimer) {
        clearInterval(syncPullTimer);
        syncPullTimer = null;
    }
    if (typeof syncPushTimer !== 'undefined' && syncPushTimer) {
        clearTimeout(syncPushTimer);
        syncPushTimer = null;
    }
    if (typeof supabaseStudentsSyncTimer !== 'undefined' && supabaseStudentsSyncTimer) {
        clearTimeout(supabaseStudentsSyncTimer);
        supabaseStudentsSyncTimer = null;
    }
    if (typeof batchedStudentsSyncTimer !== 'undefined' && batchedStudentsSyncTimer) {
        clearTimeout(batchedStudentsSyncTimer);
        batchedStudentsSyncTimer = null;
    }
    if (typeof supabaseFoodsSyncTimer !== 'undefined' && supabaseFoodsSyncTimer) {
        clearTimeout(supabaseFoodsSyncTimer);
        supabaseFoodsSyncTimer = null;
    }
    if (typeof supabaseRealtimeRefreshTimer !== 'undefined' && supabaseRealtimeRefreshTimer) {
        clearTimeout(supabaseRealtimeRefreshTimer);
        supabaseRealtimeRefreshTimer = null;
    }
    if (typeof batchedStudentsSyncPayload !== 'undefined') {
        batchedStudentsSyncPayload = null;
    }
    if (typeof supabaseStudentsSyncQueuedPayload !== 'undefined') {
        supabaseStudentsSyncQueuedPayload = null;
    }
    // Invalida boots pendentes do dashboard do aluno.
    studentDashboardBootToken += 1;
    studentDashboardBootPromise = null;
    if (typeof stopCardioTimerRuntime === 'function') stopCardioTimerRuntime();
}

const MOBILE_DASHBOARD_BREAKPOINT = 900;
const MOBILE_DASHBOARD_COARSE_MAX_WIDTH = 1100;
let mobileDashboardModeRaf = 0;

function isMobileDashboardMode() {
    const width = Number(window.innerWidth || 0);
    const screenWidth = Number(window.screen?.width || width || 0);
    const narrowByWidth = width > 0 ? width <= MOBILE_DASHBOARD_BREAKPOINT : false;
    const hasCoarsePointer = !!(window.matchMedia && window.matchMedia('(pointer: coarse)').matches);
    const coarseWidthAllowed = Math.min(width || screenWidth, screenWidth || width) <= MOBILE_DASHBOARD_COARSE_MAX_WIDTH;
    return narrowByWidth || (hasCoarsePointer && coarseWidthAllowed);
}

function applyMobileDashboardMode(force = false) {
    const body = document.body;
    if (!body) return false;
    const nextMode = isMobileDashboardMode();
    const prevMode = body.classList.contains('mobile-dashboard-mode');
    if (nextMode) body.classList.add('mobile-dashboard-mode');
    else body.classList.remove('mobile-dashboard-mode');
    return force ? nextMode : (nextMode !== prevMode ? nextMode : prevMode);
}

function scheduleApplyMobileDashboardMode() {
    if (mobileDashboardModeRaf) cancelAnimationFrame(mobileDashboardModeRaf);
    mobileDashboardModeRaf = requestAnimationFrame(() => {
        mobileDashboardModeRaf = 0;
        applyMobileDashboardMode();
    });
}

window.addEventListener('resize', scheduleApplyMobileDashboardMode, { passive: true });
window.addEventListener('orientationchange', scheduleApplyMobileDashboardMode);
window.addEventListener('pageshow', () => applyMobileDashboardMode());


const appStorage = (() => {
    const memoryStore = new Map();
    const safeMemory = {
        getItem: (key) => (memoryStore.has(key) ? memoryStore.get(key) : null),
        setItem: (key, value) => memoryStore.set(String(key), String(value)),
        removeItem: (key) => memoryStore.delete(String(key)),
        clear: () => memoryStore.clear()
    };

    const hasLocalStorage = (() => {
        try {
            const testKey = '__consultoria_test__';
            window.localStorage.setItem(testKey, '1');
            window.localStorage.removeItem(testKey);
            return true;
        } catch (err) {
            return false;
        }
    })();

    let storageQuotaExceeded = false;
    const volatileKeys = ['trainerNotifications', 'workoutHistory'];

    const tryLocalSet = (key, value) => {
        window.localStorage.setItem(String(key), String(value));
        return true;
    };

    const tryRecoverLocalStorageQuota = () => {
        try {
            volatileKeys.forEach((k) => {
                const existing = window.localStorage.getItem(k);
                if (!existing) return;
                if (k === 'trainerNotifications') {
                    const parsed = JSON.parse(existing);
                    if (Array.isArray(parsed) && parsed.length > 80) {
                        window.localStorage.setItem(k, JSON.stringify(parsed.slice(0, 80)));
                    }
                }
                if (k === 'workoutHistory') {
                    const parsed = JSON.parse(existing);
                    if (Array.isArray(parsed) && parsed.length > 180) {
                        window.localStorage.setItem(k, JSON.stringify(parsed.slice(-180)));
                    }
                }
            });
        } catch {
            // noop
        }
    };

    return {
        getItem: (key) => {
            const safeKey = String(key);
            if (hasLocalStorage) {
                const localValue = window.localStorage.getItem(safeKey);
                if (localValue !== null) return localValue;
            }
            return safeMemory.getItem(safeKey);
        },
        setItem: (key, value) => {
            const safeKey = String(key);
            const safeValue = String(value);
            if (!hasLocalStorage) {
                safeMemory.setItem(safeKey, safeValue);
                return;
            }
            try {
                tryLocalSet(safeKey, safeValue);
                storageQuotaExceeded = false;
            } catch (err) {
                tryRecoverLocalStorageQuota();
                try {
                    tryLocalSet(safeKey, safeValue);
                    storageQuotaExceeded = false;
                } catch (retryErr) {
                    safeMemory.setItem(safeKey, safeValue);
                    storageQuotaExceeded = true;
                    console.error('Falha ao persistir no localStorage. Dados mantidos temporariamente em memória até liberar espaço.', retryErr);
                }
            }
        },
        removeItem: (key) => {
            const safeKey = String(key);
            if (hasLocalStorage) window.localStorage.removeItem(safeKey);
            safeMemory.removeItem(safeKey);
        },
        clear: () => {
            if (hasLocalStorage) window.localStorage.clear();
            safeMemory.clear();
        },
        isPersistent: () => hasLocalStorage && !storageQuotaExceeded
    };
})();

function memoryGetItem(key) {
    return appStorage.getItem(key);
}
function memorySetItem(key, value) {
    appStorage.setItem(key, value);
}
function memoryRemoveItem(key) {
    appStorage.removeItem(key);
}
function memoryClear() {
    appStorage.clear();
}

