function triggerHaptic(durationMs = 20) {
    try {
        if (window.navigator && typeof window.navigator.vibrate === 'function') {
            window.navigator.vibrate(durationMs);
        }
    } catch {
        // ignora erros de vibração
    }
}

async function scheduleCompletedWorkoutSync() {
    try {
        if (!('serviceWorker' in navigator) || !('SyncManager' in window)) return;
        const registration = await navigator.serviceWorker.ready;
        await registration.sync.register('sync-completed-workouts');
    } catch {
        // falha silenciosa; o app continua funcionando offline-first
    }
}

function upgradeSidebarNavIcons() {
    try {
        const trainerSidebar = document.querySelector('#trainer-dashboard-screen .sidebar');
        if (!trainerSidebar) return;

        const mapping = {
            'nav-dashboard': 'nav-dashboard',
            'nav-alunos': 'nav-alunos',
            'nav-duvidas': 'nav-duvidas',
            'nav-config': 'nav-config'
        };

        Object.entries(mapping).forEach(([id, iconName]) => {
            const item = document.getElementById(id);
            if (!item) return;
            const iEl = item.querySelector('i');
            if (!iEl) return;
            const wrapper = document.createElement('span');
            wrapper.innerHTML = uiSvgIcon(iconName);
            const svg = wrapper.firstElementChild;
            if (svg) iEl.replaceWith(svg);
        });

        const extraMap = [
            { selector: '.sidebar-footer .btn-logout i', icon: 'nav-logout' }
        ];

        extraMap.forEach(({ selector, icon }) => {
            const iEl = trainerSidebar.querySelector(selector);
            if (!iEl) return;
            const wrapper = document.createElement('span');
            wrapper.innerHTML = uiSvgIcon(icon);
            const svg = wrapper.firstElementChild;
            if (svg) iEl.replaceWith(svg);
        });
    } catch {
        // fail silently to avoid breaking app
    }
}

let deferredInstallPrompt = null;

window.addEventListener('beforeinstallprompt', (event) => {
    event.preventDefault();
    deferredInstallPrompt = event;
    const btn = document.getElementById('install-app-btn');
    if (btn) {
        btn.style.display = 'inline-flex';
    }
});

window.addEventListener('appinstalled', () => {
    deferredInstallPrompt = null;
    const btn = document.getElementById('install-app-btn');
    if (btn) {
        btn.style.display = 'none';
    }
});

function setupInstallButton() {
    const btn = document.getElementById('install-app-btn');
    if (!btn) return;
    btn.addEventListener('click', async () => {
        if (!deferredInstallPrompt) {
            btn.style.display = 'none';
            return;
        }
        try {
            deferredInstallPrompt.prompt();
            const { outcome } = await deferredInstallPrompt.userChoice;
            if (outcome === 'accepted') {
                btn.style.display = 'none';
            }
        } catch {
            // ignore
        } finally {
            deferredInstallPrompt = null;
        }
    });
}

function validateFormFields(form) {
    if (!(form instanceof HTMLFormElement)) return true;

    const emailFields = form.querySelectorAll('input[type="email"]');
    for (const emailField of emailFields) {
        if (!(emailField instanceof HTMLInputElement)) continue;
        const value = sanitizeEmailInput(emailField.value);
        emailField.value = value;
        if (value && !EMAIL_REGEX.test(value)) {
            emailField.setCustomValidity('Informe um e-mail válido.');
            emailField.reportValidity();
            return false;
        }
        emailField.setCustomValidity('');
    }

    if (!form.checkValidity()) {
        form.reportValidity();
        return false;
    }

    return true;
}

function setupClientSideFormProtection() {
    if (document.documentElement.dataset.formsGuardInit === '1') return;
    document.documentElement.dataset.formsGuardInit = '1';

    document.addEventListener('submit', (event) => {
        const form = event.target;
        if (!(form instanceof HTMLFormElement)) return;

        sanitizeFormFields(form);
        const isValid = validateFormFields(form);
        if (!isValid) {
            event.preventDefault();
            event.stopPropagation();
        }
    }, true);
}

function studentCanEditWorkout(student) {
    const id = String(student?.id || '');
    return !!student?.canSelfEditWorkout || (ENABLE_DEMO_ACCESS && SELF_TRAINING_STUDENT_CODES.includes(id));
}

function ensureSelfTrainingStudent() {
    if (!ENABLE_DEMO_ACCESS) return;
    const students = readStorageJSON('trainerStudents', []);
    const nowIso = new Date().toISOString();
    const selfLastWorkout = new Date();
    selfLastWorkout.setDate(selfLastWorkout.getDate() - 6);
    const baselineMetric = {
        date: nowIso,
        weight: 82,
        bodyFat: 18,
        height: 178
    };
    const defaultWorkoutBlocks = getDefaultWorkoutBlocks();

    const selfStudent = {
        id: SELF_TRAINING_STUDENT_CODE,
        name: SELF_TRAINING_STUDENT_NAME,
        age: '29',
        gender: 'M',
        goal: 'Auto Treino',
        weight: '82',
        height: '178',
        bodyFat: '18',
        status: 'Ativo',
        active: true,
        pending: false,
        dailyKcal: 2600,
        trainerCode: '00001',
        workoutBlocks: defaultWorkoutBlocks,
        mealBlocks: [],
        lastWorkoutAt: selfLastWorkout.toISOString(),
        assessmentPending: false,
        metricHistory: [baselineMetric],
        progressLogs: [{ date: new Date().toISOString().slice(0, 10), weight: 82, notes: 'Perfil Aluno Teste auto-treino.' }],
        personalRecords: {}
    };
    selfStudent.tmbBase = Math.round(calcTMBMifflin(selfStudent.weight, selfStudent.height, selfStudent.age, selfStudent.gender));
    const selfDietBase = createDietBaseFromStudent(selfStudent);
    selfStudent.mealBlocks = selfDietBase.mealBlocks;
    selfStudent.dietMeta = selfDietBase.dietMeta;

    const idx = students.findIndex(s => s.id === SELF_TRAINING_STUDENT_CODE);
    if (idx === -1) {
        students.push(selfStudent);
    } else {
        const current = students[idx] || {};
        students[idx] = {
            ...selfStudent,
            ...current,
            id: SELF_TRAINING_STUDENT_CODE,
            name: SELF_TRAINING_STUDENT_NAME,
            active: true,
            pending: false,
            trainerCode: current.trainerCode || '00001',
            lastWorkoutAt: current.lastWorkoutAt || selfLastWorkout.toISOString(),
            assessmentPending: current.assessmentPending ?? false,
            workoutBlocks: Array.isArray(current.workoutBlocks) && current.workoutBlocks.length > 0
                ? current.workoutBlocks
                : defaultWorkoutBlocks,
            mealBlocks: Array.isArray(current.mealBlocks) && current.mealBlocks.length > 0
                ? current.mealBlocks
                : selfDietBase.mealBlocks,
            dietMeta: current.dietMeta && typeof current.dietMeta === 'object'
                ? current.dietMeta
                : selfDietBase.dietMeta
        };
    }

    const selfStudentId = idx === -1 ? SELF_TRAINING_STUDENT_CODE : String(students[idx]?.id || SELF_TRAINING_STUDENT_CODE);
    saveStudentData(students, { studentId: selfStudentId });
}

function ensureAdminStudent() {
    if (!ENABLE_DEMO_ACCESS) return;
    const students = readStorageJSON('trainerStudents', []);
    const nowIso = new Date().toISOString();
    const adminLastWorkout = new Date();
    adminLastWorkout.setDate(adminLastWorkout.getDate() - 3);
    const baselineMetric = {
        date: nowIso,
        weight: 78,
        bodyFat: 17,
        height: 178
    };

    const demoStudent = {
        id: ADMIN_STUDENT_CODE,
        name: ADMIN_STUDENT_NAME,
        age: '28',
        gender: 'M',
        goal: 'Hipertrofia',
        weight: '78',
        height: '178',
        bodyFat: '17',
        status: 'Ativo',
        active: true,
        pending: false,
        dailyKcal: 2500,
        trainerCode: '00001',
        workoutBlocks: DEMO_WORKOUT_BLOCKS,
        mealBlocks: [],
        lastWorkoutAt: adminLastWorkout.toISOString(),
        assessmentPending: true,
        metricHistory: [baselineMetric],
        progressLogs: [{ date: new Date().toISOString().slice(0, 10), weight: 78, notes: 'Perfil Aluno Teste inicial.' }],
        personalRecords: {}
    };
    demoStudent.tmbBase = Math.round(calcTMBMifflin(demoStudent.weight, demoStudent.height, demoStudent.age, demoStudent.gender));
    const demoDietBase = createDietBaseFromStudent(demoStudent);
    demoStudent.mealBlocks = demoDietBase.mealBlocks;
    demoStudent.dietMeta = demoDietBase.dietMeta;

    const idx = students.findIndex(s => s.id === ADMIN_STUDENT_CODE);
    if (idx === -1) {
        students.push(demoStudent);
    } else {
        const current = students[idx] || {};
        students[idx] = {
            ...demoStudent,
            ...current,
            id: ADMIN_STUDENT_CODE,
            name: ADMIN_STUDENT_NAME,
            active: true,
            pending: false,
            trainerCode: current.trainerCode || '00001',
            lastWorkoutAt: current.lastWorkoutAt || adminLastWorkout.toISOString(),
            assessmentPending: current.assessmentPending ?? true,
            workoutBlocks: Array.isArray(current.workoutBlocks) && current.workoutBlocks.length > 0 ? current.workoutBlocks : DEMO_WORKOUT_BLOCKS,
            mealBlocks: Array.isArray(current.mealBlocks) && current.mealBlocks.length > 0 ? current.mealBlocks : demoDietBase.mealBlocks,
            dietMeta: current.dietMeta && typeof current.dietMeta === 'object'
                ? current.dietMeta
                : demoDietBase.dietMeta,
            metricHistory: Array.isArray(current.metricHistory) && current.metricHistory.length > 0 ? current.metricHistory : [baselineMetric]
        };
    }

    const demoStudentId = idx === -1 ? ADMIN_STUDENT_CODE : String(students[idx]?.id || ADMIN_STUDENT_CODE);
    saveStudentData(students, { studentId: demoStudentId });
}

function buildEvaluationTrainerIdentity() {
    return {
        code: EVALUATION_TRAINER_CODE,
        name: EVALUATION_TRAINER_NAME,
        displayName: EVALUATION_TRAINER_NAME,
        consultoriaName: 'Consultoria Teste',
        services: 'ambos',
        headline: 'Painel local para avaliar fluxos de treino, dieta e alunos.',
        bio: 'Perfil de teste local. Use para testar o dashboard sem login real.',
        specialties: ['Hipertrofia', 'Emagrecimento', 'Nutrição'],
        handle: 'teste.consultoria',
        themePreset: TRAINER_THEME_PRESETS[0],
        onboardingComplete: true
    };
}

function ensureEvaluationDemoData() {
    if (!ENABLE_DEMO_ACCESS) return null;
    removeLegacyEvaluationStudents();
    ensureAdminStudent();
    const trainerIdentity = cacheTrainerLocal(buildEvaluationTrainerIdentity());
    memorySetItem('trainerName', 'Teste');
    memorySetItem('currentTrainerCode', EVALUATION_TRAINER_CODE);
    memorySetItem('trainerCodeDefault', EVALUATION_TRAINER_CODE);
    return trainerIdentity || buildEvaluationTrainerIdentity();
}

function setTrainerEvaluationMode(enabled = false) {
    if (enabled && ENABLE_DEMO_ACCESS) {
        memorySetItem(TRAINER_EVALUATION_MODE_KEY, '1');
        return true;
    }
    memoryRemoveItem(TRAINER_EVALUATION_MODE_KEY);
    return false;
}

function isTrainerEvaluationModeActive() {
    return ENABLE_DEMO_ACCESS && memoryGetItem(TRAINER_EVALUATION_MODE_KEY) === '1';
}

function getCurrentRuntimeRoles() {
    const candidates = [];
    try {
        const parsed = JSON.parse(memoryGetItem('currentUserRoles') || '[]');
        if (Array.isArray(parsed)) candidates.push(...parsed);
    } catch {
        // Ignore malformed local role cache.
    }
    const legacy = memoryGetItem('currentUserRole') || '';
    if (legacy) candidates.push(legacy);
    const normalized = [];
    candidates.forEach((entry) => {
        const raw = String(entry || '').trim().toLowerCase();
        const role = normalizeAppRole(raw) || (['admin', 'dev', 'tester', 'beta'].includes(raw) ? raw : '');
        if (role && !normalized.includes(role)) normalized.push(role);
    });
    return normalized;
}

function isEvaluationTrainerRuntimeContext() {
    const code = sanitizeCodeInput(
        memoryGetItem('currentTrainerCode') || memoryGetItem('trainerCodeDefault') || '',
        5
    );
    return isTrainerEvaluationModeActive() && code === EVALUATION_TRAINER_CODE;
}

function canUseTestAccountSwitcherFromTrainer() {
    const dashboard = document.getElementById('trainer-dashboard-screen');
    if (!ENABLE_DEMO_ACCESS || !isEvaluationTrainerRuntimeContext() || !dashboard?.classList.contains('active')) {
        return false;
    }
    const roles = getCurrentRuntimeRoles();
    return roles.length === 0 || roles.includes('trainer') || roles.includes('admin') || roles.includes('dev') || roles.includes('tester') || roles.includes('beta');
}

function getTestAccountSwitchContext() {
    try {
        const context = JSON.parse(memoryGetItem(TEST_ACCOUNT_SWITCH_CONTEXT_KEY) || 'null');
        if (!context || typeof context !== 'object') return null;
        return context;
    } catch {
        return null;
    }
}

function isTestStudentSwitchActive() {
    const context = getTestAccountSwitchContext();
    return ENABLE_DEMO_ACCESS
        && isTrainerEvaluationModeActive()
        && memoryGetItem(TEST_ACCOUNT_SWITCH_MODE_KEY) === 'student-test'
        && String(memoryGetItem('currentStudentId') || '') === String(ADMIN_STUDENT_CODE)
        && context?.trainerCode === EVALUATION_TRAINER_CODE
        && context?.source === 'trainer-evaluation';
}

function setRuntimeRoleForTestSwitch(role = 'trainer') {
    const normalizedRole = normalizeAppRole(role) || 'trainer';
    memorySetItem('currentUserRoles', JSON.stringify([normalizedRole]));
    memorySetItem('currentUserRole', normalizedRole);
}

function saveTrainerTestSwitchContext() {
    const context = {
        source: 'trainer-evaluation',
        trainerCode: EVALUATION_TRAINER_CODE,
        trainerName: memoryGetItem('trainerName') || EVALUATION_TRAINER_NAME,
        currentTrainerCode: memoryGetItem('currentTrainerCode') || EVALUATION_TRAINER_CODE,
        trainerCodeDefault: memoryGetItem('trainerCodeDefault') || EVALUATION_TRAINER_CODE,
        roles: getCurrentRuntimeRoles(),
        createdAt: new Date().toISOString(),
        returnUrl: 'trainer.html#/alunos'
    };
    memorySetItem(TEST_ACCOUNT_SWITCH_CONTEXT_KEY, JSON.stringify(context));
    return context;
}

function clearTestAccountSwitchContext() {
    memoryRemoveItem(TEST_ACCOUNT_SWITCH_MODE_KEY);
    memoryRemoveItem(TEST_ACCOUNT_SWITCH_CONTEXT_KEY);
}

function syncTestAccountSwitcherUI(root = document) {
    const scope = root && root.querySelectorAll ? root : document;
    const showTrainerSwitcher = canUseTestAccountSwitcherFromTrainer();
    scope.querySelectorAll('[data-test-account-switcher="trainer"]').forEach((el) => {
        el.style.display = showTrainerSwitcher ? '' : 'none';
        el.setAttribute('aria-hidden', showTrainerSwitcher ? 'false' : 'true');
    });

    const studentSwitchActive = isTestStudentSwitchActive();
    const studentDashboard = document.getElementById('student-dashboard-screen');
    if (studentDashboard) {
        studentDashboard.classList.toggle('test-student-switch-active', studentSwitchActive);
    }
    scope.querySelectorAll('[data-test-account-switcher="student"]').forEach((el) => {
        el.style.display = studentSwitchActive ? '' : 'none';
        el.setAttribute('aria-hidden', studentSwitchActive ? 'false' : 'true');
    });
}

function getEvaluationSandboxStudentIds() {
    return new Set([String(ADMIN_STUDENT_CODE), String(SELF_TRAINING_STUDENT_CODE)]);
}

function isEvaluationSandboxRecord(record = {}) {
    if (!record || typeof record !== 'object') return false;
    const demoIds = getEvaluationSandboxStudentIds();
    const recordIds = [
        record.id,
        record.studentId,
        record.student_id,
        record.ID_Usuario,
        record.userId,
        record.user_id
    ].map((value) => String(value || '').trim()).filter(Boolean);
    if (recordIds.some((id) => demoIds.has(id))) return true;

    const trainerCode = sanitizeCodeInput(
        record.trainerCode || record.trainer_code || record.currentTrainerCode || record.connectedTrainerCode || '',
        5
    );
    return trainerCode === EVALUATION_TRAINER_CODE;
}

function removeLegacyEvaluationStudents() {
    if (!ENABLE_DEMO_ACCESS) return;
    const students = readStorageJSON('trainerStudents', []);
    if (!Array.isArray(students) || students.length === 0) return;
    const cleaned = students.filter((student) => {
        const id = String(student?.id || '').trim();
        if (id === String(ADMIN_STUDENT_CODE)) return true;
        if (id === String(SELF_TRAINING_STUDENT_CODE)) return false;
        return !isEvaluationSandboxRecord(student);
    });
    if (cleaned.length !== students.length) {
        saveStudentData(cleaned, {
            skipSupabaseSync: true,
            stampDataUpdatedAt: false,
            syncMode: 'local-only'
        });
    }
}

function filterEvaluationSandboxRecords(records) {
    return Array.isArray(records) ? records.filter((record) => !isEvaluationSandboxRecord(record)) : [];
}

function clearEvaluationSandboxRuntimeContext() {
    [
        TRAINER_EVALUATION_MODE_KEY,
        'currentStudentId',
        'connectedTrainerCode',
        'studentName',
        'trainerName',
        'currentTrainerCode',
        'trainerCodeDefault',
        'currentAnamnesis',
        'currentUserId',
        'currentUserEmail',
        'currentUserName',
        'currentUserRoles',
        'currentUserRole',
        'currentOnboardingStep'
    ].forEach((key) => memoryRemoveItem(key));
}

function resetEvaluationSandbox() {
    if (!ENABLE_DEMO_ACCESS) {
        const message = 'Sandbox disponivel apenas em ambiente local.';
        showEvaluationAccessUnavailable();
        return { ok: false, message };
    }

    const previousEvaluationMode = isTrainerEvaluationModeActive();
    setTrainerEvaluationMode(true);

    const students = readStorageJSON('trainerStudents', []);
    saveStudentData(filterEvaluationSandboxRecords(students), {
        skipSupabaseSync: true,
        stampDataUpdatedAt: false,
        syncMode: 'local-only'
    });

    const trainers = readStorageJSON('allTrainers', []);
    memorySetItem(
        'allTrainers',
        JSON.stringify(trainers.filter((trainer) => sanitizeCodeInput(trainer?.code || '', 5) !== EVALUATION_TRAINER_CODE))
    );

    memorySetItem('trainerNotifications', JSON.stringify(filterEvaluationSandboxRecords(readStorageJSON('trainerNotifications', []))));
    memorySetItem('workoutHistory', JSON.stringify(filterEvaluationSandboxRecords(readStorageJSON('workoutHistory', []))));
    getEvaluationSandboxStudentIds().forEach((studentId) => {
        memoryRemoveItem(`student_chat_v1_${studentId}`);
        memoryRemoveItem(`student_chat_beta_${studentId}`);
    });

    clearEvaluationSandboxRuntimeContext();
    setTrainerEvaluationMode(true);
    ensureEvaluationDemoData();
    if (!previousEvaluationMode) setTrainerEvaluationMode(false);
    setStudentSyncState('synced', 'Sandbox local');

    if (document.getElementById('dash-stats-grid')) {
        scheduleTrainerDashboardRefresh({ delayMs: 0, refreshProfile: true });
    }
    scheduleStudentDashboardRefresh({ delayMs: 0, refreshLegacyViews: true });
    renderTrainerDemoStudentPreview();

    return { ok: true, message: 'Sandbox restaurado com Aluno Teste e Treinador Teste.' };
}

function syncEvaluationShortcutVisibility(root = document) {
    const scope = root && root.querySelectorAll ? root : document;
    scope.querySelectorAll('[data-evaluation-shortcuts]').forEach((section) => {
        section.style.display = ENABLE_DEMO_ACCESS ? '' : 'none';
    });
}

function showEvaluationAccessUnavailable() {
    const message = 'Modo avaliação disponível apenas em ambiente local.';
    const hasInline = setAuthInlineFeedback('login-inline-feedback', message, 'warning');
    if (!hasInline) alert(message);
}

async function ensureStudentEvaluationScreens() {
    await ensureScreenElement('student-dashboard-screen', 'pages/student-dashboard.html');
    await ensureScreenElement('student-workout-screen', 'pages/student-workout.html');
    await ensureScreenElement('student-diet-screen', 'pages/student-diet.html');
}

async function openStudentEvaluationDashboard() {
    if (!ENABLE_DEMO_ACCESS) {
        showEvaluationAccessUnavailable();
        return;
    }

    window.__CONSULTORIA_REACT_AUTH__?.hide?.();
    setTrainerEvaluationMode(true);
    ensureEvaluationDemoData();
    await ensureStudentEvaluationScreens();

    const students = readStorageJSON('trainerStudents', []);
    const demoStudent = students.find((s) => String(s.id) === String(ADMIN_STUDENT_CODE)) || {
        id: ADMIN_STUDENT_CODE,
        name: ADMIN_STUDENT_NAME,
        trainerCode: EVALUATION_TRAINER_CODE,
        active: true,
        pending: false
    };

    const opened = openStudentDashboardSession(demoStudent);
    if (!opened) {
        const message = 'Não foi possível abrir o dashboard do Aluno Teste.';
        const hasInline = setAuthInlineFeedback('login-inline-feedback', message, 'error');
        if (!hasInline) alert(message);
    }
}

async function enterAsTestStudentFromTrainer() {
    if (!canUseTestAccountSwitcherFromTrainer()) {
        const message = 'Troca de conta teste disponível apenas no Treinador Teste autorizado.';
        if (typeof showTrainerRuntimeMessage === 'function') showTrainerRuntimeMessage(message, 'warning');
        else alert(message);
        return;
    }

    setTrainerEvaluationMode(true);
    ensureEvaluationDemoData();
    saveTrainerTestSwitchContext();
    await ensureStudentEvaluationScreens();

    const students = readStorageJSON('trainerStudents', []);
    const demoStudent = students.find((s) => String(s?.id || '') === String(ADMIN_STUDENT_CODE));
    if (!demoStudent || getStudentTrainerCodeValue(demoStudent) !== EVALUATION_TRAINER_CODE) {
        clearTestAccountSwitchContext();
        showEvaluationAccessUnavailable();
        return;
    }

    memorySetItem(TEST_ACCOUNT_SWITCH_MODE_KEY, 'student-test');
    setRuntimeRoleForTestSwitch('student');
    memorySetItem('currentUserId', `sandbox-student-${ADMIN_STUDENT_CODE}`);
    memorySetItem('currentUserName', ADMIN_STUDENT_NAME);
    const opened = openStudentDashboardSession({
        ...demoStudent,
        id: ADMIN_STUDENT_CODE,
        name: ADMIN_STUDENT_NAME,
        trainerCode: EVALUATION_TRAINER_CODE,
        active: true,
        pending: false
    });
    if (!opened) {
        clearTestAccountSwitchContext();
        setRuntimeRoleForTestSwitch('trainer');
        showEvaluationAccessUnavailable();
        return;
    }
    syncTestAccountSwitcherUI();
}

async function returnToTrainerFromTestStudent() {
    if (!isTestStudentSwitchActive()) {
        const message = 'Retorno ao treinador disponível apenas no modo aluno teste.';
        const hasInline = setAuthInlineFeedback('login-inline-feedback', message, 'warning');
        if (!hasInline) alert(message);
        return;
    }
    const context = getTestAccountSwitchContext() || {};
    clearTestAccountSwitchContext();
    memoryRemoveItem('currentStudentId');
    memoryRemoveItem('connectedTrainerCode');
    memoryRemoveItem('studentName');
    memorySetItem('trainerName', context.trainerName || EVALUATION_TRAINER_NAME);
    memorySetItem('currentTrainerCode', context.currentTrainerCode || EVALUATION_TRAINER_CODE);
    memorySetItem('trainerCodeDefault', context.trainerCodeDefault || EVALUATION_TRAINER_CODE);
    setRuntimeRoleForTestSwitch('trainer');
    setTrainerEvaluationMode(true);
    ensureEvaluationDemoData();
    await openTrainerEvaluationDashboard();
    syncTestAccountSwitcherUI();
}

async function openTrainerEvaluationDashboard() {
    if (!ENABLE_DEMO_ACCESS) {
        showEvaluationAccessUnavailable();
        return;
    }

    window.__CONSULTORIA_REACT_AUTH__?.hide?.();
    setTrainerEvaluationMode(true);
    ensureEvaluationDemoData();

    if (!isTrainerDashboardContext() || !document.getElementById('trainer-dashboard-screen')) {
        window.location.href = 'trainer.html#/alunos';
        return;
    }

    trainerDashboardInitPromise = null;
    hideAllScreens();
    const app = document.getElementById('app');
    if (app) app.classList.add('wide');
    setRuntimeRoleForTestSwitch('trainer');
    const dashboard = document.getElementById('trainer-dashboard-screen');
    if (dashboard) dashboard.classList.add('active');
    await initTrainerDashboard({ force: true });
    syncTestAccountSwitcherUI();
    showTrainerRuntimeMessage('Modo avaliação do treinador ativo.', 'success');
}

function goToHome() {
    stopSupabaseRealtimeSync();
    clearDashboardRuntimeTimers();
    memoryRemoveItem('currentStudentId');
    memoryRemoveItem('connectedTrainerCode');
    memoryRemoveItem('studentName');
    if (window.__CONSULTORIA_REACT_AUTH__?.showHome && !document.getElementById('home-screen')) {
        window.__CONSULTORIA_REACT_AUTH__.showHome();
        return;
    }
    const opened = activateScreen('home-screen');
    if (!opened) {
        goToGlobalLogin();
    }
}

async function logout() {
    if (workoutState && !confirmExitActiveWorkout()) return;
    if (confirm('Deseja realmente sair?')) {
        stopSupabaseRealtimeSync();
        clearAuthRuntimeContext();
        workoutState = null;
        workoutFeedbackRating = 0;
        workoutFeedbackIntensity = 'moderado';
        clearWorkoutBackup();
        try {
            if (typeof window.supabase?.auth?.signOut === 'function') {
                await window.supabase.auth.signOut();
            }
        } catch (err) {
            console.warn('Falha ao encerrar sessao no Supabase.', err);
        }
        setStudentSyncState('synced', 'Sessão encerrada');
        goToHome();
    }
}

async function goBackFromStudentConnect() {
    const activeUser = await getSupabaseSessionUser();
    const currentUserId = String(memoryGetItem('currentUserId') || '');
    const connectedCode = sanitizeCodeInput(memoryGetItem('connectedTrainerCode') || '', 5);
    if (activeUser?.id && currentUserId && String(activeUser.id) === currentUserId) {
        const opened = await openStudentDashboardForUser(activeUser.id, connectedCode);
        if (opened) return;
    }
    goToHome();
}

