function cloneSyncPayload(value, fallback = []) {
    try {
        if (typeof structuredClone === 'function') {
            return structuredClone(value);
        }
    } catch {
        // fallback below
    }
    try {
        return JSON.parse(JSON.stringify(value));
    } catch {
        return Array.isArray(fallback) ? [...fallback] : fallback;
    }
}

function hasStoragePressure() {
    return !appStorage.isPersistent();
}

function resolveBatchedStudentsSyncDelay(delayMs = BATCHED_STUDENTS_SYNC_DEFAULT_DELAY_MS) {
    const requestedDelay = parseInt(delayMs, 10);
    const baseDelay = Number.isFinite(requestedDelay) && requestedDelay > 0
        ? requestedDelay
        : BATCHED_STUDENTS_SYNC_DEFAULT_DELAY_MS;
    const minDelay = hasStoragePressure() ? STORAGE_PRESSURE_SYNC_DELAY_MS : BATCHED_STUDENTS_SYNC_MIN_DELAY_MS;
    return Math.max(minDelay, baseDelay);
}

function normalizeDietMetaShape(meta) {
    const m = meta && typeof meta === 'object' ? meta : {};
    return {
        kcal: parseDecimalSafe(m.kcal) || '',
        protein: parseDecimalSafe(m.protein) || '',
        carb: parseDecimalSafe(m.carb) || '',
        fat: parseDecimalSafe(m.fat) || ''
    };
}

function createStableDietId(prefix = 'diet', label = '', index = 0, seed = '') {
    const base = normalizeText(`${label || prefix} ${seed || ''}`)
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-+|-+$/g, '')
        .slice(0, 44);
    return `${prefix}-${base || 'item'}-${Math.max(0, parseInt(index, 10) || 0)}`;
}

function normalizeDietMealItem(item = {}, itemIdx = 0, mealId = '') {
    const name = sanitizeUserInput(item.nome || item.name || '', { maxLen: 140 }) || 'Alimento';
    const qtd = sanitizeUserInput(item.qtd || '100g', { maxLen: 40 }) || '100g';
    const kcal = parseDecimalSafe(item.kcal);
    const prot = parseDecimalSafe(item.prot || item.protein);
    const carb = parseDecimalSafe(item.carb);
    const gord = parseDecimalSafe(item.gord || item.fat);
    const parsedQty = parseAmountAndUnit(qtd, item.unitKey || item.unit_key || item.baseUnit || item.base_unit || 'g');
    const unitKey = normalizeFoodUnitKey(item.unitKey || item.unit_key || parsedQty.unit || 'g');
    const amount = Math.max(0.1, parseDecimalSafe(item.amount || item.portionAmount) || parsedQty.amount || 1);
    return {
        id: sanitizeUserInput(item.id || item.itemId || item.item_id || createStableDietId('food', name, itemIdx, mealId), { maxLen: 80 }),
        nome: name,
        qtd,
        kcal: Number.isFinite(kcal) ? kcal : Math.round((prot * 4) + (carb * 4) + (gord * 9)),
        prot: Number.isFinite(prot) ? prot : 0,
        carb: Number.isFinite(carb) ? carb : 0,
        gord: Number.isFinite(gord) ? gord : 0,
        foodId: String(item.foodId || item.food_id || ''),
        baseQty: Math.max(0.1, parseDecimalSafe(item.baseQty || item.base_qty) || parsedQty.amount || 100),
        baseUnit: normalizeFoodUnitKey(item.baseUnit || item.base_unit || parsedQty.unit || 'g'),
        source: sanitizeUserInput(item.source || 'manual', { maxLen: 40 }) || 'manual',
        amount,
        unitKey,
        portionId: String(item.portionId || item.portion_id || ''),
        portionLabel: sanitizeUserInput(item.portionLabel || item.portion_label || '', { maxLen: 80 }),
        portions: Array.isArray(item.portions) ? item.portions.map(normalizeFoodPortionRow).filter(Boolean) : [],
        addedByStudent: !!item.addedByStudent
    };
}

function normalizeDietMealBlocksShape(mealBlocks) {
    const blocks = Array.isArray(mealBlocks) ? mealBlocks : [];
    return blocks.map((meal, idx) => {
        const name = sanitizeUserInput(meal?.name || `Refeição ${idx + 1}`, { maxLen: 80 }) || `Refeição ${idx + 1}`;
        const id = sanitizeUserInput(meal?.id || meal?.mealId || meal?.meal_id || createStableDietId('meal', name, idx), { maxLen: 80 });
        return {
            id,
            name,
            note: sanitizeUserInput(meal?.note || meal?.notes || meal?.observacao || '', { allowNewlines: true, maxLen: 260 }),
            time: sanitizeUserInput(meal?.time || meal?.horario || '', { maxLen: 32 }),
            items: Array.isArray(meal?.items) ? meal.items.map((item, itemIdx) => normalizeDietMealItem(item, itemIdx, id)) : []
        };
    });
}

function normalizeDietExtraItem(row = {}, extraIdx = 0, mealIdx = 0) {
    const item = normalizeDietMealItem(row, extraIdx, `extra-${mealIdx}`);
    return {
        ...item,
        id: sanitizeUserInput(row.id || row.extraId || row.extra_id || createStableDietId('extra', item.nome, extraIdx, `${mealIdx}-${row.addedAt || ''}`), { maxLen: 90 }),
        checked: row.checked !== false,
        addedByStudent: true,
        addedAt: row.addedAt || row.added_at || new Date().toISOString()
    };
}

function getEmptyDietLogItem() {
    return {
        checked: false,
        qty: '',
        amount: 1,
        unitKey: 'g',
        portionId: '',
        portionLabel: '',
        substitute: {
            enabled: false,
            name: '',
            qty: '',
            kcal: 0,
            prot: 0,
            carb: 0,
            gord: 0,
            foodId: '',
            baseQty: 100,
            baseUnit: 'g',
            source: 'manual',
            amount: 1,
            unitKey: 'g',
            portionId: '',
            portionLabel: ''
        }
    };
}

function normalizeDietLogsShape(dietLogs, mealBlocks) {
    const logs = dietLogs && typeof dietLogs === 'object' ? dietLogs : {};
    const normalized = {};
    Object.keys(logs).forEach((dateKey) => {
        if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey))) return;
        const entry = logs[dateKey] && typeof logs[dateKey] === 'object' ? logs[dateKey] : {};
        const meals = entry.meals && typeof entry.meals === 'object' ? entry.meals : {};
        const normalizedMeals = {};
        Object.keys(meals).forEach((mealIdxKey) => {
            const mealIdx = parseInt(mealIdxKey, 10);
            if (!Number.isFinite(mealIdx) || mealIdx < 0) return;
            const mealLog = meals[mealIdxKey] && typeof meals[mealIdxKey] === 'object' ? meals[mealIdxKey] : {};
            const items = mealLog.items && typeof mealLog.items === 'object' ? mealLog.items : {};
            const normalizedItems = {};
            Object.keys(items).forEach((itemIdxKey) => {
                const itemIdx = parseInt(itemIdxKey, 10);
                if (!Number.isFinite(itemIdx) || itemIdx < 0) return;
                const row = items[itemIdxKey] && typeof items[itemIdxKey] === 'object' ? items[itemIdxKey] : {};
                const sub = row.substitute && typeof row.substitute === 'object' ? row.substitute : {};
                normalizedItems[itemIdx] = {
                    ...getEmptyDietLogItem(),
                    checked: !!row.checked,
                    qty: sanitizeUserInput(row.qty || '', { maxLen: 40 }),
                    amount: Math.max(0.1, parseDecimalSafe(row.amount) || parseAmountAndUnit(row.qty || '', row.unitKey || row.unit_key || 'g').amount || 1),
                    unitKey: normalizeFoodUnitKey(row.unitKey || row.unit_key || parseAmountAndUnit(row.qty || '', 'g').unit || 'g'),
                    portionId: String(row.portionId || row.portion_id || ''),
                    portionLabel: sanitizeUserInput(row.portionLabel || row.portion_label || '', { maxLen: 80 }),
                    substitute: {
                        enabled: !!sub.enabled,
                        name: sanitizeUserInput(sub.name || '', { maxLen: 140 }),
                        qty: sanitizeUserInput(sub.qty || '', { maxLen: 40 }),
                        kcal: parseDecimalSafe(sub.kcal) || 0,
                        prot: parseDecimalSafe(sub.prot) || 0,
                        carb: parseDecimalSafe(sub.carb) || 0,
                        gord: parseDecimalSafe(sub.gord) || 0,
                        foodId: String(sub.foodId || sub.food_id || ''),
                        baseQty: Math.max(0.1, parseDecimalSafe(sub.baseQty || sub.base_qty) || 100),
                        baseUnit: normalizeFoodUnitKey(sub.baseUnit || sub.base_unit || 'g'),
                        source: sanitizeUserInput(sub.source || 'manual', { maxLen: 40 }) || 'manual',
                        amount: Math.max(0.1, parseDecimalSafe(sub.amount) || parseAmountAndUnit(sub.qty || '', sub.unitKey || sub.unit_key || 'g').amount || 1),
                        unitKey: normalizeFoodUnitKey(sub.unitKey || sub.unit_key || parseAmountAndUnit(sub.qty || '', 'g').unit || 'g'),
                        portionId: String(sub.portionId || sub.portion_id || ''),
                        portionLabel: sanitizeUserInput(sub.portionLabel || sub.portion_label || '', { maxLen: 80 })
                    }
                };
            });
            const extras = Array.isArray(mealLog.extras)
                ? mealLog.extras.map((extra, extraIdx) => normalizeDietExtraItem(extra, extraIdx, mealIdx)).filter(Boolean)
                : [];
            normalizedMeals[mealIdx] = { items: normalizedItems, extras };
        });

        // ensure all current meal items have a log slot
        (Array.isArray(mealBlocks) ? mealBlocks : []).forEach((meal, mealIdx) => {
            if (!normalizedMeals[mealIdx]) normalizedMeals[mealIdx] = { items: {}, extras: [] };
            if (!Array.isArray(normalizedMeals[mealIdx].extras)) normalizedMeals[mealIdx].extras = [];
            (Array.isArray(meal?.items) ? meal.items : []).forEach((_, itemIdx) => {
                if (!normalizedMeals[mealIdx].items[itemIdx]) {
                    normalizedMeals[mealIdx].items[itemIdx] = getEmptyDietLogItem();
                }
            });
        });
        const meta = entry.meta && typeof entry.meta === 'object'
            ? {
                completed: !!entry.meta.completed,
                completedAt: entry.meta.completedAt || entry.meta.completed_at || null,
                copiedFrom: sanitizeUserInput(entry.meta.copiedFrom || entry.meta.copied_from || '', { maxLen: 20 }),
                copiedAt: entry.meta.copiedAt || entry.meta.copied_at || ''
            }
            : {};
        normalized[dateKey] = { meals: normalizedMeals, meta };
    });
    return normalized;
}

const CARDIO_PLAN_DAYS = [
    { key: 'seg', label: 'Segunda' },
    { key: 'ter', label: 'Terça' },
    { key: 'qua', label: 'Quarta' },
    { key: 'qui', label: 'Quinta' },
    { key: 'sex', label: 'Sexta' },
    { key: 'sab', label: 'Sábado' },
    { key: 'dom', label: 'Domingo' }
];

const CARDIO_PLAN_DAYS_DOM_FIRST = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
const CARDIO_ZONE_KEYS = ['z1', 'z2', 'z3'];
const CARDIO_INTENSITY_OPTIONS = [
    { key: 'low', label: 'Baixa', legacyLabel: 'Baixa', shortLabel: 'Baixa' },
    { key: 'medium', label: 'Média', legacyLabel: 'Média', shortLabel: 'Média' },
    { key: 'high', label: 'Alta', legacyLabel: 'Alta', shortLabel: 'Alta' }
];

function normalizeCardioZoneKey(value, fallback = 'z2') {
    const safeValue = String(value || '').trim().toLowerCase();
    if (CARDIO_ZONE_KEYS.includes(safeValue)) return safeValue;
    const safeFallback = String(fallback || '').trim().toLowerCase();
    return CARDIO_ZONE_KEYS.includes(safeFallback) ? safeFallback : 'z2';
}

function normalizeCardioIntensityKey(value, fallback = 'medium') {
    const safeValue = String(value || '').trim().toLowerCase();
    if (CARDIO_INTENSITY_OPTIONS.some((item) => item.key === safeValue)) return safeValue;
    const safeFallback = String(fallback || '').trim().toLowerCase();
    if (CARDIO_INTENSITY_OPTIONS.some((item) => item.key === safeFallback)) return safeFallback;
    return 'medium';
}

function getCardioIntensityMeta(intensityKey = 'medium') {
    const safeKey = normalizeCardioIntensityKey(intensityKey, 'medium');
    return CARDIO_INTENSITY_OPTIONS.find((item) => item.key === safeKey) || CARDIO_INTENSITY_OPTIONS[1];
}

function inferCardioIntensityKeyFromLegacy(intensityValue = '') {
    const raw = sanitizeUserInput(intensityValue || '', { maxLen: 40 });
    const normalized = normalizeText(raw || '');
    if (!normalized) return 'medium';
    if (/(alta|high|vigor|forte|intens|hiit|sprint|pico)/.test(normalized)) return 'high';
    if (/(baixa|low|leve|suave|recupera|liss)/.test(normalized)) return 'low';
    return 'medium';
}

function getCardioDayByKey(dayKey = '') {
    const safeDayKey = String(dayKey || '').trim().toLowerCase();
    return CARDIO_PLAN_DAYS.find((day) => day.key === safeDayKey) || null;
}

function getCardioDaysDomFirst(daysLike = []) {
    const byKey = new Map((Array.isArray(daysLike) ? daysLike : []).map((entry) => [
        String(entry?.dayKey || '').toLowerCase(),
        entry
    ]));
    return CARDIO_PLAN_DAYS_DOM_FIRST.map((key) => byKey.get(key)).filter(Boolean);
}

function getDefaultCardioPlan() {
    return {
        weeklyGoalMin: 120,
        baseZoneKey: 'z2',
        hrMaxMode: 'auto',
        hrMaxFormula: 'tanaka',
        hrMaxManual: '',
        coachRecommendation: '',
        days: CARDIO_PLAN_DAYS.map((day) => ({
            dayKey: day.key,
            dayLabel: day.label,
            type: '',
            durationMin: '',
            intensity: '',
            intensityKey: 'medium',
            zoneKey: 'z2',
            notes: ''
        }))
    };
}

function normalizeCardioDaysShape(daysLike = [], fallbackZoneKey = 'z2') {
    const mapByDay = new Map();
    const safeFallbackZone = normalizeCardioZoneKey(fallbackZoneKey, 'z2');
    (Array.isArray(daysLike) ? daysLike : []).forEach((entry) => {
        const rawKey = sanitizeUserInput(entry?.dayKey || '', { maxLen: 8 }).toLowerCase();
        if (!rawKey) return;
        const dayType = sanitizeUserInput(entry?.type || '', { maxLen: 80 });
        const dayDuration = sanitizeUserInput(entry?.durationMin || '', { maxLen: 6 });
        const legacyIntensity = sanitizeUserInput(entry?.intensity || '', { maxLen: 40 });
        const dayNotes = sanitizeUserInput(entry?.notes || '', { allowNewlines: true, maxLen: 280 });
        const intensityKey = normalizeCardioIntensityKey(
            entry?.intensityKey,
            inferCardioIntensityKeyFromLegacy(legacyIntensity)
        );
        const intensityMeta = getCardioIntensityMeta(intensityKey);
        const hasDayPrescription = [dayType, dayDuration, legacyIntensity, dayNotes].some(Boolean);
        mapByDay.set(rawKey, {
            dayKey: rawKey,
            dayLabel: sanitizeUserInput(entry?.dayLabel || '', { maxLen: 20 }),
            type: dayType,
            durationMin: dayDuration,
            intensity: hasDayPrescription ? (legacyIntensity || intensityMeta.legacyLabel) : '',
            intensityKey,
            zoneKey: normalizeCardioZoneKey(entry?.zoneKey, safeFallbackZone),
            notes: dayNotes
        });
    });
    return CARDIO_PLAN_DAYS.map((day) => {
        const found = mapByDay.get(day.key);
        if (found) {
            const resolvedIntensityKey = normalizeCardioIntensityKey(found.intensityKey, inferCardioIntensityKeyFromLegacy(found.intensity));
            const intensityMeta = getCardioIntensityMeta(resolvedIntensityKey);
            const hasDayPrescription = [found.type, found.durationMin, found.intensity, found.notes].some(Boolean);
            return {
                ...found,
                dayLabel: found.dayLabel || day.label,
                intensityKey: resolvedIntensityKey,
                intensity: hasDayPrescription ? (found.intensity || intensityMeta.legacyLabel) : '',
                zoneKey: normalizeCardioZoneKey(found.zoneKey, safeFallbackZone)
            };
        }
        return {
            dayKey: day.key,
            dayLabel: day.label,
            type: '',
            durationMin: '',
            intensity: '',
            intensityKey: 'medium',
            zoneKey: safeFallbackZone,
            notes: ''
        };
    });
}

function normalizeCardioPlanShape(cardioPlanLike = []) {
    const raw = cardioPlanLike && typeof cardioPlanLike === 'object' ? cardioPlanLike : {};
    const legacyDays = Array.isArray(cardioPlanLike) ? cardioPlanLike : [];
    const daysSource = Array.isArray(raw.days) ? raw.days : legacyDays;
    const weeklyGoalParsed = parseIntegerSafe(raw.weeklyGoalMin);
    const baseZoneKey = normalizeCardioZoneKey(raw.baseZoneKey, 'z2');
    const hrMaxModeRaw = String(raw.hrMaxMode || '').trim().toLowerCase();
    const hrMaxMode = hrMaxModeRaw === 'manual' ? 'manual' : 'auto';
    const hrMaxFormula = 'tanaka';
    const hrMaxManualParsed = parseIntegerSafe(raw.hrMaxManual);
    const hrMaxManual = hrMaxMode === 'manual' && Number.isFinite(hrMaxManualParsed)
        ? Math.min(240, Math.max(90, hrMaxManualParsed))
        : '';
    return {
        weeklyGoalMin: Number.isFinite(weeklyGoalParsed)
            ? Math.min(600, Math.max(30, weeklyGoalParsed))
            : 120,
        baseZoneKey,
        hrMaxMode,
        hrMaxFormula,
        hrMaxManual,
        coachRecommendation: sanitizeUserInput(raw.coachRecommendation || '', { maxLen: 220 }),
        days: normalizeCardioDaysShape(daysSource, baseZoneKey)
    };
}

function normalizeWaterPlanShape(waterPlanLike = {}) {
    const raw = waterPlanLike && typeof waterPlanLike === 'object' ? waterPlanLike : {};
    const goal = parseIntegerSafe(raw.dailyGoalMl);
    const adjustmentParsed = parseIntegerSafe(raw.adjustmentMl);
    const hasLegacyManualGoal = Number.isFinite(goal) && goal > 0;
    const requestedMode = String(raw.mode || '').trim().toLowerCase();
    const resolvedMode = requestedMode === 'auto' || requestedMode === 'manual'
        ? requestedMode
        : (hasLegacyManualGoal ? 'manual' : 'auto');
    return {
        mode: resolvedMode,
        dailyGoalMl: resolvedMode === 'manual'
            ? (Number.isFinite(goal) && goal > 0 ? Math.min(6000, Math.max(1000, goal)) : 3000)
            : null,
        adjustmentMl: Number.isFinite(adjustmentParsed) ? Math.min(3000, Math.max(-3000, adjustmentParsed)) : 0,
        remindersEnabled: raw.remindersEnabled !== false,
        notes: sanitizeUserInput(raw.notes || '', { allowNewlines: true, maxLen: 280 })
    };
}

function normalizeWaterLogsShape(waterLogsLike = {}) {
    const raw = waterLogsLike && typeof waterLogsLike === 'object' ? waterLogsLike : {};
    const normalized = {};
    Object.entries(raw).forEach(([dateKey, entries]) => {
        if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return;
        normalized[dateKey] = (Array.isArray(entries) ? entries : [])
            .map((entry) => ({
                entryId: sanitizeUserInput(entry?.entryId || '', { maxLen: 64 }),
                amountMl: Math.min(2000, Math.max(50, parseIntegerSafe(entry?.amountMl || entry?.amount) || 0)),
                time: sanitizeUserInput(entry?.time || '', { maxLen: 40 }) || new Date().toISOString()
            }))
            .map((entry) => ({
                ...entry,
                entryId: entry.entryId || `water-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`
            }))
            .filter((entry) => entry.amountMl > 0);
    });
    return normalized;
}

function normalizeCardioLogsShape(cardioLogsLike = {}) {
    const raw = cardioLogsLike && typeof cardioLogsLike === 'object' ? cardioLogsLike : {};
    const rawCompletion = raw.completionByDate && typeof raw.completionByDate === 'object'
        ? raw.completionByDate
        : raw;
    const rawSessions = raw.sessionsByDate && typeof raw.sessionsByDate === 'object'
        ? raw.sessionsByDate
        : {};

    const completionByDate = {};
    Object.entries(rawCompletion).forEach(([dateKey, entries]) => {
        if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return;
        completionByDate[dateKey] = (Array.isArray(entries) ? entries : [])
            .map((entry) => ({
                dayKey: sanitizeUserInput(entry?.dayKey || '', { maxLen: 8 }).toLowerCase(),
                completed: !!entry?.completed,
                completedAt: sanitizeUserInput(entry?.completedAt || '', { maxLen: 30 }) || new Date().toISOString()
            }))
            .filter((entry) => entry.dayKey);
    });
    const sessionsByDate = {};
    Object.entries(rawSessions).forEach(([dateKey, entries]) => {
        if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return;
        sessionsByDate[dateKey] = (Array.isArray(entries) ? entries : [])
            .map((entry) => ({
                sessionId: sanitizeUserInput(entry?.sessionId || '', { maxLen: 80 }) || `cardio-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
                startedAt: sanitizeUserInput(entry?.startedAt || '', { maxLen: 40 }) || new Date().toISOString(),
                endedAt: sanitizeUserInput(entry?.endedAt || '', { maxLen: 40 }) || new Date().toISOString(),
                elapsedSec: Math.max(1, parseIntegerSafe(entry?.elapsedSec) || 0),
                zoneKey: ['z1', 'z2', 'z3'].includes(String(entry?.zoneKey || '').toLowerCase())
                    ? String(entry.zoneKey).toLowerCase()
                    : 'z2',
                source: String(entry?.source || '').toLowerCase() === 'manual' ? 'manual' : 'timer',
                notes: sanitizeUserInput(entry?.notes || '', { maxLen: 200 })
            }))
            .filter((entry) => entry.elapsedSec > 0);
    });
    return { completionByDate, sessionsByDate };
}

function normalizeStudentDietSchema(studentLike = {}) {
    const student = studentLike && typeof studentLike === 'object' ? studentLike : {};
    const mealBlocks = normalizeDietMealBlocksShape(student.mealBlocks);
    const dietMeta = normalizeDietMetaShape(student.dietMeta);
    const dietLogs = normalizeDietLogsShape(student.dietLogs, mealBlocks);
    const cardioPlan = normalizeCardioPlanShape(student.cardioPlan);
    const cardioLogs = normalizeCardioLogsShape(student.cardioLogs);
    const waterPlan = normalizeWaterPlanShape(student.waterPlan);
    const waterLogs = normalizeWaterLogsShape(student.waterLogs);
    const routine = normalizeRoutineShape(student.routine);
    const chatMessages = mergeChatMessagesById(student.chatMessages || []);
    const paymentRequests = normalizeStudentPaymentRequests(student.paymentRequests || student.payment_requests || []);
    const trainerPaymentSettings = normalizeTrainerPaymentSettings(
        student.trainerPaymentSettings || student.trainer_payment_settings || {}
    );
    const trainerServices = normalizeTrainerServices(
        student.trainerServices || student.trainer_services || ''
    );
    return {
        ...student,
        mealBlocks,
        dietMeta,
        dietLogs,
        cardioPlan,
        cardioLogs,
        waterPlan,
        waterLogs,
        routine,
        chatMessages,
        paymentRequests,
        trainerPaymentSettings,
        trainerServices,
        dietSchemaVersion: DIET_SCHEMA_VERSION
    };
}

function normalizeRoutineRecurrenceType(value = 'daily') {
    return String(value || '').toLowerCase() === 'weekdays' ? 'weekdays' : 'daily';
}

function normalizeRoutineWeekdays(daysLike = [], recurrenceType = 'daily') {
    if (recurrenceType !== 'weekdays') return [];
    return (Array.isArray(daysLike) ? daysLike : [])
        .map((d) => String(d || '').toLowerCase())
        .filter((d) => ROUTINE_WEEKDAY_KEYS.includes(d));
}

function normalizeRoutineCreatedBy(value = 'student') {
    const safe = String(value || '').trim().toLowerCase();
    return safe === 'trainer' ? 'trainer' : 'student';
}

function trimRoutineCheckinsByDate(checkinsByDate = {}) {
    const allKeys = Object.keys(checkinsByDate).sort();
    const keepKeys = allKeys.slice(-120);
    const trimmed = {};
    keepKeys.forEach((dateKey) => {
        const entries = Array.isArray(checkinsByDate[dateKey]) ? checkinsByDate[dateKey] : [];
        trimmed[dateKey] = entries.slice(-80);
    });
    return trimmed;
}

function normalizeRoutineShape(rawRoutine = {}) {
    const safeRoutine = rawRoutine && typeof rawRoutine === 'object' ? rawRoutine : {};
    const habits = (Array.isArray(safeRoutine.habits) ? safeRoutine.habits : [])
        .map((habit) => {
            const recurrenceType = normalizeRoutineRecurrenceType(habit?.recurrenceType);
            return {
                id: sanitizeUserInput(habit?.id || '', { maxLen: 80 }) || `habit-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
                title: sanitizeUserInput(habit?.title || '', { maxLen: 80 }) || 'Hábito',
                timeHHmm: normalizeTimeHHmm(habit?.timeHHmm || '08:00'),
                recurrenceType,
                weekdays: normalizeRoutineWeekdays(habit?.weekdays, recurrenceType),
                active: habit?.active !== false,
                createdAt: sanitizeUserInput(habit?.createdAt || '', { maxLen: 40 }) || new Date().toISOString(),
                createdBy: normalizeRoutineCreatedBy(habit?.createdBy || 'student')
            };
        })
        .filter((habit) => habit.id && habit.title)
        .slice(-120);

    const reminders = (Array.isArray(safeRoutine.reminders) ? safeRoutine.reminders : [])
        .map((reminder) => {
            const rawRecurrence = sanitizeUserInput(reminder?.recurrenceType || '', { maxLen: 20 }).toLowerCase();
            const recurrenceType = normalizeRoutineRecurrenceType(rawRecurrence || 'daily');
            const hasLegacyDateKey = /^\d{4}-\d{2}-\d{2}$/.test(String(reminder?.dateKey || ''));
            const legacyDateOnly = !rawRecurrence && hasLegacyDateKey;
            return {
                id: sanitizeUserInput(reminder?.id || '', { maxLen: 80 }) || `rem-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
                title: sanitizeUserInput(reminder?.title || '', { maxLen: 80 }) || 'Lembrete',
                timeHHmm: normalizeTimeHHmm(reminder?.timeHHmm || '08:00'),
                recurrenceType,
                weekdays: normalizeRoutineWeekdays(reminder?.weekdays, recurrenceType),
                active: reminder?.active !== false,
                createdAt: sanitizeUserInput(reminder?.createdAt || '', { maxLen: 40 }) || new Date().toISOString(),
                createdBy: normalizeRoutineCreatedBy(reminder?.createdBy || 'student'),
                dateKey: legacyDateOnly ? String(reminder.dateKey) : '',
                legacyDateOnly
            };
        })
        .filter((item) => item.id && item.title)
        .slice(-240);

    const checkinsByDate = {};
    if (safeRoutine.checkinsByDate && typeof safeRoutine.checkinsByDate === 'object') {
        Object.entries(safeRoutine.checkinsByDate).forEach(([dateKey, values]) => {
            if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return;
            checkinsByDate[dateKey] = (Array.isArray(values) ? values : [])
                .map((entry) => ({
                    habitId: sanitizeUserInput(entry?.habitId || '', { maxLen: 80 }),
                    doneAt: sanitizeUserInput(entry?.doneAt || '', { maxLen: 40 }) || new Date().toISOString()
                }))
                .filter((entry) => entry.habitId);
        });
    }

    return {
        habits,
        reminders,
        checkinsByDate: trimRoutineCheckinsByDate(checkinsByDate)
    };
}

function normalizeTimeHHmm(value = '08:00') {
    const raw = String(value || '').trim();
    if (!raw) return '08:00';
    const match = raw.match(/^(\d{1,2}):(\d{2})$/);
    if (!match) return '08:00';
    const hh = Math.max(0, Math.min(23, parseInt(match[1], 10) || 0));
    const mm = Math.max(0, Math.min(59, parseInt(match[2], 10) || 0));
    return `${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}`;
}

function normalizeStudentsDietSchema(students = []) {
    return (Array.isArray(students) ? students : []).map((student) => normalizeStudentDietSchema(student));
}

function createStudentPersistOpId() {
    return `persist-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function logStudentPersistOperation(payload = {}) {
    try {
        const safe = {
            opId: payload.opId || createStudentPersistOpId(),
            studentId: payload.studentId || '',
            mode: payload.mode || 'immediate',
            localOk: payload.localOk !== false,
            remoteOk: payload.remoteOk === true,
            reason: payload.reason || '',
            ts: new Date().toISOString()
        };
        console.info('[students-persist]', safe);
    } catch {
        // noop
    }
}

function needsDietSchemaMigration(student) {
    if (!student || typeof student !== 'object') return true;
    const version = parseInt(student.dietSchemaVersion || 0, 10) || 0;
    if (version < DIET_SCHEMA_VERSION) return true;
    if (!Array.isArray(student.mealBlocks)) return true;
    if (!student.dietMeta || typeof student.dietMeta !== 'object') return true;
    if (!student.dietLogs || typeof student.dietLogs !== 'object') return true;
    if (!student.cardioPlan || typeof student.cardioPlan !== 'object') return true;
    if (!Array.isArray(student.cardioPlan.days)) return true;
    if (!student.waterPlan || typeof student.waterPlan !== 'object') return true;
    if (!student.waterLogs || typeof student.waterLogs !== 'object') return true;
    if (!student.cardioLogs || typeof student.cardioLogs !== 'object') return true;
    if (!student.cardioLogs.completionByDate || typeof student.cardioLogs.completionByDate !== 'object') return true;
    if (!student.cardioLogs.sessionsByDate || typeof student.cardioLogs.sessionsByDate !== 'object') return true;
    if (!student.routine || typeof student.routine !== 'object') return true;
    if (!Array.isArray(student.routine.habits)) return true;
    if (!Array.isArray(student.routine.reminders)) return true;
    if (!student.routine.checkinsByDate || typeof student.routine.checkinsByDate !== 'object') return true;
    return false;
}

function migrateStoredStudentsDietSchema({ syncRemote = true } = {}) {
    const localStudents = readStorageJSON('trainerStudents', []);
    if (!Array.isArray(localStudents) || localStudents.length === 0) return false;
    const shouldMigrate = localStudents.some(needsDietSchemaMigration);
    if (!shouldMigrate) return false;
    const normalized = normalizeStudentsDietSchema(localStudents);
    memorySetItem('trainerStudents', JSON.stringify(normalized));
    if (syncRemote && isSupabaseReady()) queueSupabaseStudentsSync(normalized, { syncMode: 'batched' });
    return true;
}

function normalizeStudentRow(row) {
    if (!row) return null;
    const student = row.data && typeof row.data === 'object' ? row.data : {};
    student.id = student.id || row.id || '';
    student.trainerCode = student.trainerCode || row.trainer_code || '';
    student._remoteRowUpdatedAt = String(row.updated_at || student._remoteRowUpdatedAt || '').trim();
    student._localDataUpdatedAt = resolveStudentDataUpdatedAt(student) || student._remoteRowUpdatedAt || '';
    return normalizeStudentDietSchema(student);
}

const FOOD_VARIANT_FAMILIES = {
    rice: {
        label: 'Arroz',
        variants: { white: 'Branco', brown: 'Integral' },
        order: ['white', 'brown']
    },
    beans: {
        label: 'Feijão',
        variants: { carioca: 'Carioca', black: 'Preto' },
        order: ['carioca', 'black']
    },
    milk: {
        label: 'Leite',
        variants: { whole: 'Integral', semi: 'Semi', skim: 'Desnatado' },
        order: ['whole', 'semi', 'skim']
    },
    soda: {
        label: 'Refrigerante',
        variants: { regular: 'Normal', zero: 'Zero' },
        order: ['regular', 'zero']
    },
    water: {
        label: 'Água',
        variants: { still: 'Sem gás', sparkling: 'Com gás' },
        order: ['still', 'sparkling']
    },
    yogurt: {
        label: 'Iogurte',
        variants: { natural: 'Natural', greek: 'Grego', skim: 'Desnatado' },
        order: ['natural', 'greek', 'skim']
    },
    bread: {
        label: 'Pão',
        variants: { french: 'Francês', whole: 'Integral' },
        order: ['french', 'whole']
    },
    cheese: {
        label: 'Queijo',
        variants: { mozzarella: 'Muçarela', minas: 'Minas', cottage: 'Cottage' },
        order: ['mozzarella', 'minas', 'cottage']
    },
    juice: {
        label: 'Suco',
        variants: { natural: 'Natural', integral: 'Integral', zero: 'Zero' },
        order: ['natural', 'integral', 'zero']
    },
    hot_drink: {
        label: 'Café/Chá',
        variants: { coffee_black: 'Café sem açúcar', coffee_milk: 'Café com leite', tea_unsweetened: 'Chá sem açúcar' },
        order: ['coffee_black', 'coffee_milk', 'tea_unsweetened']
    }
};

function inferFoodFamilyKey(name = '', baseUnit = 'g') {
    const text = normalizeText(name);
    if (!text) return '';
    if (text.includes('cafe') || text.includes('cha')) return 'hot_drink';
    if (text.includes('suco')) return 'juice';
    if (text.includes('iogurte')) return 'yogurt';
    if (text.includes('queijo') || text.includes('ricota') || text.includes('cottage')) return 'cheese';
    if (text.includes('pao') || text.includes('torrada')) return 'bread';
    if (text.includes('leite')) return 'milk';
    if (text.includes('refrigerante') || text.includes('refri')) return 'soda';
    if (text.includes('agua') && (normalizeFoodUnitKey(baseUnit) === 'ml' || normalizeFoodUnitKey(baseUnit) === 'l')) return 'water';
    if (text.includes('arroz')) return 'rice';
    if (text.includes('feijao')) return 'beans';
    return '';
}

function inferFoodVariantKey(familyKey = '', name = '') {
    const text = normalizeText(name);
    if (!familyKey || !text) return '';
    if (familyKey === 'milk') {
        if (text.includes('desnat')) return 'skim';
        if (text.includes('semi')) return 'semi';
        if (text.includes('integral')) return 'whole';
        return '';
    }
    if (familyKey === 'rice') {
        if (text.includes('integral')) return 'brown';
        if (text.includes('branco')) return 'white';
        return '';
    }
    if (familyKey === 'beans') {
        if (text.includes('carioca')) return 'carioca';
        if (text.includes('preto')) return 'black';
        return '';
    }
    if (familyKey === 'soda') {
        if (text.includes('zero') || text.includes('diet') || text.includes('light')) return 'zero';
        if (text.includes('normal') || text.includes('tradicional')) return 'regular';
        return '';
    }
    if (familyKey === 'water') {
        if (text.includes('com gas')) return 'sparkling';
        if (text.includes('sem gas') || text.includes('mineral')) return 'still';
        return '';
    }
    if (familyKey === 'yogurt') {
        if (text.includes('grego')) return 'greek';
        if (text.includes('desnat')) return 'skim';
        if (text.includes('natural')) return 'natural';
        return '';
    }
    if (familyKey === 'bread') {
        if (text.includes('integral')) return 'whole';
        if (text.includes('frances') || text.includes('francês') || text.includes('pao')) return 'french';
        return '';
    }
    if (familyKey === 'cheese') {
        if (text.includes('mucarela') || text.includes('mozarela') || text.includes('mozzarella')) return 'mozzarella';
        if (text.includes('minas')) return 'minas';
        if (text.includes('cottage')) return 'cottage';
        return '';
    }
    if (familyKey === 'juice') {
        if (text.includes('zero') || text.includes('sem acucar') || text.includes('sem açúcar')) return 'zero';
        if (text.includes('integral')) return 'integral';
        if (text.includes('natural')) return 'natural';
        return '';
    }
    if (familyKey === 'hot_drink') {
        if (text.includes('cafe com leite') || text.includes('café com leite')) return 'coffee_milk';
        if (text.includes('cha') || text.includes('chá')) return 'tea_unsweetened';
        if (text.includes('cafe') || text.includes('café')) return 'coffee_black';
        return '';
    }
    return '';
}

function getFoodVariantLabel(familyKey = '', variantKey = '', fallbackLabel = '') {
    const cleanFallback = sanitizeUserInput(fallbackLabel || '', { maxLen: 50 });
    const family = FOOD_VARIANT_FAMILIES[familyKey];
    if (!family) return cleanFallback;
    return family.variants?.[variantKey] || cleanFallback;
}

function normalizeFoodCatalogRow(row) {
    if (!row) return null;
    const name = sanitizeUserInput(row.name || row.nome || '', { maxLen: 140 });
    if (!name) return null;
    const baseUnit = normalizeFoodUnitKey(row.base_unit || row.baseUnit || 'g');
    const portionsInput = Array.isArray(row.portions) ? row.portions : [];
    const normalizedPortions = portionsInput.map(normalizeFoodPortionRow).filter(Boolean);
    const rawFamily = sanitizeUserInput(row.family_key || row.familyKey || '', { maxLen: 40 }).toLowerCase();
    const familyKey = rawFamily || inferFoodFamilyKey(name, baseUnit);
    const rawVariant = sanitizeUserInput(row.variant_key || row.variantKey || '', { maxLen: 40 }).toLowerCase();
    const variantKey = rawVariant || inferFoodVariantKey(familyKey, name);
    const variantLabel = getFoodVariantLabel(
        familyKey,
        variantKey,
        row.variant_label || row.variantLabel || ''
    );
    return {
        id: String(row.id || ''),
        name,
        brand: sanitizeUserInput(row.brand || '', { maxLen: 80 }),
        base_qty: Math.max(0.1, parseDecimalSafe(row.base_qty) || 100),
        base_unit: baseUnit,
        kcal: Math.max(0, parseDecimalSafe(row.kcal)),
        protein: Math.max(0, parseDecimalSafe(row.protein || row.prot)),
        carb: Math.max(0, parseDecimalSafe(row.carb)),
        fat: Math.max(0, parseDecimalSafe(row.fat || row.gord)),
        source: sanitizeUserInput(row.source || 'manual', { maxLen: 80 }) || 'manual',
        created_by: sanitizeUserInput(row.created_by || '', { maxLen: 80 }),
        provider: sanitizeUserInput(row.provider || row.data_provider || '', { maxLen: 30 }).toLowerCase(),
        provider_food_id: sanitizeUserInput(row.provider_food_id || row.providerFoodId || '', { maxLen: 80 }),
        provider_serving_id: sanitizeUserInput(row.provider_serving_id || row.providerServingId || '', { maxLen: 80 }),
        verified_at: sanitizeUserInput(row.verified_at || row.verifiedAt || '', { maxLen: 40 }),
        family_key: familyKey,
        variant_key: variantKey,
        variant_label: variantLabel,
        portions: normalizedPortions
    };
}

function getCurrentFoodCreatorId() {
    return memoryGetItem('currentUserId')
        || memoryGetItem('currentStudentId')
        || memoryGetItem('currentTrainerCode')
        || 'anon';
}

const FOOD_UNIT_KEYS = ['g', 'ml', 'l', 'un', 'slice', 'tbsp', 'tsp', 'cup', 'glass', 'ladle'];
const FOOD_UNIT_LABELS = {
    g: { single: 'grama', plural: 'gramas', short: 'g' },
    ml: { single: 'mililitro', plural: 'mililitros', short: 'ml' },
    l: { single: 'litro', plural: 'litros', short: 'l' },
    un: { single: 'unidade', plural: 'unidades', short: 'un' },
    slice: { single: 'fatia', plural: 'fatias', short: 'fatia' },
    tbsp: { single: 'colher de sopa', plural: 'colheres de sopa', short: 'cs' },
    tsp: { single: 'colher de chá', plural: 'colheres de chá', short: 'ccha' },
    cup: { single: 'xícara', plural: 'xícaras', short: 'xic' },
    glass: { single: 'copo', plural: 'copos', short: 'copo' },
    ladle: { single: 'concha', plural: 'conchas', short: 'concha' }
};
const FOOD_UNIT_ALIASES = {
    g: ['g', 'gr', 'grama', 'gramas'],
    ml: ['ml', 'mililitro', 'mililitros'],
    l: ['l', 'lt', 'lts', 'litro', 'litros'],
    un: ['un', 'und', 'unid', 'unidade', 'unidades'],
    slice: ['fatia', 'fatias', 'slice', 'slices'],
    tbsp: ['colher de sopa', 'colher sopa', 'colheres de sopa', 'tbsp', 'cs'],
    tsp: ['colher de cha', 'colher de chá', 'colher cha', 'colheres de cha', 'colheres de chá', 'tsp', 'ccha'],
    cup: ['xicara', 'xícara', 'xicaras', 'xícaras', 'cup'],
    glass: ['copo', 'copos', 'glass'],
    ladle: ['concha', 'conchas', 'ladle']
};

function normalizeFoodUnitKey(rawValue) {
    const raw = normalizeText(String(rawValue || '').trim());
    if (!raw) return 'g';
    if (FOOD_UNIT_KEYS.includes(raw)) return raw;
    const found = FOOD_UNIT_KEYS.find((key) => (FOOD_UNIT_ALIASES[key] || []).some((alias) => normalizeText(alias) === raw));
    return found || 'g';
}

function getFoodUnitLabel(unitKey, amount = 1) {
    const safeUnit = normalizeFoodUnitKey(unitKey);
    const dictionary = FOOD_UNIT_LABELS[safeUnit] || FOOD_UNIT_LABELS.g;
    return Number(amount || 0) === 1 ? dictionary.single : dictionary.plural;
}

function getFoodUnitShort(unitKey) {
    const safeUnit = normalizeFoodUnitKey(unitKey);
    return (FOOD_UNIT_LABELS[safeUnit] || FOOD_UNIT_LABELS.g).short;
}

function formatFoodQuantity(amountValue, unitKey, { compact = false } = {}) {
    const safeUnit = normalizeFoodUnitKey(unitKey);
    const numericAmount = Math.max(0.1, parseDecimalSafe(amountValue) || 0);
    const roundedAmount = Number.isInteger(numericAmount) ? numericAmount : Math.round(numericAmount * 10) / 10;
    if (safeUnit === 'g' || safeUnit === 'ml' || safeUnit === 'l') {
        return `${roundedAmount}${safeUnit}`;
    }
    if (compact) {
        return `${roundedAmount}${getFoodUnitShort(safeUnit)}`;
    }
    return `${roundedAmount} ${getFoodUnitLabel(safeUnit, roundedAmount)}`;
}

function isLikelyLiquidFoodName(foodName = '') {
    const name = normalizeText(foodName);
    if (!name) return false;
    const liquidTerms = [
        'suco',
        'refrigerante',
        'refri',
        'agua',
        'água',
        'cha',
        'chá',
        'cafe',
        'café',
        'leite',
        'iogurte liquido',
        'isotonico',
        'isotônico',
        'energetico',
        'energético',
        'vitamina',
        'bebida',
        'drink'
    ];
    return liquidTerms.some((term) => name.includes(normalizeText(term)));
}

function normalizeFoodPortionRow(row) {
    if (!row) return null;
    const unitKey = normalizeFoodUnitKey(row.unit_key || row.unitKey || 'g');
    const amount = Math.max(0.1, parseDecimalSafe(row.amount) || 1);
    const baseEquivalent = Math.max(0.1, parseDecimalSafe(row.base_qty_equivalent || row.baseQtyEquivalent) || amount);
    const label = sanitizeUserInput(row.label || `${getFoodUnitLabel(unitKey, amount)}`, { maxLen: 90 }) || `${getFoodUnitLabel(unitKey, amount)}`;
    return {
        id: String(row.id || ''),
        food_id: String(row.food_id || row.foodId || ''),
        label,
        amount,
        unit_key: unitKey,
        base_qty_equivalent: baseEquivalent,
        is_default: !!row.is_default,
        sort_order: Number.isFinite(Number(row.sort_order)) ? Number(row.sort_order) : 0
    };
}

function addFallbackPortion(portions, foodId, portion) {
    if (!Array.isArray(portions) || !portion) return;
    const normalized = normalizeFoodPortionRow({
        ...portion,
        id: '',
        food_id: String(foodId || portion.food_id || '')
    });
    if (!normalized) return;
    const key = `${normalizeFoodUnitKey(normalized.unit_key)}:${normalizeText(normalized.label)}`;
    const exists = portions.some((item) => `${normalizeFoodUnitKey(item.unit_key)}:${normalizeText(item.label)}` === key);
    if (!exists) portions.push(normalized);
}

function inferUnitEquivalentByFoodName(foodName, baseQty) {
    const safeBase = Math.max(1, parseDecimalSafe(baseQty) || 100);
    const rules = [
        { term: 'ovo', equivalent: 50 },
        { term: 'banana', equivalent: 90 },
        { term: 'maca', equivalent: 130 },
        { term: 'pera', equivalent: 140 },
        { term: 'laranja', equivalent: 130 },
        { term: 'tangerina', equivalent: 120 },
        { term: 'kiwi', equivalent: 75 },
        { term: 'abacate', equivalent: 150 },
        { term: 'manga', equivalent: 150 }
    ];
    const match = rules.find((rule) => foodName.includes(rule.term));
    return Math.max(1, parseDecimalSafe(match?.equivalent) || safeBase);
}

function getFallbackFoodPortions(foodLike = {}) {
    const food = normalizeFoodCatalogRow(foodLike) || {};
    const defaultPortions = [];
    const baseUnit = normalizeFoodUnitKey(food.base_unit || 'g');
    const baseQty = Math.max(0.1, parseDecimalSafe(food.base_qty) || 100);
    const foodId = String(food.id || '');
    const foodName = normalizeText(food.name || '');
    if (baseUnit === 'ml' || baseUnit === 'l') {
        addFallbackPortion(defaultPortions, foodId, { label: 'mililitro (ml)', amount: 1, unit_key: 'ml', base_qty_equivalent: 1, is_default: true, sort_order: 0 });
        addFallbackPortion(defaultPortions, foodId, { label: 'litro (l)', amount: 1, unit_key: 'l', base_qty_equivalent: 1000, is_default: false, sort_order: 5 });
        addFallbackPortion(defaultPortions, foodId, { label: 'colher de chá', amount: 1, unit_key: 'tsp', base_qty_equivalent: 5, is_default: false, sort_order: 10 });
        addFallbackPortion(defaultPortions, foodId, { label: 'colher de sopa', amount: 1, unit_key: 'tbsp', base_qty_equivalent: 15, is_default: false, sort_order: 20 });
        addFallbackPortion(defaultPortions, foodId, { label: 'xícara', amount: 1, unit_key: 'cup', base_qty_equivalent: 240, is_default: false, sort_order: 30 });
        addFallbackPortion(defaultPortions, foodId, { label: 'copo', amount: 1, unit_key: 'glass', base_qty_equivalent: 200, is_default: false, sort_order: 40 });
        addFallbackPortion(defaultPortions, foodId, { label: 'concha', amount: 1, unit_key: 'ladle', base_qty_equivalent: 100, is_default: false, sort_order: 50 });
    } else if (baseUnit === 'un') {
        addFallbackPortion(defaultPortions, foodId, { label: 'unidade', amount: 1, unit_key: 'un', base_qty_equivalent: 1, is_default: true, sort_order: 0 });
    } else {
        addFallbackPortion(defaultPortions, foodId, { label: 'grama (g)', amount: 1, unit_key: 'g', base_qty_equivalent: 1, is_default: true, sort_order: 0 });
    }

    const sliceFriendlyTerms = ['pao', 'pão', 'pizza', 'bolo', 'torta', 'queijo', 'presunto', 'peito de peru', 'torrada'];
    if (sliceFriendlyTerms.some((term) => foodName.includes(normalizeText(term)))) {
        addFallbackPortion(defaultPortions, foodId, {
            label: 'fatia',
            amount: 1,
            unit_key: 'slice',
            base_qty_equivalent: 25,
            is_default: false,
            sort_order: 15
        });
    }

    const portableTerms = ['ovo', 'banana', 'maca', 'pera', 'laranja', 'tangerina', 'kiwi', 'manga', 'abacate', 'goiaba'];
    if (baseUnit === 'g' && portableTerms.some((term) => foodName.includes(term))) {
        addFallbackPortion(defaultPortions, foodId, {
            label: 'unidade',
            amount: 1,
            unit_key: 'un',
            base_qty_equivalent: inferUnitEquivalentByFoodName(foodName, baseQty),
            is_default: false,
            sort_order: 12
        });
    }

    const spoonFriendlyTerms = ['arroz', 'feijao', 'lentilha', 'grao de bico', 'ervilha', 'macarrao', 'quinoa', 'cuscuz', 'aveia', 'granola', 'farofa'];
    if (baseUnit === 'g' && spoonFriendlyTerms.some((term) => foodName.includes(term))) {
        addFallbackPortion(defaultPortions, foodId, { label: 'colher de chá', amount: 1, unit_key: 'tsp', base_qty_equivalent: 5, is_default: false, sort_order: 18 });
        addFallbackPortion(defaultPortions, foodId, { label: 'colher de sopa', amount: 1, unit_key: 'tbsp', base_qty_equivalent: 15, is_default: false, sort_order: 20 });
        addFallbackPortion(defaultPortions, foodId, { label: 'xícara', amount: 1, unit_key: 'cup', base_qty_equivalent: 160, is_default: false, sort_order: 25 });
        addFallbackPortion(defaultPortions, foodId, { label: 'concha', amount: 1, unit_key: 'ladle', base_qty_equivalent: 100, is_default: false, sort_order: 30 });
    }

    if (baseUnit === 'g' && isLikelyLiquidFoodName(food.name || '')) {
        addFallbackPortion(defaultPortions, foodId, { label: 'mililitro (ml)', amount: 1, unit_key: 'ml', base_qty_equivalent: 1, is_default: false, sort_order: 8 });
        addFallbackPortion(defaultPortions, foodId, { label: 'litro (l)', amount: 1, unit_key: 'l', base_qty_equivalent: 1000, is_default: false, sort_order: 9 });
        addFallbackPortion(defaultPortions, foodId, { label: 'copo', amount: 1, unit_key: 'glass', base_qty_equivalent: 200, is_default: false, sort_order: 22 });
    }

    return defaultPortions.sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
}

function getFoodPortions(foodLike = {}) {
    const normalizedFood = normalizeFoodCatalogRow(foodLike);
    if (!normalizedFood) return [];
    const provided = Array.isArray(normalizedFood.portions)
        ? normalizedFood.portions.map(normalizeFoodPortionRow).filter(Boolean)
        : [];
    const list = provided.length ? provided : getFallbackFoodPortions(normalizedFood);
    return list.sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));
}

function parseAmountAndUnit(rawValue, fallbackUnit = 'g') {
    const text = String(rawValue || '').trim();
    const normalizedTextValue = normalizeText(text);
    const numericMatches = text.replace(',', '.').match(/-?\d+(\.\d+)?/);
    const amount = Math.max(0, parseDecimalSafe(numericMatches?.[0] || '0'));
    const normalizedFallback = normalizeFoodUnitKey(fallbackUnit || 'g');

    let unitKey = normalizedFallback;
    if (normalizedTextValue) {
        for (const key of FOOD_UNIT_KEYS) {
            const aliases = FOOD_UNIT_ALIASES[key] || [];
            if (aliases.some((alias) => normalizedTextValue.includes(normalizeText(alias)))) {
                unitKey = key;
                break;
            }
        }
    }
    return {
        amount: amount > 0 ? amount : 0,
        unit: unitKey,
        unitKey
    };
}

function resolveFoodQuantity(foodLike, amountValue, unitKeyValue, portionId = '') {
    const food = normalizeFoodCatalogRow(foodLike);
    if (!food) {
        return {
            factor: 1,
            amount: Math.max(0.1, parseDecimalSafe(amountValue) || 100),
            unitKey: normalizeFoodUnitKey(unitKeyValue || 'g'),
            portion: null,
            qtyText: formatFoodQuantity(Math.max(0.1, parseDecimalSafe(amountValue) || 100), unitKeyValue || 'g')
        };
    }
    const baseQty = Math.max(0.1, parseDecimalSafe(food.base_qty) || 100);
    const amount = Math.max(0.1, parseDecimalSafe(amountValue) || baseQty);
    const unitKey = normalizeFoodUnitKey(unitKeyValue || food.base_unit || 'g');
    const portions = getFoodPortions(food);
    let selectedPortion = null;
    if (portionId) {
        selectedPortion = portions.find((portion) => String(portion.id || '') === String(portionId));
    }
    if (!selectedPortion) {
        selectedPortion = portions.find((portion) => normalizeFoodUnitKey(portion.unit_key) === unitKey && !!portion.is_default)
            || portions.find((portion) => normalizeFoodUnitKey(portion.unit_key) === unitKey)
            || null;
    }

    let baseEquivalent = amount;
    if (selectedPortion) {
        const perAmount = Math.max(0.0001, parseDecimalSafe(selectedPortion.base_qty_equivalent) || 1) / Math.max(0.0001, parseDecimalSafe(selectedPortion.amount) || 1);
        baseEquivalent = amount * perAmount;
    } else if (unitKey === normalizeFoodUnitKey(food.base_unit || 'g')) {
        baseEquivalent = amount;
    }
    const factor = Math.max(0.01, baseEquivalent / baseQty);
    return {
        factor,
        amount,
        unitKey,
        portion: selectedPortion,
        baseEquivalent,
        qtyText: formatFoodQuantity(amount, unitKey)
    };
}

function computeMacrosByAmount(food, amount, unit, portionId = '') {
    const normalized = normalizeFoodCatalogRow(food);
    if (!normalized) {
        return { kcal: 0, protein: 0, carb: 0, fat: 0, base_qty: 100, base_unit: 'g', amount: 0, unit_key: 'g', portion_id: '', portion_label: '' };
    }
    const resolved = resolveFoodQuantity(normalized, amount, unit, portionId);
    const factor = resolved.factor;
    return {
        kcal: Math.round((normalized.kcal || 0) * factor),
        protein: Math.round((normalized.protein || 0) * factor * 10) / 10,
        carb: Math.round((normalized.carb || 0) * factor * 10) / 10,
        fat: Math.round((normalized.fat || 0) * factor * 10) / 10,
        base_qty: Math.max(0.1, normalized.base_qty || 100),
        base_unit: normalized.base_unit,
        amount: resolved.amount,
        unit_key: resolved.unitKey,
        portion_id: String(resolved.portion?.id || ''),
        portion_label: resolved.portion?.label || getFoodUnitLabel(resolved.unitKey, resolved.amount)
    };
}

async function fetchFoodPortionsByFoodIds(foodIds = []) {
    const safeIds = Array.from(new Set((Array.isArray(foodIds) ? foodIds : []).map((id) => String(id || '').trim()).filter(Boolean)));
    if (!safeIds.length || !isSupabaseReady()) return new Map();
    const { data, error } = await window.supabase
        .from(SUPABASE_TABLES.foodPortions)
        .select('*')
        .in('food_id', safeIds);
    if (error) {
        console.warn('Supabase food portions fetch failed', error.message);
        return new Map();
    }
    const grouped = new Map();
    (data || []).forEach((row) => {
        const normalized = normalizeFoodPortionRow(row);
        if (!normalized) return;
        const foodId = String(normalized.food_id || '').trim();
        if (!foodId) return;
        if (!grouped.has(foodId)) grouped.set(foodId, []);
        grouped.get(foodId).push(normalized);
    });
    return grouped;
}

