// â”€â”€â”€ Meu Perfil (Student Profile) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let _perfilModalField = '';

function normalizeStudentConfigSection(value = '') {
    const raw = String(value || '').trim().toLowerCase();
    const aliasMap = {
        perfil: 'perfil',
        anamnese: 'anamnesis',
        anamnesis: 'anamnesis',
        consultoria: 'consultoria',
        financeiro: 'consultoria',
        evolucao: 'evolucao',
        'evolução': 'evolucao'
    };
    const normalized = aliasMap[raw] || raw;
    if (STUDENT_CONFIG_SECTION_VALUES.includes(normalized)) return normalized;
    return 'perfil';
}

function getStudentConfigSectionStorageKey() {
    const userId = String(memoryGetItem('currentUserId') || memoryGetItem('currentStudentId') || 'default').trim() || 'default';
    return `${STUDENT_CONFIG_SECTION_KEY}:${userId}`;
}

function switchStudentConfigSection(section = 'perfil', options = {}) {
    const normalized = normalizeStudentConfigSection(section);
    activeStudentConfigSection = normalized;
    if (options?.persist !== false) {
        memorySetItem(getStudentConfigSectionStorageKey(), normalized);
    }

    const root = document.getElementById('view-student-config');
    if (!root) return normalized;

    root.querySelectorAll('.student-config-tab').forEach((button) => {
        const tabId = String(button.id || '');
        const tabSection = normalizeStudentConfigSection(tabId.replace('student-config-tab-', ''));
        const isActive = tabSection === normalized;
        button.classList.toggle('active', isActive);
        button.setAttribute('aria-selected', isActive ? 'true' : 'false');
    });

    root.querySelectorAll('.student-config-panel').forEach((panel) => {
        const panelId = String(panel.id || '');
        const panelSection = normalizeStudentConfigSection(panelId.replace('student-config-panel-', ''));
        const isActive = panelSection === normalized;
        panel.classList.toggle('active', isActive);
    });

    return normalized;
}

function normalizeStudentWeeklyCheckinsShape(raw = {}) {
    const safeRaw = raw && typeof raw === 'object' && !Array.isArray(raw) ? raw : {};
    const sortedEntries = Object.entries(safeRaw)
        .filter(([weekKey]) => /^\d{4}-\d{2}-\d{2}$/.test(String(weekKey || '')))
        .sort(([left], [right]) => left.localeCompare(right))
        .slice(-24);

    return sortedEntries.reduce((acc, [weekKey, entry]) => {
        const safeEntry = entry && typeof entry === 'object' ? entry : {};
        acc[weekKey] = {
            notes: sanitizeUserInput(
                safeEntry.notes || safeEntry.note || safeEntry.observacoes || safeEntry.observacao || '',
                { allowNewlines: true, maxLen: 600 }
            ),
            completedAt: sanitizeUserInput(safeEntry.completedAt || safeEntry.completed_at || '', { maxLen: 40 }),
            updatedAt: sanitizeUserInput(safeEntry.updatedAt || safeEntry.updated_at || safeEntry.savedAt || '', { maxLen: 40 }),
            createdAt: sanitizeUserInput(safeEntry.createdAt || safeEntry.created_at || safeEntry.updatedAt || safeEntry.updated_at || '', { maxLen: 40 })
        };
        return acc;
    }, {});
}

function getStudentWeeklyCheckins(student = {}) {
    return normalizeStudentWeeklyCheckinsShape(student?.weeklyCheckins || student?.weekly_checkins || {});
}

function formatStudentCheckinDateRange(weekStart) {
    const start = weekStart instanceof Date ? new Date(weekStart) : new Date(weekStart);
    const end = new Date(start);
    end.setDate(start.getDate() + 6);
    const fmt = (date) => date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
    return `${fmt(start)} a ${fmt(end)}`;
}

function isStudentCheckinDateWithinWeek(iso = '', weekStart = new Date()) {
    if (!iso) return false;
    const target = new Date(iso);
    if (Number.isNaN(target.getTime())) return false;
    const start = weekStart instanceof Date ? new Date(weekStart) : new Date(weekStart);
    start.setHours(0, 0, 0, 0);
    const endExclusive = new Date(start);
    endExclusive.setDate(start.getDate() + 7);
    return target.getTime() >= start.getTime() && target.getTime() < endExclusive.getTime();
}

function buildStudentWeeklyCheckinContext(student = {}, baseDate = new Date()) {
    const weekStart = getCurrentWeekMondayDate(baseDate);
    const weekKey = formatDateKeyFromDate(weekStart);
    const weeklyCheckins = getStudentWeeklyCheckins(student);
    const checkinEntry = weeklyCheckins[weekKey] || {
        notes: '',
        completedAt: '',
        updatedAt: '',
        createdAt: ''
    };

    const history = Array.isArray(student?.metricHistory) ? student.metricHistory : [];
    const weightEntriesThisWeek = history
        .filter((entry) => entry?.weight && isStudentCheckinDateWithinWeek(entry?.date, weekStart))
        .sort((left, right) => new Date(right.date).getTime() - new Date(left.date).getTime());
    const latestWeightEntry = weightEntriesThisWeek[0] || null;

    const currentUserId = String(memoryGetItem('currentUserId') || '').trim();
    const mediaItems = currentUserId && studentMediaState.loadedForUser === currentUserId && Array.isArray(studentMediaState.items)
        ? studentMediaState.items.map((item, index) => ({ ...item, previewIndex: index }))
        : [];
    const mediaThisWeek = mediaItems.filter((item) => isStudentCheckinDateWithinWeek(item?.created_at, weekStart));
    const notes = String(checkinEntry.notes || '').trim();
    const taskList = [
        {
            key: 'peso',
            title: 'Atualizar peso',
            description: latestWeightEntry
                ? `Último registro em ${formatDate(latestWeightEntry.date).trim()}`
                : 'Registre seu peso atual da semana',
            done: !!latestWeightEntry
        },
        {
            key: 'midia',
            title: 'Enviar fotos do shape',
            description: mediaThisWeek.length > 0
                ? `${mediaThisWeek.length} arquivo(s) enviado(s) nesta semana`
                : 'Frente, lado e costas já ajudam bastante',
            done: mediaThisWeek.length > 0
        },
        {
            key: 'notas',
            title: 'Escrever observações',
            description: notes
                ? 'Observações salvas para o treinador'
                : 'Conte como foi sua semana, energia, fome e treino',
            done: !!notes
        }
    ];
    const tasksDone = taskList.filter((task) => task.done).length;

    return {
        weekStart,
        weekKey,
        dateRangeLabel: formatStudentCheckinDateRange(weekStart),
        checkinEntry,
        notes,
        latestWeightEntry,
        mediaThisWeek,
        mediaPreview: mediaThisWeek.slice(0, 4),
        taskList,
        tasksDone,
        tasksTotal: taskList.length,
        completed: !!checkinEntry.completedAt
    };
}

function refreshStudentCheckinViewIfVisible() {
    if (inferCurrentStudentViewKey() === 'checkin') {
        renderStudentCheckinMain();
    }
}

function updateStudentCurrentWeekCheckin(mutator) {
    if (typeof mutator !== 'function') {
        return { ok: false, message: 'Atualização inválida.' };
    }

    return persistStudentData((students, studentIdx) => {
        const student = students[studentIdx];
        if (!student || typeof student !== 'object') return;

        const weeklyCheckins = getStudentWeeklyCheckins(student);
        const now = new Date().toISOString();
        const weekKey = formatDateKeyFromDate(getCurrentWeekMondayDate(new Date()));
        const entry = {
            notes: '',
            completedAt: '',
            updatedAt: '',
            createdAt: now,
            ...(weeklyCheckins[weekKey] || {})
        };

        mutator(entry, { student, now, weekKey });

        entry.notes = sanitizeUserInput(entry.notes || '', { allowNewlines: true, maxLen: 600 });
        entry.completedAt = sanitizeUserInput(entry.completedAt || '', { maxLen: 40 });
        entry.updatedAt = sanitizeUserInput(entry.updatedAt || now, { maxLen: 40 }) || now;
        entry.createdAt = sanitizeUserInput(entry.createdAt || now, { maxLen: 40 }) || now;

        weeklyCheckins[weekKey] = entry;
        student.weeklyCheckins = normalizeStudentWeeklyCheckinsShape(weeklyCheckins);
        students[studentIdx] = student;
    });
}

function saveStudentWeeklyCheckinNotes() {
    const notes = sanitizeUserInput(document.getElementById('student-checkin-notes')?.value, {
        allowNewlines: true,
        maxLen: 600
    });
    const result = updateStudentCurrentWeekCheckin((entry, ctx) => {
        entry.notes = notes;
        entry.updatedAt = ctx.now;
    });

    if (!result?.ok) {
        showDietRuntimeMessage(result?.message || 'Não foi possível salvar suas observações agora.', 'error');
        return;
    }

    showDietRuntimeMessage(notes ? 'Observações do check-in salvas.' : 'Observações do check-in removidas.', 'success');
    renderStudentCheckinMain();
}

function toggleStudentWeeklyCheckinStatus(forceComplete = null) {
    const { student } = getStudentData();
    if (!student) return;

    const notes = sanitizeUserInput(document.getElementById('student-checkin-notes')?.value, {
        allowNewlines: true,
        maxLen: 600
    });
    const context = buildStudentWeeklyCheckinContext(student);
    const shouldComplete = forceComplete === null ? !context.completed : !!forceComplete;

    if (shouldComplete && !notes && !context.latestWeightEntry && context.mediaThisWeek.length === 0) {
        showDietRuntimeMessage('Atualize peso, envie uma foto ou escreva observações antes de concluir o check-in.', 'info');
        return;
    }

    const result = updateStudentCurrentWeekCheckin((entry, ctx) => {
        entry.notes = notes;
        entry.updatedAt = ctx.now;
        entry.completedAt = shouldComplete ? ctx.now : '';
    });

    if (!result?.ok) {
        showDietRuntimeMessage(result?.message || 'Não foi possível atualizar o check-in.', 'error');
        return;
    }

    showDietRuntimeMessage(shouldComplete ? 'Check-in semanal concluído.' : 'Check-in reaberto para edição.', 'success');
    renderStudentCheckinMain();
}

async function openStudentEvolutionFromCheckin(section = 'evolucao') {
    await switchStudentView('config');
    switchStudentConfigSection(section);
}

function renderStudentCheckinMain() {
    const container = document.getElementById('student-checkin-content-main');
    const subtitleEl = document.getElementById('student-checkin-subtitle');
    const primaryActionBtn = document.querySelector('#view-student-checkin .student-checkin-hero-actions .btn-primary');
    if (!container) return;

    const { student } = getStudentData();
    if (!student) {
        container.innerHTML = `
            <div class="perfil-history-empty" data-motion="surface">
                <i class="ph-bold ph-user-circle"></i>
                <p>Não encontramos seu perfil do aluno para montar o check-in.</p>
            </div>
        `;
        return;
    }

    const userId = String(memoryGetItem('currentUserId') || '').trim();
    if (
        userId
        && !studentMediaState.loading
        && (studentMediaState.loadedForUser !== userId || !studentMediaState.loadedAt)
    ) {
        void loadStudentMediaGallery().then(() => {
            refreshStudentCheckinViewIfVisible();
        });
    }

    const context = buildStudentWeeklyCheckinContext(student);
    const weightValue = parseFloat(student.weight) || 0;
    const completionText = context.completed
        ? `Concluído em ${formatDate(context.checkinEntry.completedAt).trim()}`
        : context.tasksDone > 0
            ? `${context.tasksDone} de ${context.tasksTotal} etapas concluídas`
            : 'Nenhuma etapa concluída ainda';
    const completionTone = context.completed ? 'is-complete' : (context.tasksDone > 0 ? 'is-progress' : 'is-pending');
    const mediaSummaryText = studentMediaState.loading
        ? 'Carregando galeria...'
        : studentMediaState.error
            ? studentMediaState.error
            : `${context.mediaThisWeek.length} arquivo(s) nesta semana`;

    if (subtitleEl) {
        subtitleEl.textContent = `Semana de ${context.dateRangeLabel} • ${completionText}`;
    }
    if (primaryActionBtn) {
        primaryActionBtn.innerHTML = context.completed
            ? '<i class="ph-bold ph-arrow-counter-clockwise"></i> Reabrir'
            : '<i class="ph-bold ph-check-circle"></i> Concluir';
    }

    const historyKeys = Array.from(new Set([context.weekKey, ...Object.keys(getStudentWeeklyCheckins(student))]))
        .sort((left, right) => right.localeCompare(left))
        .slice(0, 6);
    const historyItems = historyKeys.map((weekKey) => {
        const weekContext = buildStudentWeeklyCheckinContext(student, new Date(`${weekKey}T12:00:00`));
        const statusLabel = weekContext.completed
            ? 'Concluído'
            : weekContext.tasksDone > 0
                ? 'Em andamento'
                : 'Sem atividade';
        return `
            <div class="student-checkin-history-item ${weekContext.completed ? 'is-complete' : ''}">
                <div>
                    <strong>Semana ${escHtml(weekContext.dateRangeLabel)}</strong>
                    <span>${escHtml(statusLabel)} • ${weekContext.tasksDone}/${weekContext.tasksTotal} etapas</span>
                </div>
                <small>${weekContext.checkinEntry.completedAt ? escHtml(formatDate(weekContext.checkinEntry.completedAt).trim()) : '—'}</small>
            </div>
        `;
    }).join('');

    container.innerHTML = `
        <section class="student-checkin-summary-grid">
            <article class="student-checkin-summary-card ${completionTone}" data-motion="card">
                <span class="student-checkin-summary-label">Status da semana</span>
                <strong>${context.completed ? 'Check-in concluído' : 'Check-in em aberto'}</strong>
                <small>${escHtml(completionText)}</small>
            </article>
            <article class="student-checkin-summary-card" data-motion="card">
                <span class="student-checkin-summary-label">Peso atual</span>
                <strong>${weightValue > 0 ? `${weightValue} kg` : 'Sem registro'}</strong>
                <small>${context.latestWeightEntry ? `Atualizado em ${escHtml(formatDate(context.latestWeightEntry.date).trim())}` : 'Atualize o peso desta semana'}</small>
            </article>
            <article class="student-checkin-summary-card" data-motion="card">
                <span class="student-checkin-summary-label">Fotos e vídeos</span>
                <strong>${studentMediaState.loading ? '...' : context.mediaThisWeek.length}</strong>
                <small>${escHtml(mediaSummaryText)}</small>
            </article>
            <article class="student-checkin-summary-card" data-motion="card">
                <span class="student-checkin-summary-label">Observações</span>
                <strong>${context.notes ? 'Salvas' : 'Pendentes'}</strong>
                <small>${context.notes ? 'Seu treinador já pode consultar.' : 'Use este campo para resumir a semana.'}</small>
            </article>
        </section>

        <div class="student-checkin-layout">
            <section class="student-checkin-main-card" data-motion="surface">
                <div class="perfil-section-title">
                    <i class="ph-fill ph-check-square"></i>
                    <h3>Checklist do check-in</h3>
                </div>
                <div class="student-checkin-task-list">
                    ${context.taskList.map((task) => `
                        <button type="button" class="student-checkin-task ${task.done ? 'is-done' : ''}" onclick="${task.key === 'peso' ? "openPerfilUpdateModal('peso')" : task.key === 'midia' ? 'triggerStudentGalleryUpload()' : "document.getElementById('student-checkin-notes')?.focus()"}">
                            <span class="student-checkin-task-icon">
                                <i class="ph-bold ${task.done ? 'ph-check-circle' : task.key === 'peso' ? 'ph-barbell' : task.key === 'midia' ? 'ph-camera' : 'ph-note-pencil'}"></i>
                            </span>
                            <span class="student-checkin-task-copy">
                                <strong>${escHtml(task.title)}</strong>
                                <small>${escHtml(task.description)}</small>
                            </span>
                        </button>
                    `).join('')}
                </div>

                <div class="perfil-section-title" style="margin-top: 1.6rem;">
                    <i class="ph-fill ph-note-pencil"></i>
                    <h3>Observações da semana</h3>
                </div>
                <p class="student-checkin-helper">
                    Conte como ficaram energia, sono, fome, treinos, retenção, dores ou qualquer ajuste que o treinador precise ver.
                </p>
                <textarea id="student-checkin-notes" class="student-checkin-notes-input" placeholder="Ex: peso oscilou, treino de pernas encaixou melhor, senti mais fome à noite...">${escHtml(context.notes)}</textarea>
                <div class="student-checkin-form-actions">
                    <button class="btn-secondary" type="button" onclick="saveStudentWeeklyCheckinNotes()">
                        <i class="ph-bold ph-floppy-disk"></i> Salvar observações
                    </button>
                    <button class="btn-primary" type="button" onclick="toggleStudentWeeklyCheckinStatus()">
                        <i class="ph-bold ${context.completed ? 'ph-arrow-counter-clockwise' : 'ph-check-circle'}"></i> ${context.completed ? 'Reabrir check-in' : 'Concluir check-in'}
                    </button>
                </div>
            </section>

            <aside class="student-checkin-side-column">
                <section class="student-checkin-side-card" data-motion="surface">
                    <div class="perfil-section-title">
                        <i class="ph-fill ph-images-square"></i>
                        <h3>Últimos envios</h3>
                    </div>
                    ${context.mediaPreview.length > 0 ? `
                        <div class="student-checkin-media-grid">
                            ${context.mediaPreview.map((item) => `
                                <button type="button" class="student-checkin-media-thumb" onclick="openPerfilMediaViewer(${item.previewIndex})" aria-label="Abrir mídia enviada em ${escHtml(formatDate(item.created_at).trim())}">
                                    ${String(item.media_type || '').toLowerCase() === 'video'
                                        ? `<video src="${escHtml(item.signedUrl)}" muted playsinline></video><span class="student-checkin-media-badge">Vídeo</span>`
                                        : `<img src="${escHtml(item.signedUrl)}" alt="Foto de progresso enviada pelo aluno">`
                                    }
                                </button>
                            `).join('')}
                        </div>
                    ` : `
                        <div class="student-checkin-empty">
                            <i class="ph-bold ${studentMediaState.loading ? 'ph-spinner-gap' : 'ph-camera'}"></i>
                            <p>${escHtml(studentMediaState.loading ? 'Carregando sua galeria...' : 'Nenhuma foto enviada nesta semana ainda.')}</p>
                        </div>
                    `}
                    <button class="btn-secondary student-checkin-side-action" type="button" onclick="triggerStudentGalleryUpload()">
                        <i class="ph-bold ph-upload-simple"></i> Enviar fotos do shape
                    </button>
                </section>

                <section class="student-checkin-side-card" data-motion="surface">
                    <div class="perfil-section-title">
                        <i class="ph-fill ph-clock-counter-clockwise"></i>
                        <h3>Semanas recentes</h3>
                    </div>
                    <div class="student-checkin-history-list">
                        ${historyItems || `
                            <div class="student-checkin-empty">
                                <i class="ph-bold ph-calendar-blank"></i>
                                <p>Seus check-ins vão aparecer aqui ao longo das semanas.</p>
                            </div>
                        `}
                    </div>
                    <button class="btn-secondary student-checkin-side-action" type="button" onclick="openStudentEvolutionFromCheckin()">
                        <i class="ph-bold ph-chart-line-up"></i> Abrir evolução completa
                    </button>
                </section>
            </aside>
        </div>
    `;
}

function getStudentData() {
    const studentId = memoryGetItem('currentStudentId');
    const students = readStorageJSON('trainerStudents', []);
    return { studentId, students, student: students.find(s => s.id === studentId) };
}

function stampStudentLocalDataUpdatedAt(studentLike = {}, isoNow = '') {
    if (!studentLike || typeof studentLike !== 'object') return;
    studentLike._localDataUpdatedAt = String(isoNow || new Date().toISOString());
}

function stampStudentsLocalDataUpdatedAt(students = [], studentId = '', isoNow = '') {
    if (!Array.isArray(students) || students.length === 0) return false;
    const safeId = String(studentId || '').trim();
    const stampIso = String(isoNow || new Date().toISOString());
    if (safeId) {
        const idx = students.findIndex((student) => String(student?.id || '').trim() === safeId);
        if (idx >= 0 && students[idx] && typeof students[idx] === 'object') {
            stampStudentLocalDataUpdatedAt(students[idx], stampIso);
            return true;
        }
    }
    if (students.length === 1 && students[0] && typeof students[0] === 'object') {
        stampStudentLocalDataUpdatedAt(students[0], stampIso);
        return true;
    }
    return false;
}

function persistStudentData(mutator, options = {}) {
    if (typeof mutator !== 'function') {
        return { ok: false, localOk: false, remoteOk: false, message: 'Mutação inválida.', opId: createStudentPersistOpId() };
    }
    const students = readStorageJSON('trainerStudents', []);
    if (!Array.isArray(students) || students.length === 0) {
        return { ok: false, localOk: false, remoteOk: false, message: 'Sem alunos para persistir.', opId: createStudentPersistOpId() };
    }

    const currentStudentId = String(memoryGetItem('currentStudentId') || '').trim();
    let studentIdx = students.findIndex((s) => String(s?.id || '').trim() === currentStudentId);
    if (studentIdx < 0 && Number.isInteger(currentStudentIdx) && currentStudentIdx >= 0 && currentStudentIdx < students.length) {
        studentIdx = currentStudentIdx;
    }
    if (studentIdx < 0) {
        return { ok: false, localOk: false, remoteOk: false, message: 'Aluno atual não encontrado.', opId: createStudentPersistOpId() };
    }

    mutator(students, studentIdx);
    const touchedStudentId = String(students[studentIdx]?.id || currentStudentId || '').trim();
    stampStudentsLocalDataUpdatedAt(students, touchedStudentId);
    return saveStudentData(students, { ...options, studentId: touchedStudentId });
}

function saveStudentData(students, options = {}) {
    const skipSupabaseSync = !!options?.skipSupabaseSync;
    const evaluationModeActive = isTrainerEvaluationModeActive();
    const syncModeRaw = String(options?.syncMode || '').trim().toLowerCase();
    const allowedModes = new Set(['local-only', 'batched', 'immediate']);
    let syncMode = (skipSupabaseSync || evaluationModeActive)
        ? 'local-only'
        : (allowedModes.has(syncModeRaw) ? syncModeRaw : 'batched');
    const syncDelayMs = parseInt(options?.syncDelayMs, 10) || BATCHED_STUDENTS_SYNC_DEFAULT_DELAY_MS;
    const expectedRevision = Number.isFinite(parseIntegerSafe(options?.expectedRevision))
        ? parseIntegerSafe(options.expectedRevision)
        : null;
    if (expectedRevision !== null && expectedRevision !== trainerPlanEditRevision) {
        return {
            ok: false,
            localOk: false,
            remoteOk: false,
            message: 'Alteração ignorada por revisão desatualizada.',
            opId: String(options?.opId || createStudentPersistOpId())
        };
    }
    if (syncMode === 'immediate' && hasStoragePressure()) {
        syncMode = 'batched';
    }
    const normalized = normalizeStudentsDietSchema(students || []);
    const opId = String(options?.opId || createStudentPersistOpId());
    const studentId = String(options?.studentId || '');
    const shouldStampDataUpdatedAt = options?.stampDataUpdatedAt !== false;
    if (shouldStampDataUpdatedAt) {
        stampStudentsLocalDataUpdatedAt(normalized, studentId);
    }
    const serializedStudents = JSON.stringify(normalized);
    const currentSerialized = String(memoryGetItem('trainerStudents') || '');
    if (currentSerialized !== serializedStudents) {
        memorySetItem('trainerStudents', serializedStudents);
    }
    const persistentStorage = appStorage.isPersistent();
    if (!evaluationModeActive && !persistentStorage && navigator.onLine !== false && isSupabaseReady()) {
        setStudentSyncState('pending', 'Armazenamento local no limite. Mantendo sincronização remota.');
    }
    const resultBase = {
        ok: true,
        localOk: true,
        remoteOk: false,
        message: evaluationModeActive
            ? 'Salvo no sandbox local.'
            : (persistentStorage ? 'Salvo localmente.' : 'Salvo temporariamente. Libere espaço do navegador para persistir.'),
        opId
    };

    if (syncMode === 'local-only') {
        logStudentPersistOperation({
            opId,
            studentId,
            mode: syncMode,
            localOk: true,
            remoteOk: false,
            reason: evaluationModeActive ? 'evaluation-sandbox-local-only' : 'local-only'
        });
        return resultBase;
    }

    if (syncMode === 'batched') {
        scheduleBatchedStudentsSync(normalized, syncDelayMs);
        logStudentPersistOperation({ opId, studentId, mode: syncMode, localOk: true, remoteOk: false, reason: 'queued-batched' });
        return { ...resultBase, message: 'Salvo localmente. Sincronização pendente.' };
    }

    if (batchedStudentsSyncTimer) {
        clearTimeout(batchedStudentsSyncTimer);
        batchedStudentsSyncTimer = null;
    }
    batchedStudentsSyncPayload = null;
    if (!skipSupabaseSync) {
        queueSupabaseStudentsSync(normalized, { opId, syncMode });
        logStudentPersistOperation({ opId, studentId, mode: syncMode, localOk: true, remoteOk: false, reason: 'queued-immediate' });
        return { ...resultBase, message: 'Salvo localmente. Sincronizando...' };
    }
    logStudentPersistOperation({ opId, studentId, mode: syncMode, localOk: true, remoteOk: false, reason: 'skip-supabase-sync' });
    return resultBase;
}

function updateStudentRecord(studentId, updater) {
    if (!studentId) return;
    const students = readStorageJSON('trainerStudents', []);
    const idx = students.findIndex(s => String(s.id) === String(studentId));
    if (idx < 0) return;
    const current = students[idx] || {};
    const nextPartial = typeof updater === 'function' ? updater(current) : updater;
    if (!nextPartial || typeof nextPartial !== 'object') return;
    students[idx] = { ...current, ...nextPartial, id: current.id };
    saveStudentData(students, { studentId: String(current.id || studentId || '') });
}

function appendStudentWorkoutHistory(studentId, workoutArchive) {
    if (!studentId || !workoutArchive) return;
    updateStudentRecord(studentId, (current) => {
        const history = Array.isArray(current.workoutHistory) ? current.workoutHistory.slice() : [];
        history.push(workoutArchive);
        const trimmed = history.slice(-200);
        return { workoutHistory: trimmed };
    });
}

function setStudentChatMessages(studentId, messages, options = {}) {
    if (!studentId) return [];
    const safeId = String(studentId || '').trim();
    const students = readStorageJSON('trainerStudents', []);
    const idx = students.findIndex((s) => String(s?.id || '').trim() === safeId);
    if (idx < 0) return [];
    const currentMessages = Array.isArray(students[idx]?.chatMessages) ? students[idx].chatMessages : [];
    const merged = mergeChatMessagesById(currentMessages, messages || []);
    students[idx] = {
        ...students[idx],
        chatMessages: merged
    };
    const syncMode = String(options?.syncMode || '').trim().toLowerCase() === 'immediate' ? 'immediate' : 'batched';
    saveStudentData(students, { studentId: safeId, syncMode });
    return merged;
}

function mergeWorkoutHistoryFromStudents(students) {
    const local = readStorageJSON('workoutHistory', []);
    const map = new Map();
    const addItem = (item) => {
        if (!item) return;
        const key = `${item.ID_Usuario || ''}-${item.Data_Treino || ''}-${item.Nome_Treino || ''}`;
        if (!map.has(key)) map.set(key, item);
    };
    local.forEach(addItem);
    (students || []).forEach((s) => {
        if (Array.isArray(s.workoutHistory)) {
            s.workoutHistory.forEach(addItem);
        }
    });
    const merged = Array.from(map.values());
    memorySetItem('workoutHistory', JSON.stringify(merged));
}

function syncChatMessagesFromStudents(students) {
    (students || []).forEach((s) => {
        if (!s?.id || !Array.isArray(s.chatMessages)) return;
        const storageKey = getStudentChatStorageKey(s.id);
        const local = readStorageJSON(storageKey, []);
        const merged = mergeChatMessagesById(local, s.chatMessages);
        memorySetItem(storageKey, JSON.stringify(merged));
    });
}

function calcIMC(weight, height) {
    if (!weight || !height) return 0;
    const h = parseFloat(height) / 100;
    return (parseFloat(weight) / (h * h)).toFixed(1);
}

function parseDecimalSafe(value) {
    const parsed = parseFloat(String(value || '').replace(',', '.'));
    return Number.isFinite(parsed) ? parsed : 0;
}

function parseIntegerSafe(value) {
    const parsed = parseInt(String(value || ''), 10);
    return Number.isFinite(parsed) ? parsed : 0;
}

function calcTMBMifflin(weightKg, heightCm, ageYears, gender) {
    const peso = parseDecimalSafe(weightKg);
    const altura = parseDecimalSafe(heightCm);
    const idade = parseIntegerSafe(ageYears);
    if (peso <= 0 || altura <= 0 || idade <= 0) return 0;

    const genero = normalizeText(gender);
    const ajusteGenero = (genero === 'f' || genero.startsWith('fem')) ? -161 : 5;
    return (10 * peso) + (6.25 * altura) - (5 * idade) + ajusteGenero;
}

function syncStudentTmbData(student) {
    if (!student || typeof student !== 'object') return 0;
    const tmb = Math.round(calcTMBMifflin(student.weight, student.height, student.age, student.gender));
    if (!Number.isFinite(tmb) || tmb <= 0) {
        student.tmbBase = null;
        return 0;
    }
    student.tmbBase = tmb;
    return tmb;
}

function getIMCLabel(imc) {
    if (imc < 18.5) return 'Abaixo do peso';
    if (imc < 25) return 'Peso saudável';
    if (imc < 30) return 'Sobrepeso';
    return 'Obesidade';
}

function getPercentDelta(current, previous) {
    if (!previous || previous == 0) return null;
    return (((current - previous) / previous) * 100).toFixed(1);
}

function formatDate(iso) {
    if (!iso) return '—';
    const d = new Date(iso);
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    return `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()} `;
}

function formatDateShort(iso) {
    if (!iso) return '—';
    const d = new Date(iso);
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    return `${d.getDate()} ${months[d.getMonth()]} `;
}

function makeStorageRef(bucket, path) {
    const safeBucket = sanitizeUserInput(String(bucket || ''), { maxLen: 80 });
    const safePath = String(path || '').replace(/^\/+/, '').trim();
    if (!safeBucket || !safePath) return '';
    return `storage://${safeBucket}/${safePath}`;
}

function parseStorageRef(value) {
    const raw = String(value || '').trim();
    if (!raw.startsWith('storage://')) return null;
    const withoutPrefix = raw.slice('storage://'.length);
    const slashIdx = withoutPrefix.indexOf('/');
    if (slashIdx <= 0) return null;
    const bucket = withoutPrefix.slice(0, slashIdx);
    const path = withoutPrefix.slice(slashIdx + 1);
    if (!bucket || !path) return null;
    return { bucket, path };
}

function formatFileSize(bytesValue) {
    const bytes = Number(bytesValue) || 0;
    if (bytes <= 0) return '0 B';
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

async function resolveStorageRefUrl(value, expiresInSeconds = 3600) {
    if (!value) return '';
    if (String(value).startsWith('http://') || String(value).startsWith('https://') || String(value).startsWith('data:')) {
        return String(value);
    }
    const ref = parseStorageRef(value);
    if (!ref || !isSupabaseReady() || typeof window.supabase?.storage?.from !== 'function') return '';
    const { data, error } = await window.supabase.storage
        .from(ref.bucket)
        .createSignedUrl(ref.path, expiresInSeconds);
    if (error) {
        console.warn('Falha ao gerar signed URL de mídia.', error.message || error);
        return '';
    }
    return data?.signedUrl || '';
}

function setPerfilMediaStatus(message = '', type = '') {
    const el = document.getElementById('perfil-media-status');
    if (!el) return;
    el.textContent = message || '';
    el.classList.remove('success', 'error', 'loading');
    if (type) el.classList.add(type);
}

function getStudentAvatarSource(student = {}) {
    return String(
        student?.avatarRef
        || student?.avatar_url
        || memoryGetItem('currentUserAvatarRef')
        || ''
    ).trim();
}

function renderStudentAvatarElement(student = {}, resolvedUrl = '') {
    const avatarEl = document.getElementById('perfil-avatar');
    if (!avatarEl) return;
    const name = sanitizeUserInput(student?.name || memoryGetItem('studentName') || 'Aluno', { maxLen: 90 }) || 'Aluno';
    const initials = name.split(' ').map(w => w[0]).join('').substring(0, 2).toUpperCase();
    const avatarUrl = String(resolvedUrl || '').trim();
    if (avatarUrl) {
        avatarEl.innerHTML = `<img src="${escHtml(avatarUrl)}" alt="Foto de perfil" loading="lazy" decoding="async">`;
        avatarEl.classList.add('has-image');
    } else {
        avatarEl.innerHTML = `<span>${initials}</span>`;
        avatarEl.classList.remove('has-image');
    }
}

function getCurrentStudentSelection() {
    const studentId = String(memoryGetItem('currentStudentId') || '');
    const students = readStorageJSON('trainerStudents', []);
    const idx = students.findIndex((s) => String(s.id || '') === studentId);
    if (idx < 0) return { studentId, students, idx: -1, student: null };
    students[idx] = normalizeStudentDietSchema(students[idx]);
    return { studentId, students, idx, student: students[idx] };
}

function getWeekdayKeyFromDate(date = new Date()) {
    const key = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'][date.getDay()];
    return key || 'seg';
}

function formatRelativeDayLabel(dateKey = '') {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return dateKey;
    const today = getTodayDateKey();
    if (dateKey === today) return 'Hoje';
    const now = new Date();
    const target = new Date(`${dateKey}T00:00:00`);
    const diff = Math.round((target - new Date(`${today}T00:00:00`)) / 86400000);
    if (diff === 1) return 'Amanhã';
    if (diff === -1) return 'Ontem';
    return target.toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit' });
}

function resolveStudentNextWorkout(student) {
    const blocks = Array.isArray(student?.workoutBlocks) ? student.workoutBlocks : [];
    if (blocks.length === 0) return null;
    const studentId = String(student?.id || '');
    const history = readStorageJSON('workoutHistory', []).filter((entry) => String(entry?.ID_Usuario || '') === studentId);
    const today = new Date();
    const startWeek = new Date(today);
    startWeek.setHours(0, 0, 0, 0);
    const offset = (startWeek.getDay() + 6) % 7;
    startWeek.setDate(startWeek.getDate() - offset);
    const completedThisWeek = new Set(
        history
            .filter((entry) => {
                const d = new Date(entry?.Data_Treino || entry?.date || entry?.completedAt || 0);
                return Number.isFinite(d.getTime()) && d >= startWeek;
            })
            .map((entry) => String(entry?.Nome_Treino || entry?.title || '').trim().toLowerCase())
            .filter(Boolean)
    );
    for (let i = 0; i < blocks.length; i += 1) {
        const title = getWorkoutBlockTitle(blocks[i], i);
        if (!completedThisWeek.has(String(title || '').toLowerCase())) {
            return { block: blocks[i], idx: i, title };
        }
    }
    return { block: blocks[0], idx: 0, title: getWorkoutBlockTitle(blocks[0], 0), completedCycle: true };
}

function getTodayCheckinsMap(routine = {}) {
    const today = getTodayDateKey();
    const entries = Array.isArray(routine?.checkinsByDate?.[today]) ? routine.checkinsByDate[today] : [];
    const map = new Map();
    entries.forEach((entry) => map.set(String(entry.habitId || ''), entry));
    return map;
}

function isHabitDueToday(habit, now = new Date()) {
    if (!habit || habit.active === false) return false;
    if (habit.recurrenceType !== 'weekdays') return true;
    const wd = getWeekdayKeyFromDate(now);
    return (Array.isArray(habit.weekdays) ? habit.weekdays : []).includes(wd);
}

function isReminderDueToday(reminder, now = new Date()) {
    if (!reminder || reminder.active === false) return false;
    const today = getTodayDateKey();
    if (reminder.legacyDateOnly && reminder.dateKey) {
        return reminder.dateKey === today;
    }
    const recurrenceType = normalizeRoutineRecurrenceType(reminder.recurrenceType || 'daily');
    if (recurrenceType === 'weekdays') {
        const wd = getWeekdayKeyFromDate(now);
        return (Array.isArray(reminder.weekdays) ? reminder.weekdays : []).includes(wd);
    }
    return true;
}

function getRoutineRecurrenceLabel(entry = {}) {
    if (entry?.legacyDateOnly && entry?.dateKey) {
        return formatRelativeDayLabel(entry.dateKey);
    }
    const recurrenceType = normalizeRoutineRecurrenceType(entry?.recurrenceType || 'daily');
    if (recurrenceType === 'weekdays') {
        const list = Array.isArray(entry?.weekdays) ? entry.weekdays : [];
        return list.length > 0 ? list.join(' • ').toUpperCase() : 'Dias fixos';
    }
    return 'Todos os dias';
}

function decodeRoutineToken(token = '') {
    const raw = String(token || '');
    try {
        return decodeURIComponent(raw);
    } catch {
        return raw;
    }
}

function ensureRoutineModalDashboardRoot(modal) {
    if (!modal) return;
    const dashboardScreen = document.getElementById('student-dashboard-screen');
    if (dashboardScreen && modal.parentElement !== dashboardScreen) {
        dashboardScreen.appendChild(modal);
    }
}

function setupStudentRoutineActionBindings() {
    if (document.documentElement.dataset.studentRoutineActionsBound === '1') return;
    document.documentElement.dataset.studentRoutineActionsBound = '1';
    document.addEventListener('click', (event) => {
        const trigger = event.target?.closest?.('[data-student-routine-action]');
        if (!trigger) return;
        const action = String(trigger.getAttribute('data-student-routine-action') || '').trim();
        if (!action) return;
        event.preventDefault();
        if (action === 'open-workout') {
            switchStudentView('treino');
            return;
        }
        if (action === 'add-habit') {
            openRoutineHabitModal();
            return;
        }
        if (action === 'add-reminder') {
            openRoutineReminderModal();
            return;
        }
        if (action === 'open-cardio') {
            switchStudentView('cardio');
        }
    });
}

function renderStudentHomeMain(forcedStudent = null) {
    const selected = forcedStudent ? { student: normalizeStudentDietSchema(forcedStudent) } : getCurrentStudentSelection();
    const student = selected.student;
    const nextWorkoutEl = document.getElementById('student-next-workout-card-body');
    const routineEl = document.getElementById('student-routine-list');
    const remindersEl = document.getElementById('student-reminders-list');
    const routineBaseEl = document.getElementById('student-routine-base-list');
    const cardioSummaryEl = document.getElementById('student-routine-cardio-summary');
    if (!nextWorkoutEl || !routineEl || !remindersEl || !student) return;

    const nextWorkout = resolveStudentNextWorkout(student);
    if (!nextWorkout) {
        nextWorkoutEl.innerHTML = `
            <div class="next-workout-name">Sem treino pendente</div>
            <div class="next-workout-meta">Você está em dia. Abra sua ficha para revisar o plano completo.</div>
        `;
    } else {
        const exercises = (Array.isArray(nextWorkout.block?.exercises) ? nextWorkout.block.exercises : []).slice(0, 5);
        nextWorkoutEl.innerHTML = `
            <div class="next-workout-name">${escHtml(nextWorkout.title)}</div>
            <div class="next-workout-meta">${nextWorkout.completedCycle ? 'Ciclo concluído - reinício sugerido' : 'Próximo da semana'} • ${formatRelativeDayLabel(getTodayDateKey())}</div>
            <ul class="next-workout-exercises">
                ${exercises.length > 0 ? exercises.map((ex) => `<li>${escHtml(ex?.name || ex?.nome || 'Exercício')}</li>`).join('') : '<li>Sem exercícios cadastrados</li>'}
            </ul>
        `;
    }

    const routine = normalizeRoutineShape(student.routine);
    const dueHabits = routine.habits.filter((habit) => isHabitDueToday(habit));
    const checkinsMap = getTodayCheckinsMap(routine);
    routineEl.innerHTML = dueHabits.length === 0
        ? '<div class="student-routine-empty" data-motion="list-item"><i class="ph-bold ph-calendar-check"></i><strong>Nenhum hábito para hoje</strong><span>Crie seu primeiro hábito para montar sua rotina.</span></div>'
        : dueHabits.map((habit) => {
            const done = checkinsMap.has(habit.id);
            const recurrenceLabel = getRoutineRecurrenceLabel(habit);
            const encodedHabitId = encodeURIComponent(String(habit.id || ''));
            const wasJustChecked = done
                && String(studentRoutineRecentCheckinHabitId || '') === String(habit.id || '')
                && (Date.now() - studentRoutineRecentCheckinAt) < 1400;
            return `
                <div class="student-routine-item ${done ? 'done is-success' : 'is-idle'} ${wasJustChecked ? 'is-just-checked' : ''}" data-motion="list-item">
                    <div class="student-routine-main">
                        <strong>${escHtml(habit.title)}</strong>
                        <span>${escHtml(habit.timeHHmm)} • ${escHtml(recurrenceLabel)}</span>
                    </div>
                    <div class="student-routine-actions">
                        <button type="button" class="routine-mini-btn" onclick="toggleHabitToday('${encodedHabitId}')" aria-label="Marcar hábito">${done ? '<i class="ph-bold ph-check-circle"></i>' : '<i class="ph-bold ph-circle"></i>'}</button>
                        <button type="button" class="routine-mini-btn" onclick="openRoutineHabitModal('${encodedHabitId}')" aria-label="Editar hábito"><i class="ph-bold ph-pencil-simple"></i></button>
                        <button type="button" class="routine-mini-btn" onclick="deleteHabit('${encodedHabitId}')" aria-label="Excluir hábito"><i class="ph-bold ph-trash"></i></button>
                    </div>
                </div>
            `;
        }).join('');

    const remindersToday = routine.reminders
        .filter((reminder) => isReminderDueToday(reminder))
        .sort((a, b) => String(a.timeHHmm).localeCompare(String(b.timeHHmm)));
    remindersEl.innerHTML = remindersToday.length === 0
        ? '<div class="student-routine-empty" data-motion="list-item"><i class="ph-bold ph-bell-slash"></i><strong>Sem lembretes hoje</strong><span>Adicione lembretes para não esquecer tarefas importantes.</span></div>'
        : remindersToday.map((reminder) => `
            <div class="student-reminder-item is-active" data-motion="list-item">
                <div class="student-reminder-main">
                    <strong>${escHtml(reminder.title)}</strong>
                    <span>${escHtml(reminder.timeHHmm)} • ${escHtml(getRoutineRecurrenceLabel(reminder))}</span>
                </div>
                <div class="student-reminder-actions">
                    <button type="button" class="routine-mini-btn" onclick="deleteReminder('${encodeURIComponent(String(reminder.id || ''))}')" aria-label="Excluir lembrete"><i class="ph-bold ph-trash"></i></button>
                </div>
            </div>
        `).join('');

    if (routineBaseEl) {
        const activeHabits = routine.habits.filter((habit) => habit?.active !== false);
        const activeReminders = routine.reminders.filter((reminder) => reminder?.active !== false);
        const completedToday = dueHabits.filter((habit) => checkinsMap.has(habit.id)).length;
        const pendingToday = Math.max(0, dueHabits.length - completedToday);
        const baseRows = [
            {
                icon: 'ph-check-square-offset',
                label: 'Hábitos ativos',
                value: String(activeHabits.length),
                hint: pendingToday > 0 ? `${pendingToday} pendente${pendingToday === 1 ? '' : 's'} hoje` : 'Tudo em dia'
            },
            {
                icon: 'ph-bell-simple-ringing',
                label: 'Lembretes',
                value: String(activeReminders.length),
                hint: remindersToday.length > 0 ? `${remindersToday.length} para hoje` : 'Nenhum hoje'
            },
            {
                icon: 'ph-seal-check',
                label: 'Concluídos hoje',
                value: `${completedToday}/${dueHabits.length}`,
                hint: dueHabits.length > 0 ? 'hábitos do dia' : 'sem agenda hoje'
            }
        ];
        routineBaseEl.innerHTML = (activeHabits.length || activeReminders.length)
            ? baseRows.map((row) => `
                <div class="student-routine-base-item">
                    <i class="ph-bold ${row.icon}"></i>
                    <div>
                        <span>${escHtml(row.label)}</span>
                        <strong>${escHtml(row.value)}</strong>
                    </div>
                    <small>${escHtml(row.hint)}</small>
                </div>
            `).join('')
            : '<div class="student-routine-empty compact"><i class="ph-bold ph-calendar-plus"></i><strong>Nenhuma atividade ainda</strong><span>Adicione hábitos e lembretes para começar.</span></div>';
    }

    if (cardioSummaryEl) {
        renderStudentRoutineCardioSummary(student, cardioSummaryEl);
    }
}

function renderStudentRoutineCardioSummary(student = {}, targetEl = null) {
    const cardEl = targetEl || document.getElementById('student-routine-cardio-summary');
    if (!cardEl) return;
    if (!student || !student.active) {
        cardEl.innerHTML = `
            <div class="student-routine-cardio-empty">
                <p>Seu treinador ainda está preparando o cardio desta fase.</p>
                <button type="button" class="home-v2-link-btn" onclick="switchStudentView('config')">Ver Meu Perfil</button>
            </div>
        `;
        return;
    }

    const plan = normalizeCardioPlanShape(student.cardioPlan);
    const weekly = calculateStudentCardioWeeklyTotals(student);
    const weeklyGoal = Math.max(30, parseIntegerSafe(plan.weeklyGoalMin) || 120);
    const weeklyDoneMin = weekly.totalMinRounded;
    const weeklyRemainingMin = Math.max(0, weeklyGoal - weeklyDoneMin);
    const weeklyPercent = Math.min(100, Math.max(0, Math.round((weeklyDoneMin / weeklyGoal) * 100)));
    const completionMap = getStudentCardioCompletionMap(student);
    const completedDays = (Array.isArray(plan.days) ? plan.days : []).filter((day) => completionMap.get(day.dayKey) === true).length;
    const todayKey = getWeekdayPlanKey(new Date());
    const todayPlan = (Array.isArray(plan.days) ? plan.days : []).find((entry) => entry.dayKey === todayKey) || plan.days?.[0] || {};

    cardEl.innerHTML = `
        <div class="student-routine-cardio-progress-head">
            <strong>${weeklyDoneMin} min feitos</strong>
            <span>${weeklyPercent}% da meta</span>
        </div>
        <div class="student-routine-cardio-track">
            <span style="width:${weeklyPercent}%"></span>
        </div>
        <div class="student-routine-cardio-grid">
            <div class="student-routine-cardio-kpi">
                <span>Meta semanal</span>
                <strong>${weeklyGoal} min</strong>
            </div>
            <div class="student-routine-cardio-kpi">
                <span>Faltam</span>
                <strong>${weeklyRemainingMin} min</strong>
            </div>
            <div class="student-routine-cardio-kpi">
                <span>Dias marcados</span>
                <strong>${completedDays}</strong>
            </div>
        </div>
        <p class="student-routine-cardio-note">
            Hoje: ${escHtml(todayPlan.dayLabel || 'Dia')} · ${escHtml(todayPlan.type || 'Cardio livre')} · ${escHtml(todayPlan.durationMin || '--')} min
        </p>
    `;
}

function renderStudentChatPlaceholderLegacy() {
    const container = document.getElementById('student-chat-content-main');
    if (!container) return;
    const { student } = getStudentData();
    const firstName = escHtml(String(student?.name || memoryGetItem('studentName') || 'Aluno').trim().split(/\s+/)[0] || 'Aluno');
    container.innerHTML = `
        <section class="student-chat-placeholder" data-motion="surface">
            <div class="student-chat-placeholder-icon">
                <i class="ph-bold ph-chat-circle-dots"></i>
            </div>
            <h3>Em breve</h3>
            <p>${firstName}, estamos preparando o chat para você conversar direto com seu treinador.</p>
            <button type="button" class="btn-secondary" disabled aria-disabled="true">Iniciar conversa</button>
        </section>
    `;
}

function persistRoutineMutation(mutator) {
    const selected = getCurrentStudentSelection();
    if (!selected.student || selected.idx < 0) return { ok: false };
    mutator(selected.student);
    selected.student._localPlanUpdatedAt = new Date().toISOString();
    selected.students[selected.idx] = normalizeStudentDietSchema(selected.student);
    saveStudentData(selected.students, { syncMode: 'batched', syncDelayMs: 1000, studentId: String(selected.student.id || '') });
    renderStudentHomeMain(selected.students[selected.idx]);
    ensureRoutineReminderEngine();
    return { ok: true };
}

function openRoutineHabitModal(habitId = '') {
    const modal = document.getElementById('routine-habit-modal');
    if (!modal) return;
    ensureRoutineModalDashboardRoot(modal);
    if (modal.__hideTimer) {
        clearTimeout(modal.__hideTimer);
        modal.__hideTimer = null;
    }
    routineHabitEditId = decodeRoutineToken(habitId);
    const titleEl = document.getElementById('routine-habit-modal-title');
    const inputTitle = document.getElementById('routine-habit-title');
    const inputTime = document.getElementById('routine-habit-time');
    const inputRecurrence = document.getElementById('routine-habit-recurrence');
    const selected = getCurrentStudentSelection();
    const habit = selected.student?.routine?.habits?.find((h) => String(h.id) === routineHabitEditId);
    if (habit) {
        if (titleEl) titleEl.innerText = 'Editar hábito';
        if (inputTitle) inputTitle.value = habit.title || '';
        if (inputTime) inputTime.value = normalizeTimeHHmm(habit.timeHHmm || '08:00');
        if (inputRecurrence) inputRecurrence.value = habit.recurrenceType || 'daily';
    } else {
        if (titleEl) titleEl.innerText = 'Novo hábito';
        if (inputTitle) inputTitle.value = '';
        if (inputTime) inputTime.value = '08:00';
        if (inputRecurrence) inputRecurrence.value = 'daily';
    }
    handleRoutineRecurrenceUI(habit?.weekdays || []);
    modal.style.display = 'flex';
    requestAnimationFrame(() => modal.classList.add('active'));
    setTimeout(() => inputTitle?.focus(), 60);
}

function applyRoutineHabitPreset(presetKey = '') {
    const preset = ROUTINE_HABIT_PRESETS[String(presetKey || '').trim()] || null;
    if (!preset) return;
    const inputTitle = document.getElementById('routine-habit-title');
    const inputTime = document.getElementById('routine-habit-time');
    const inputRecurrence = document.getElementById('routine-habit-recurrence');
    if (inputTitle) inputTitle.value = preset.title || '';
    if (inputTime) inputTime.value = normalizeTimeHHmm(preset.timeHHmm || '08:00');
    if (inputRecurrence) inputRecurrence.value = preset.recurrenceType === 'weekdays' ? 'weekdays' : 'daily';
    handleRoutineRecurrenceUI(Array.isArray(preset.weekdays) ? preset.weekdays : []);
}

function handleRoutineRecurrenceUI(preselected = []) {
    const wrap = document.getElementById('routine-weekdays-wrap');
    const recurrence = document.getElementById('routine-habit-recurrence')?.value || 'daily';
    if (!wrap) return;
    wrap.style.display = recurrence === 'weekdays' ? 'block' : 'none';
    const checks = wrap.querySelectorAll('input[type="checkbox"]');
    checks.forEach((check) => {
        check.checked = Array.isArray(preselected) ? preselected.includes(String(check.value || '')) : false;
    });
}

function closeRoutineHabitModal() {
    const modal = document.getElementById('routine-habit-modal');
    if (modal) {
        modal.classList.remove('active');
        if (modal.__hideTimer) clearTimeout(modal.__hideTimer);
        modal.__hideTimer = setTimeout(() => {
            modal.style.display = 'none';
            modal.__hideTimer = null;
        }, 180);
    }
    routineHabitEditId = null;
}

function handleRoutineModalOverlayClick(modalId = '', event = null) {
    const safeId = String(modalId || '').trim();
    if (!safeId || !event || event.target?.id !== safeId) return;
    if (safeId === 'routine-habit-modal') {
        closeRoutineHabitModal();
        return;
    }
    if (safeId === 'routine-reminder-modal') {
        closeRoutineReminderModal();
    }
}

function submitRoutineHabitModal() {
    const title = sanitizeUserInput(document.getElementById('routine-habit-title')?.value || '', { maxLen: 80 });
    const timeHHmm = normalizeTimeHHmm(document.getElementById('routine-habit-time')?.value || '08:00');
    const recurrenceType = String(document.getElementById('routine-habit-recurrence')?.value || 'daily') === 'weekdays' ? 'weekdays' : 'daily';
    const weekdays = recurrenceType === 'weekdays'
        ? Array.from(document.querySelectorAll('#routine-weekdays-wrap input[type="checkbox"]:checked')).map((el) => String(el.value || '')).filter((d) => ROUTINE_WEEKDAY_KEYS.includes(d))
        : [];
    if (!title) {
        showStudentHomeMessage('Informe um título para o hábito.', 'error');
        return;
    }
    if (recurrenceType === 'weekdays' && weekdays.length === 0) {
        showStudentHomeMessage('Selecione pelo menos um dia da semana.', 'error');
        return;
    }
    const op = persistRoutineMutation((student) => {
        student.routine = normalizeRoutineShape(student.routine);
        const habits = Array.isArray(student.routine.habits) ? student.routine.habits : [];
        const nowIso = new Date().toISOString();
        const payload = {
            id: routineHabitEditId || `habit-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
            title,
            timeHHmm,
            recurrenceType,
            weekdays,
            active: true,
            createdAt: nowIso,
            createdBy: 'student'
        };
        const idx = habits.findIndex((habit) => String(habit.id) === String(routineHabitEditId || ''));
        if (idx >= 0) habits[idx] = { ...habits[idx], ...payload, createdAt: habits[idx].createdAt || nowIso };
        else habits.push(payload);
        student.routine.habits = habits;
    });
    if (!op.ok) return;
    closeRoutineHabitModal();
    showStudentHomeMessage('Hábito salvo.', 'success');
}

function toggleHabitToday(habitId = '') {
    const cleanHabitId = decodeRoutineToken(habitId);
    if (!cleanHabitId) return;
    persistRoutineMutation((student) => {
        student.routine = normalizeRoutineShape(student.routine);
        const today = getTodayDateKey();
        const list = Array.isArray(student.routine.checkinsByDate[today]) ? student.routine.checkinsByDate[today].slice() : [];
        const idx = list.findIndex((item) => String(item.habitId || '') === cleanHabitId);
        if (idx >= 0) {
            list.splice(idx, 1);
            if (String(studentRoutineRecentCheckinHabitId || '') === cleanHabitId) {
                studentRoutineRecentCheckinHabitId = '';
                studentRoutineRecentCheckinAt = 0;
            }
        } else {
            list.push({ habitId: cleanHabitId, doneAt: new Date().toISOString() });
            studentRoutineRecentCheckinHabitId = cleanHabitId;
            studentRoutineRecentCheckinAt = Date.now();
        }
        student.routine.checkinsByDate[today] = list;
    });
}

function updateHabit(habitId, patch = {}) {
    const cleanHabitId = decodeRoutineToken(habitId);
    if (!cleanHabitId) return;
    persistRoutineMutation((student) => {
        student.routine = normalizeRoutineShape(student.routine);
        student.routine.habits = student.routine.habits.map((habit) => String(habit.id) === cleanHabitId ? { ...habit, ...patch } : habit);
    });
}

function deleteHabit(habitId = '') {
    const cleanHabitId = decodeRoutineToken(habitId);
    if (!cleanHabitId) return;
    persistRoutineMutation((student) => {
        student.routine = normalizeRoutineShape(student.routine);
        student.routine.habits = student.routine.habits.filter((habit) => String(habit.id) !== cleanHabitId);
        Object.keys(student.routine.checkinsByDate || {}).forEach((dateKey) => {
            student.routine.checkinsByDate[dateKey] = (student.routine.checkinsByDate[dateKey] || []).filter((entry) => String(entry.habitId) !== cleanHabitId);
        });
    });
}

function openRoutineReminderModal() {
    const modal = document.getElementById('routine-reminder-modal');
    if (!modal) return;
    ensureRoutineModalDashboardRoot(modal);
    if (modal.__hideTimer) {
        clearTimeout(modal.__hideTimer);
        modal.__hideTimer = null;
    }
    const title = document.getElementById('routine-reminder-title');
    const time = document.getElementById('routine-reminder-time');
    const recurrence = document.getElementById('routine-reminder-recurrence');
    if (title) title.value = '';
    if (time) time.value = '08:00';
    if (recurrence) recurrence.value = 'daily';
    handleRoutineReminderRecurrenceUI([]);
    modal.style.display = 'flex';
    requestAnimationFrame(() => modal.classList.add('active'));
    setTimeout(() => title?.focus(), 60);
}

function closeRoutineReminderModal() {
    const modal = document.getElementById('routine-reminder-modal');
    if (modal) {
        modal.classList.remove('active');
        if (modal.__hideTimer) clearTimeout(modal.__hideTimer);
        modal.__hideTimer = setTimeout(() => {
            modal.style.display = 'none';
            modal.__hideTimer = null;
        }, 180);
    }
}

function submitRoutineReminderModal() {
    const title = sanitizeUserInput(document.getElementById('routine-reminder-title')?.value || '', { maxLen: 80 });
    const timeHHmm = normalizeTimeHHmm(document.getElementById('routine-reminder-time')?.value || '08:00');
    const recurrenceType = normalizeRoutineRecurrenceType(document.getElementById('routine-reminder-recurrence')?.value || 'daily');
    const weekdays = recurrenceType === 'weekdays'
        ? Array.from(document.querySelectorAll('#routine-reminder-weekdays-wrap input[type="checkbox"]:checked'))
            .map((el) => String(el.value || ''))
            .filter((d) => ROUTINE_WEEKDAY_KEYS.includes(d))
        : [];
    if (!title) {
        showStudentHomeMessage('Informe um título para o lembrete.', 'error');
        return;
    }
    if (recurrenceType === 'weekdays' && weekdays.length === 0) {
        showStudentHomeMessage('Selecione pelo menos um dia da semana.', 'error');
        return;
    }
    createReminder({ title, timeHHmm, recurrenceType, weekdays, createdBy: 'student' });
    closeRoutineReminderModal();
    showStudentHomeMessage('Lembrete salvo.', 'success');
}

function handleRoutineReminderRecurrenceUI(preselected = []) {
    const wrap = document.getElementById('routine-reminder-weekdays-wrap');
    const recurrence = normalizeRoutineRecurrenceType(document.getElementById('routine-reminder-recurrence')?.value || 'daily');
    if (!wrap) return;
    wrap.style.display = recurrence === 'weekdays' ? 'block' : 'none';
    const checks = wrap.querySelectorAll('input[type="checkbox"]');
    checks.forEach((check) => {
        check.checked = Array.isArray(preselected) ? preselected.includes(String(check.value || '')) : false;
    });
}

function createReminder({ title = '', timeHHmm = '08:00', recurrenceType = 'daily', weekdays = [], createdBy = 'student' } = {}) {
    const cleanTitle = sanitizeUserInput(title || '', { maxLen: 80 });
    if (!cleanTitle) return;
    persistRoutineMutation((student) => {
        student.routine = normalizeRoutineShape(student.routine);
        const reminders = Array.isArray(student.routine.reminders) ? student.routine.reminders : [];
        const safeRecurrence = normalizeRoutineRecurrenceType(recurrenceType);
        reminders.push({
            id: `rem-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
            title: cleanTitle,
            timeHHmm: normalizeTimeHHmm(timeHHmm),
            recurrenceType: safeRecurrence,
            weekdays: normalizeRoutineWeekdays(weekdays, safeRecurrence),
            active: true,
            createdAt: new Date().toISOString(),
            createdBy: normalizeRoutineCreatedBy(createdBy),
            dateKey: '',
            legacyDateOnly: false
        });
        student.routine.reminders = reminders.slice(-240);
    });
}

function deleteReminder(reminderId = '') {
    const cleanReminderId = decodeRoutineToken(reminderId);
    if (!cleanReminderId) return;
    persistRoutineMutation((student) => {
        student.routine = normalizeRoutineShape(student.routine);
        student.routine.reminders = (student.routine.reminders || []).filter((reminder) => String(reminder.id) !== cleanReminderId);
    });
}

function showStudentHomeMessage(message, type = 'success') {
    if (typeof showDietRuntimeMessage === 'function') {
        showDietRuntimeMessage(message, type === 'error' ? 'error' : 'success');
        return;
    }
    if (type === 'error') {
        alert(message);
    }
}

function ensureRoutineReminderEngine() {
    if (routineReminderTicker) return;
    routineReminderTicker = setInterval(runRoutineReminderTick, 30 * 1000);
    runRoutineReminderTick();
}

function runRoutineReminderTick() {
    const selected = getCurrentStudentSelection();
    if (!selected.student) return;
    const routine = normalizeRoutineShape(selected.student.routine);
    const now = new Date();
    const nowKey = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
    const today = getTodayDateKey();
    const dueItems = [];
    routine.habits.forEach((habit) => {
        if (!isHabitDueToday(habit, now) || habit.timeHHmm !== nowKey) return;
        dueItems.push({ id: `habit-${habit.id}`, title: habit.title, kind: 'Hábito' });
    });
    routine.reminders.forEach((reminder) => {
        if (!isReminderDueToday(reminder, now) || reminder.timeHHmm !== nowKey) return;
        dueItems.push({ id: `rem-${reminder.id}`, title: reminder.title, kind: 'Lembrete' });
    });
    dueItems.forEach((item) => {
        const key = `${today}-${item.id}-${nowKey}`;
        if (routineReminderNotifiedKeys.has(key)) return;
        routineReminderNotifiedKeys.add(key);
        if (routineReminderNotifiedKeys.size > 800) {
            const oldestKey = routineReminderNotifiedKeys.values().next().value;
            if (oldestKey) routineReminderNotifiedKeys.delete(oldestKey);
        }
        showStudentHomeMessage(`${item.kind}: ${item.title}`, 'success');
        if (typeof window !== 'undefined' && 'Notification' in window) {
            if (window.Notification.permission === 'granted') {
                new Notification('Consultoria - rotina', { body: `${item.kind}: ${item.title}` });
            } else if (window.Notification.permission === 'default') {
                window.Notification.requestPermission().catch(() => { });
            }
        }
    });
}

async function syncStudentAvatarFromProfile(student) {
    if (!student || !isSupabaseReady()) return;
    const source = getStudentAvatarSource(student);
    renderStudentAvatarElement(student, '');
    if (!source) return;
    const resolved = await resolveStorageRefUrl(source, 3600);
    renderStudentAvatarElement(student, resolved);
}

function triggerStudentAvatarUpload() {
    const input = document.getElementById('perfil-avatar-input');
    if (!input) return;
    input.click();
}

function triggerStudentGalleryUpload() {
    const input = document.getElementById('perfil-media-input');
    if (!input) return;
    input.click();
}

function getStudentConnectTutorialStorageKey() {
    const userId = String(memoryGetItem('currentUserId') || memoryGetItem('currentStudentId') || 'anon').trim() || 'anon';
    return `${STUDENT_CONNECT_TUTORIAL_KEY}:${userId}`;
}

function resolveStudentConsultoriaStatus(student = {}) {
    const connectedCode = sanitizeCodeInput(
        student?.trainerCode || student?.trainer_code || memoryGetItem('connectedTrainerCode') || '',
        5
    );
    if (!connectedCode) return { status: 'desconectado', trainerCode: '' };
    if (student?.active) return { status: 'aprovado', trainerCode: connectedCode };
    return { status: 'pendente', trainerCode: connectedCode };
}

function getTrainerDisplayNameByCode(trainerCode = '') {
    const safeCode = sanitizeCodeInput(trainerCode, 5);
    if (!safeCode) return '';
    const allTrainers = readStorageJSON('allTrainers', []);
    const found = (Array.isArray(allTrainers) ? allTrainers : []).find((trainer) => String(trainer?.code || '') === safeCode);
    if (!found) return '';
    return sanitizeUserInput(found?.displayName || found?.name || '', { maxLen: 90 });
}

function getStudentTrainerPaymentSettings(student = {}) {
    const studentSettings = normalizeTrainerPaymentSettings(student?.trainerPaymentSettings || student?.trainer_payment_settings || {});
    if (hasTrainerPaymentSettingsConfigured(studentSettings)) return studentSettings;
    const state = resolveStudentConsultoriaStatus(student);
    const safeCode = sanitizeCodeInput(state.trainerCode, 5);
    if (!safeCode) return studentSettings;
    const allTrainers = readStorageJSON('allTrainers', []);
    const trainer = (Array.isArray(allTrainers) ? allTrainers : []).find((entry) => String(entry?.code || '') === safeCode);
    if (!trainer) return studentSettings;
    return normalizeTrainerPaymentSettings(
        trainer?.paymentSettings
        || extractTrainerPaymentSettingsFromSocialLinks(trainer?.socialLinks || trainer?.social_links || {})
    );
}

function parseStudentMoneyAmount(value = '') {
    const parsed = parseFloat(String(value || '').replace(',', '.'));
    if (!Number.isFinite(parsed) || parsed <= 0) return 0;
    return parsed;
}

function formatStudentCurrencyBRL(value = '') {
    const amount = parseStudentMoneyAmount(value);
    if (!amount) return 'Não definido';
    return amount.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function formatStudentCompetenceLabel(competence = '') {
    const safe = String(competence || '').trim();
    const match = safe.match(/^(\d{4})-(\d{2})$/);
    if (!match) return '--';
    return `${match[2]}/${match[1]}`;
}

function parseStudentDateValue(value = '') {
    const raw = String(value || '').trim();
    if (!raw) return null;
    const direct = new Date(raw);
    if (Number.isFinite(direct.getTime())) return direct;
    const yyyyMmDd = raw.slice(0, 10);
    return parseISODateSafe(yyyyMmDd);
}

function formatStudentDateLabel(value = '') {
    const parsed = parseStudentDateValue(value);
    return parsed ? formatPtDate(parsed) : '--';
}

function resolveStudentMonthlyAmount(student = {}, paymentSettings = {}) {
    const billing = getStudentBillingData(student);
    const fromBilling = sanitizePixAmountText(billing.billingMonthlyAmount || '');
    if (fromBilling) return fromBilling;
    const fromPix = sanitizePixAmountText(paymentSettings?.monthlyAmountDefault || '');
    if (fromPix) return fromPix;
    return '';
}

function resolveStudentCurrentBillingCompetence(snapshot = null) {
    const safeSnapshot = snapshot || {};
    if (safeSnapshot?.startDate && safeSnapshot?.monthIndex > 0) {
        const competenceDate = new Date(safeSnapshot.startDate);
        competenceDate.setMonth(competenceDate.getMonth() + (safeSnapshot.monthIndex - 1));
        return formatCompetence(competenceDate);
    }
    return formatCompetence(new Date());
}

function hasStudentPixPaymentConfigured(paymentSettings = {}) {
    const normalized = normalizeTrainerPaymentSettings(paymentSettings);
    return !!(normalized.pixCopyPaste || normalized.pixQrImage);
}

function resolveStudentLatestPaymentRequest(student = {}) {
    const requests = normalizeStudentPaymentRequests(student?.paymentRequests || student?.payment_requests || []);
    if (!Array.isArray(requests) || requests.length === 0) return null;
    return requests[0];
}

function getPaymentRequestStatusLabel(status = '') {
    if (status === 'aprovado') return 'Aprovado';
    if (status === 'recusado') return 'Recusado';
    return 'Aguardando confirmação';
}

function resolveStudentLastPaymentInfo(student = {}) {
    const billing = getStudentBillingData(student);
    const history = (Array.isArray(billing.billingHistory) ? billing.billingHistory : [])
        .map(normalizeBillingHistoryItem)
        .filter((entry) => entry?.status === 'pago');
    if (history.length > 0) {
        const sorted = [...history].sort((a, b) => {
            const aMs = parseStudentDateValue(a?.paidAt || a?.updatedAt || '')?.getTime() || 0;
            const bMs = parseStudentDateValue(b?.paidAt || b?.updatedAt || '')?.getTime() || 0;
            if (aMs !== bMs) return bMs - aMs;
            return String(b?.competence || '').localeCompare(String(a?.competence || ''));
        });
        const latest = sorted[0] || {};
        const paidLabel = formatStudentDateLabel(latest?.paidAt || latest?.updatedAt || '');
        return {
            label: `${formatStudentCompetenceLabel(latest?.competence || '')} • ${paidLabel}`,
            date: paidLabel
        };
    }
    if (billing.billingCurrentPaidAt) {
        const fallbackDate = formatStudentDateLabel(billing.billingCurrentPaidAt);
        return {
            label: fallbackDate !== '--' ? fallbackDate : 'Sem pagamento confirmado',
            date: fallbackDate
        };
    }
    return { label: 'Sem pagamento confirmado', date: '--' };
}

function renderStudentConsultoriaCard(student = {}) {
    const container = document.getElementById('student-consultoria-card');
    if (!container) return;
    const state = resolveStudentConsultoriaStatus(student);
    const trainerName = getTrainerDisplayNameByCode(state.trainerCode);
    const trainerLabel = trainerName || 'Seu treinador';
    const paymentSettings = getStudentTrainerPaymentSettings(student);
    const canRequestPixPayment = hasStudentPixPaymentConfigured(paymentSettings);
    const billingSnapshot = getStudentBillingSnapshot(student);
    const monthlyAmount = resolveStudentMonthlyAmount(student, paymentSettings);
    const lastPayment = resolveStudentLastPaymentInfo(student);
    const latestRequest = resolveStudentLatestPaymentRequest(student);
    const latestRequestLabel = latestRequest
        ? `${getPaymentRequestStatusLabel(latestRequest.status)} em ${formatStudentDateLabel(latestRequest.requestedAt)}`
        : 'Sem solicitações recentes';

    if (state.status === 'desconectado') {
        container.innerHTML = `
            <div class="settings-card-header">
                <h2>Minha consultoria</h2>
                <p class="subtitle">Conecte seu código para liberar treino, dieta, cardio e água.</p>
            </div>
            <div class="student-consultoria-actions">
                <button class="btn-primary" type="button" onclick="openStudentConnectFromDashboard()">
                    <i class="ph-bold ph-link"></i> Conectar com treinador
                </button>
            </div>
        `;
        return;
    }
    container.innerHTML = `
        <div class="settings-card-header">
            <h2>Minha consultoria</h2>
            <p class="subtitle">Consultoria de ${escHtml(trainerLabel)} • Código ${escHtml(state.trainerCode)}</p>
        </div>
        <div class="student-consultoria-status ${state.status === 'aprovado' ? 'is-approved' : 'is-pending'}">
            <i class="ph-bold ${state.status === 'aprovado' ? 'ph-check-circle' : 'ph-hourglass-high'}"></i>
            <span>${state.status === 'aprovado' ? 'Conectado e aprovado pelo treinador' : 'Solicitação enviada, aguardando aprovação'}</span>
        </div>
        <div class="student-consultoria-financial">
            <div class="student-consultoria-financial-item">
                <span>Status atual do ciclo</span>
                <strong class="status-${billingSnapshot.status}">${escHtml(`${billingSnapshot.statusLabel} • ${billingSnapshot.monthLabel}`)}</strong>
            </div>
            <div class="student-consultoria-financial-item">
                <span>Valor mensal</span>
                <strong>${escHtml(formatStudentCurrencyBRL(monthlyAmount))}</strong>
            </div>
            <div class="student-consultoria-financial-item">
                <span>Último pagamento</span>
                <strong>${escHtml(lastPayment.label)}</strong>
            </div>
        </div>
        <div class="student-consultoria-financial-meta">
            <span>Próximo vencimento: ${escHtml(billingSnapshot.nextDueLabel || '-')}</span>
            <span>Última solicitação: ${escHtml(latestRequestLabel)}</span>
        </div>
        ${!canRequestPixPayment ? `
            <div class="student-consultoria-inline-hint">
                <i class="ph-bold ph-warning-circle"></i>
                <span>O PIX ainda não foi configurado pelo treinador.</span>
            </div>
        ` : ''}
        <div class="student-consultoria-actions">
            <button class="btn-primary" type="button" onclick="openStudentPaymentModal()" ${canRequestPixPayment ? '' : 'disabled'}>
                <i class="ph-bold ph-currency-circle-dollar"></i> Pagar agora
            </button>
            <button class="btn-secondary btn-perfil-logout" type="button" onclick="disconnectStudentConsultoria()">
                <i class="ph-bold ph-sign-out"></i> Sair da consultoria
            </button>
        </div>
    `;
}

async function hydrateStudentPaymentSettingsFromTrainer(student = {}, students = [], studentIdx = -1) {
    let paymentSettings = getStudentTrainerPaymentSettings(student);
    if (hasStudentPixPaymentConfigured(paymentSettings)) return paymentSettings;
    const state = resolveStudentConsultoriaStatus(student);
    if (!state.trainerCode) return paymentSettings;
    const trainer = await resolveTrainerByCode(state.trainerCode);
    if (!trainer) return paymentSettings;
    paymentSettings = normalizeTrainerPaymentSettings(
        trainer.paymentSettings
        || extractTrainerPaymentSettingsFromSocialLinks(trainer.socialLinks || trainer.social_links || {})
    );
    if (hasTrainerPaymentSettingsConfigured(paymentSettings) && Array.isArray(students) && studentIdx >= 0) {
        students[studentIdx] = {
            ...students[studentIdx],
            trainerPaymentSettings: paymentSettings
        };
        saveStudentData(students, {
            studentId: String(students[studentIdx]?.id || ''),
            syncMode: 'batched',
            syncDelayMs: 1400
        });
    }
    return paymentSettings;
}

async function openStudentPaymentModal() {
    const modal = document.getElementById('student-payment-modal');
    const summaryEl = document.getElementById('student-payment-modal-summary');
    const unavailableEl = document.getElementById('student-payment-pix-unavailable');
    const contentEl = document.getElementById('student-payment-pix-content');
    const qrEl = document.getElementById('student-payment-pix-qr');
    const copyInput = document.getElementById('student-payment-pix-copy');
    const copyBtn = document.getElementById('student-payment-copy-btn');
    const confirmBtn = document.getElementById('student-payment-confirm-btn');
    const instructionsEl = document.getElementById('student-payment-pix-instructions');
    if (!modal || !summaryEl || !unavailableEl || !contentEl || !qrEl || !copyInput || !copyBtn || !confirmBtn || !instructionsEl) return;

    const { studentId, students, student } = getStudentData();
    if (!studentId || !student) return;
    const state = resolveStudentConsultoriaStatus(student);
    if (state.status === 'desconectado') {
        showDietRuntimeMessage('Conecte-se a uma consultoria para pagar via PIX.', 'info');
        return;
    }

    const idx = students.findIndex((entry) => String(entry?.id || '') === String(studentId));
    const paymentSettings = await hydrateStudentPaymentSettingsFromTrainer(student, students, idx);
    const billingSnapshot = getStudentBillingSnapshot(student);
    const monthlyAmount = resolveStudentMonthlyAmount(student, paymentSettings);
    const competence = resolveStudentCurrentBillingCompetence(billingSnapshot);
    const lastPayment = resolveStudentLastPaymentInfo(student);
    const canRequest = hasStudentPixPaymentConfigured(paymentSettings);
    const copyPastePix = sanitizeUserInput(paymentSettings.pixCopyPaste || '', { allowNewlines: true, maxLen: 4000 });
    const instructions = sanitizeUserInput(paymentSettings.instructions || '', { allowNewlines: true, maxLen: 320 });

    activeStudentPaymentModalState = {
        studentId: String(student.id || studentId || ''),
        trainerCode: state.trainerCode,
        competence,
        amount: monthlyAmount,
        paymentSettings
    };

    summaryEl.innerHTML = `
        <div class="student-payment-summary-grid">
            <div class="student-payment-summary-item">
                <span>Consultoria</span>
                <strong>${escHtml(getTrainerDisplayNameByCode(state.trainerCode) || 'Seu treinador')}</strong>
            </div>
            <div class="student-payment-summary-item">
                <span>Ciclo</span>
                <strong>${escHtml(`${billingSnapshot.monthLabel} • ${billingSnapshot.statusLabel}`)}</strong>
            </div>
            <div class="student-payment-summary-item">
                <span>Competência</span>
                <strong>${escHtml(formatStudentCompetenceLabel(competence))}</strong>
            </div>
            <div class="student-payment-summary-item">
                <span>Valor mensal</span>
                <strong>${escHtml(formatStudentCurrencyBRL(monthlyAmount))}</strong>
            </div>
            <div class="student-payment-summary-item">
                <span>Último pagamento</span>
                <strong>${escHtml(lastPayment.label)}</strong>
            </div>
        </div>
    `;

    unavailableEl.style.display = canRequest ? 'none' : 'flex';
    contentEl.style.display = canRequest ? 'grid' : 'none';
    confirmBtn.disabled = !canRequest;

    copyInput.value = copyPastePix;
    copyBtn.disabled = !copyPastePix;
    copyBtn.innerHTML = '<i class="ph-bold ph-copy"></i> Copiar PIX';

    instructionsEl.innerHTML = instructions
        ? instructions.split('\n').map((line) => escHtml(line)).join('<br>')
        : '<span>Faça o pagamento e clique em "Já paguei" para solicitar confirmação ao treinador.</span>';

    const qrRaw = sanitizeImageDataUrl(paymentSettings.pixQrImage, { maxLen: 3_200_000 })
        || sanitizeStrictUrl(paymentSettings.pixQrImage, { maxLen: 5_000, allowStorage: true });
    let qrUrl = qrRaw;
    if (qrUrl && qrUrl.startsWith('storage://')) {
        qrUrl = await resolveStorageRefUrl(qrUrl, 3600);
    }
    if (qrUrl) {
        qrEl.innerHTML = `<img src="${escHtml(qrUrl)}" alt="QR Code PIX" loading="lazy" decoding="async">`;
    } else {
        qrEl.innerHTML = `
            <div class="student-payment-pix-qr-empty">
                <i class="ph-bold ph-qr-code"></i>
                <span>QR Code não informado</span>
            </div>
        `;
    }

    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('active'), 10);
}

function closeStudentPaymentModal() {
    const modal = document.getElementById('student-payment-modal');
    if (!modal) return;
    modal.classList.remove('active');
    setTimeout(() => {
        modal.style.display = 'none';
    }, 220);
    activeStudentPaymentModalState = null;
}

function copyStudentPaymentPix() {
    const input = document.getElementById('student-payment-pix-copy');
    const btn = document.getElementById('student-payment-copy-btn');
    if (!input || !btn) return;
    const pixText = String(input.value || '').trim();
    if (!pixText) {
        showDietRuntimeMessage('Nenhuma chave PIX disponível para copiar.', 'info');
        return;
    }

    const applyFeedback = () => {
        btn.innerHTML = '<i class="ph-bold ph-check"></i> Copiado';
        setTimeout(() => {
            btn.innerHTML = '<i class="ph-bold ph-copy"></i> Copiar PIX';
        }, 1400);
    };
    const fallbackCopy = () => {
        input.focus();
        input.select();
        const copied = document.execCommand('copy');
        if (copied) {
            applyFeedback();
            showDietRuntimeMessage('PIX copiado com sucesso.', 'success');
        } else {
            showDietRuntimeMessage('Não foi possível copiar automaticamente.', 'error');
        }
    };

    if (navigator.clipboard?.writeText) {
        navigator.clipboard.writeText(pixText)
            .then(() => {
                applyFeedback();
                showDietRuntimeMessage('PIX copiado com sucesso.', 'success');
            })
            .catch(fallbackCopy);
    } else {
        fallbackCopy();
    }
}

async function submitStudentPaymentRequest() {
    const draft = activeStudentPaymentModalState;
    const { studentId, students, student } = getStudentData();
    if (!studentId || !student || !draft) return;

    const idx = students.findIndex((entry) => String(entry?.id || '') === String(studentId));
    if (idx < 0) return;

    const paymentSettings = normalizeTrainerPaymentSettings(draft.paymentSettings || {});
    if (!hasStudentPixPaymentConfigured(paymentSettings)) {
        showDietRuntimeMessage('O treinador ainda não configurou o PIX para pagamento.', 'info');
        return;
    }

    const competence = sanitizeUserInput(draft.competence || resolveStudentCurrentBillingCompetence(getStudentBillingSnapshot(student)), { maxLen: 7 });
    const amount = sanitizePixAmountText(draft.amount || resolveStudentMonthlyAmount(student, paymentSettings));
    const currentRequests = normalizeStudentPaymentRequests(student.paymentRequests || student.payment_requests || []);
    const hasPendingForCompetence = currentRequests.some((request) =>
        request?.competence === competence && request?.status === 'aguardando_confirmacao'
    );
    if (hasPendingForCompetence) {
        showDietRuntimeMessage('Já existe uma solicitação pendente para este ciclo.', 'info');
        closeStudentPaymentModal();
        renderStudentPerfil();
        return;
    }

    const newRequest = normalizeStudentPaymentRequest({
        id: `pay-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        competence,
        amount,
        status: 'aguardando_confirmacao',
        requestedAt: new Date().toISOString(),
        pixSnapshot: paymentSettings
    });
    activeStudentPaymentRequestId = newRequest.id;

    const nextRequests = normalizeStudentPaymentRequests([newRequest, ...currentRequests]);
    students[idx] = {
        ...students[idx],
        paymentRequests: nextRequests,
        payment_requests: nextRequests,
        trainerPaymentSettings: paymentSettings
    };
    saveStudentData(students, { studentId: String(students[idx]?.id || studentId || '') });
    void syncStudentProfileEntity(students[idx]);

    closeStudentPaymentModal();
    renderStudentPerfil();
    switchStudentConfigSection('consultoria');
    showDietRuntimeMessage('Solicitação enviada. Aguarde a confirmação do treinador.', 'success');
}

function showStudentConnectTutorialModal() {
    const modal = document.getElementById('student-connect-tutorial-modal');
    if (!modal) return;
    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('active'), 10);
}

function closeStudentConnectTutorialModal() {
    const modal = document.getElementById('student-connect-tutorial-modal');
    if (!modal) return;
    modal.classList.remove('active');
    setTimeout(() => {
        modal.style.display = 'none';
    }, 180);
    studentConnectTutorialShownInSession = true;
    memorySetItem(getStudentConnectTutorialStorageKey(), '1');
}

function startStudentConnectFromTutorial() {
    closeStudentConnectTutorialModal();
    openStudentConnectFromDashboard();
}

function maybeShowStudentConnectTutorial(student = {}) {
    const state = resolveStudentConsultoriaStatus(student);
    if (state.status !== 'desconectado') return;
    if (studentConnectTutorialShownInSession) return;
    const seen = memoryGetItem(getStudentConnectTutorialStorageKey()) === '1';
    if (seen) return;
    showStudentConnectTutorialModal();
    studentConnectTutorialShownInSession = true;
}

async function disconnectStudentConsultoria() {
    const { studentId, students, student } = getStudentData();
    if (!studentId || !student) return;
    const state = resolveStudentConsultoriaStatus(student);
    if (state.status === 'desconectado') return;
    const shouldDisconnect = confirm('Você quer mesmo sair dessa consultoria? Essa ação remove sua conexão com o treinador atual.');
    if (!shouldDisconnect) return;

    const idx = students.findIndex((entry) => String(entry?.id || '') === String(studentId));
    if (idx < 0) return;
    const oldTrainerCode = state.trainerCode;
    const userId = String(student?.userId || memoryGetItem('currentUserId') || '').trim();
    students[idx] = {
        ...students[idx],
        trainerCode: '',
        trainer_code: '',
        pending: false,
        active: false
    };
    saveStudentData(students, { studentId: String(student.id || studentId || '') });
    memoryRemoveItem('connectedTrainerCode');
    memoryRemoveItem('currentTrainerCode');
    memoryRemoveItem(getStudentConnectTutorialStorageKey());
    studentConnectTutorialShownInSession = false;
    closeStudentPaymentModal();

    if (userId && oldTrainerCode) {
        await syncStudentConnectionEntity(userId, oldTrainerCode, 'rejected');
    }
    const activeUser = await getSupabaseSessionUser();
    if (activeUser) {
        await upsertOwnProfile({
            id: activeUser.id,
            connected_trainer_code: null,
            onboarding_step: 'done'
        });
    }

    await initStudentDashboard({ force: true, remoteSync: false });
    renderStudentConsultoriaCard(students[idx]);
    renderStudentWaterMain();
    showDietRuntimeMessage('Consultoria removida. Você pode conectar um novo treinador quando quiser.', 'success');
}

function renderStudentPerfil() {
    const { student } = getStudentData();
    if (!student) return;
    const savedSection = memoryGetItem(getStudentConfigSectionStorageKey());
    const sectionToKeep = normalizeStudentConfigSection(savedSection || activeStudentConfigSection || 'perfil');
    activeStudentConfigSection = sectionToKeep;
    renderStudentConsultoriaCard(student);

    const history = student.metricHistory || [];
    const lastEntry = history.length > 0 ? history[history.length - 1] : null;
    const prevEntry = history.length > 1 ? history[history.length - 2] : null;

    const weight = parseFloat(student.weight) || 0;
    const height = parseFloat(student.height) || 0;
    const imc = calcIMC(weight, height);
    const bodyFat = parseFloat(student.bodyFat) || 0;

    const prevWeight = prevEntry ? parseFloat(prevEntry.weight) : null;
    const prevBodyFat = prevEntry ? parseFloat(prevEntry.bodyFat || 0) : null;

    // Profile header
    const nameEl = document.getElementById('perfil-nome');
    if (nameEl) nameEl.textContent = student.name || 'Aluno';

    const avatarEl = document.getElementById('perfil-avatar');
    if (avatarEl) renderStudentAvatarElement(student, '');
    void syncStudentAvatarFromProfile(student);

    const membroEl = document.getElementById('perfil-membro-desde');
    if (membroEl) membroEl.textContent = `Membro desde ${formatDate(student.joinedAt)} `;

    // Metrics grid
    const metricsGrid = document.getElementById('perfil-metrics-grid');
    if (metricsGrid) {
        const weightDelta = getPercentDelta(weight, prevWeight);
        const imcVal = parseFloat(imc);
        const bfDelta = getPercentDelta(bodyFat, prevBodyFat);

        metricsGrid.innerHTML = `
        <div class="perfil-metric-card" onclick="openPerfilUpdateModal('peso')">
                <div class="metric-card-top">
                    <span class="metric-label">Peso</span>
                    <button class="metric-edit-btn"><i class="ph-bold ph-pencil-simple"></i></button>
                </div>
                <div class="metric-value">${weight}<span class="metric-unit">kg</span></div>
                ${weightDelta !== null ? `
                    <div class="metric-delta ${parseFloat(weightDelta) > 0 ? 'up' : parseFloat(weightDelta) < 0 ? 'down' : ''}">
                        <i class="ph-bold ${parseFloat(weightDelta) > 0 ? 'ph-trend-up' : parseFloat(weightDelta) < 0 ? 'ph-trend-down' : 'ph-minus'}"></i>
                        ${Math.abs(weightDelta)}% desde última atualização
                    </div>
                ` : '<div class="metric-delta neutral">Primeiro registro</div>'
            }
            </div>

            <div class="perfil-metric-card">
                <div class="metric-card-top">
                    <span class="metric-label">IMC</span>
                </div>
                <div class="metric-value">${imc}<span class="metric-unit">kg/m²</span></div>
                <div class="metric-delta ${imcVal < 25 && imcVal >= 18.5 ? 'healthy' : 'warn'}">
                    <i class="ph-bold ${imcVal < 25 && imcVal >= 18.5 ? 'ph-check-circle' : 'ph-warning'}"></i>
                    ${getIMCLabel(imcVal)}
                </div>
            </div>

            <div class="perfil-metric-card" onclick="openPerfilUpdateModal('gordura')">
                <div class="metric-card-top">
                    <span class="metric-label">% Gordura</span>
                    <button class="metric-edit-btn"><i class="ph-bold ph-pencil-simple"></i></button>
                </div>
                <div class="metric-value">${bodyFat || '—'}<span class="metric-unit">%</span></div>
                ${bodyFat > 0 && bfDelta !== null ? `
                    <div class="metric-delta ${parseFloat(bfDelta) < 0 ? 'down' : parseFloat(bfDelta) > 0 ? 'up' : ''}">
                        <i class="ph-bold ${parseFloat(bfDelta) < 0 ? 'ph-trend-down' : parseFloat(bfDelta) > 0 ? 'ph-trend-up' : 'ph-minus'}"></i>
                        ${Math.abs(bfDelta)}% desde última atualização
                    </div>
                ` : '<div class="metric-delta neutral">Sem dados anteriores</div>'}
            </div>

            <div class="perfil-metric-card" onclick="openPerfilUpdateModal('altura')">
                <div class="metric-card-top">
                    <span class="metric-label">Altura</span>
                    <button class="metric-edit-btn"><i class="ph-bold ph-pencil-simple"></i></button>
                </div>
                <div class="metric-value">${height}<span class="metric-unit">cm</span></div>
                <div class="metric-delta neutral">
                    <i class="ph-bold ph-ruler"></i>
                    ${(height / 100).toFixed(2)}m
                </div>
            </div>
    `;
    }

    // Personal Info grid
    const infoGrid = document.getElementById('perfil-info-grid');
    if (infoGrid) {
        const safeName = sanitizeUserInput(student.name || '', { maxLen: 90 }) || '—';
        const safeAge = sanitizeUserInput(student.age || '', { maxLen: 3 });
        const safeGoal = sanitizeUserInput(student.goal || '', { maxLen: 120 }) || '—';
        const safeBio = sanitizeUserInput(student.bio || '', { allowNewlines: true, maxLen: 400 });
        const safeBioHtml = safeBio
            ? escHtml(safeBio).replace(/\n/g, '<br>')
            : 'Conte um pouco sobre você para personalizar sua consultoria.';
        infoGrid.innerHTML = `
        <div class="perfil-info-item">
                <i class="ph-bold ph-user"></i>
                <div>
                    <span class="info-label">Nome</span>
                    <span class="info-value">${escHtml(safeName)}</span>
                </div>
            </div>
            <div class="perfil-info-item">
                <i class="ph-bold ph-calendar-blank"></i>
                <div>
                    <span class="info-label">Idade</span>
                    <span class="info-value">${escHtml(safeAge || '—')} anos</span>
                </div>
            </div>
            <div class="perfil-info-item">
                <i class="ph-bold ph-gender-intersex"></i>
                <div>
                    <span class="info-label">Gênero</span>
                    <span class="info-value">${student.gender === 'M' ? 'Masculino' : student.gender === 'F' ? 'Feminino' : '—'}</span>
                </div>
            </div>
            <div class="perfil-info-item">
                <i class="ph-bold ph-target"></i>
                <div>
                    <span class="info-label">Objetivo</span>
                    <span class="info-value">${escHtml(safeGoal)}</span>
                </div>
            </div>
            <div class="perfil-info-item perfil-info-item-bio">
                <i class="ph-bold ph-note-pencil"></i>
                <div>
                    <span class="info-label">Biografia</span>
                    <span class="info-value info-value-bio">${safeBioHtml}</span>
                </div>
            </div>
    `;
    }

    const anamnesisSummary = document.getElementById('perfil-anamnesis-summary');
    if (anamnesisSummary) {
        const anamnesisView = buildPerfilAnamnesisView(student);
        anamnesisSummary.innerHTML = anamnesisView;
    }
    const anamnesisCachePayload = buildStudentQuestionnairePayload(student);
    if (anamnesisCachePayload?.questionnaire && Object.keys(anamnesisCachePayload.questionnaire).length > 0) {
        memorySetItem('currentAnamnesis', JSON.stringify(anamnesisCachePayload));
    }

    // History list
    renderPerfilHistory(student);

    // Chart
    renderPerfilChart();
    void loadStudentMediaGallery();
    maybeShowStudentConnectTutorial(student);
    switchStudentConfigSection(sectionToKeep, { persist: false });
}

function getStudentAnamnesisSource(student = {}) {
    if (student?.questionnaire && typeof student.questionnaire === 'object') {
        return student.questionnaire;
    }
    if (student?.anamnesis?.questionnaire && typeof student.anamnesis.questionnaire === 'object') {
        return student.anamnesis.questionnaire;
    }
    const cachedRaw = memoryGetItem('currentAnamnesis');
    if (cachedRaw) {
        try {
            const cached = JSON.parse(cachedRaw);
            if (cached?.questionnaire && typeof cached.questionnaire === 'object') return cached.questionnaire;
            if (cached && typeof cached === 'object') return cached;
        } catch (err) {
            // noop
        }
    }
    return null;
}

function buildPerfilAnamnesisView(student = {}) {
    const anamnesis = getStudentAnamnesisSource(student);
    if (!anamnesis) {
        return `
            <div class="perfil-history-empty">
                <i class="ph-bold ph-clipboard-text"></i>
                <p>A anamnese ainda não foi encontrada. Conecte sua conta para concluir o onboarding.</p>
            </div>
            <div class="perfil-anamnesis-actions">
                <button class="btn-primary" type="button" onclick="openStudentAnamnesisEditor()">
                    <i class="ph-bold ph-pencil-simple"></i> Preencher anamnese completa
                </button>
            </div>
        `;
    }

    const summaryItems = [
        { label: 'Dor / Limitações', value: anamnesis?.saude?.dor === 'sim' ? 'Sim' : 'Não' },
        { label: 'Uso de medicação', value: anamnesis?.saude?.med === 'sim' ? 'Sim' : 'Não' },
        { label: 'Horas de sono', value: `${anamnesis?.rotina?.sono || '--'} h` },
        { label: 'Refeições por dia', value: anamnesis?.nutricao?.refeicoes || '--' },
        { label: 'Estresse', value: anamnesis?.rotina?.estresse || '--' },
        { label: 'Duração de treino', value: `${anamnesis?.treino?.duracao || '--'} min` }
    ];

    return `
        <p style="margin:0; color:var(--text-muted);">
            Resumo do seu questionário inicial usado para montar treino e dieta.
        </p>
        <div class="perfil-anamnesis-summary-grid">
            ${summaryItems.map((item) => `
                <div class="perfil-anamnesis-item">
                    <span>${escHtml(item.label)}</span>
                    <strong>${escHtml(String(item.value || '--'))}</strong>
                </div>
            `).join('')}
        </div>
        <div class="perfil-anamnesis-actions">
            <button class="btn-secondary" type="button" onclick="openPerfilAnamnesisModal()">
                <i class="ph-bold ph-eye"></i> Ver completo
            </button>
            <button class="btn-primary" type="button" onclick="openStudentAnamnesisEditor()">
                <i class="ph-bold ph-pencil-simple"></i> Editar completa
            </button>
        </div>
    `;
}

function setQuestionnaireInputValue(id, value = '') {
    const el = document.getElementById(id);
    if (!el) return;
    el.value = String(value ?? '');
}

function dispatchQuestionnaireFieldChange(el) {
    if (!el) return;
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
}

function setQuestionnairePreset(id, value = '') {
    const el = document.getElementById(id);
    if (!el) return;
    el.value = String(value ?? '');
    dispatchQuestionnaireFieldChange(el);
}

function appendQuestionnairePreset(id, value = '') {
    const el = document.getElementById(id);
    const nextValue = sanitizeUserInput(value, { allowNewlines: true, maxLen: 120 });
    if (!el || !nextValue) return;

    const currentParts = String(el.value || '')
        .split(/[,\n;]+/)
        .map((item) => sanitizeUserInput(item, { allowNewlines: true, maxLen: 120 }).trim())
        .filter(Boolean);
    const alreadySelected = currentParts.some((item) => normalizeText(item) === normalizeText(nextValue));
    if (!alreadySelected) currentParts.push(nextValue);
    el.value = currentParts.join(', ');
    dispatchQuestionnaireFieldChange(el);
}

function clearQuestionnaireChecks(name) {
    document.querySelectorAll(`input[name="${name}"]`).forEach((checkbox) => {
        checkbox.checked = false;
        dispatchQuestionnaireFieldChange(checkbox);
    });
}

function validateQuestionnaireBaseFields() {
    const requiredFields = [
        { id: 'q_nome', label: 'seu nome' },
        { id: 'q_idade', label: 'sua idade' },
        { id: 'q_genero', label: 'seu gênero' },
        { id: 'q_peso', label: 'seu peso' },
        { id: 'q_altura', label: 'sua altura' }
    ];
    const missing = requiredFields.find(({ id }) => !String(document.getElementById(id)?.value || '').trim());
    if (missing) {
        switchQTab('saude');
        alert(`Preencha ${missing.label} para salvar a anamnese.`);
        setTimeout(() => document.getElementById(missing.id)?.focus(), 80);
        return false;
    }

    const numericRules = [
        { id: 'q_idade', label: 'idade', min: 10, max: 100 },
        { id: 'q_peso', label: 'peso', min: 20, max: 350 },
        { id: 'q_altura', label: 'altura', min: 100, max: 250 }
    ];
    const invalid = numericRules.find(({ id, min, max }) => {
        const parsed = parseFloat(String(document.getElementById(id)?.value || '').replace(',', '.'));
        return !Number.isFinite(parsed) || parsed < min || parsed > max;
    });
    if (invalid) {
        switchQTab('saude');
        alert(`Confira o campo ${invalid.label} antes de salvar.`);
        setTimeout(() => document.getElementById(invalid.id)?.focus(), 80);
        return false;
    }

    return true;
}

function setQuestionnaireSelectValue(id, value = '', fallback = '') {
    const el = document.getElementById(id);
    if (!el) return;
    const desired = String(value || '').trim();
    const hasDesired = Array.from(el.options || []).some((option) => String(option.value || '') === desired);
    if (desired && hasDesired) {
        el.value = desired;
        return;
    }
    el.value = String(fallback || '').trim();
}

function setQuestionnaireRadioValue(name, value = '', fallback = '') {
    const radios = Array.from(document.querySelectorAll(`input[name="${name}"]`));
    if (!radios.length) return;
    const desired = String(value || '').trim();
    let applied = false;
    radios.forEach((radio) => {
        const shouldCheck = desired && String(radio.value || '') === desired;
        radio.checked = shouldCheck;
        if (shouldCheck) applied = true;
    });
    if (!applied) {
        const fallbackRadio = radios.find((radio) => String(radio.value || '') === String(fallback || '').trim()) || radios[0];
        if (fallbackRadio) fallbackRadio.checked = true;
    }
}

function setQuestionnaireCheckboxValues(name, values = []) {
    const selected = new Set((Array.isArray(values) ? values : [values]).map((item) => String(item || '').trim()));
    document.querySelectorAll(`input[name="${name}"]`).forEach((checkbox) => {
        checkbox.checked = selected.has(String(checkbox.value || '').trim());
    });
}

function setQuestionnaireSliderValue(id, value = '', outputId = '', suffix = '') {
    const slider = document.getElementById(id);
    if (!slider) return;
    const min = parseFloat(slider.min || '0');
    const max = parseFloat(slider.max || '999');
    const parsed = parseFloat(String(value || '').replace(',', '.'));
    const safeValue = Number.isFinite(parsed)
        ? Math.max(min, Math.min(max, parsed))
        : parseFloat(slider.value || min || 0);
    slider.value = String(safeValue);
    const output = document.getElementById(outputId);
    if (output) output.textContent = `${safeValue}${suffix}`;
}

function buildStudentQuestionnairePayload(student = {}) {
    let cached = null;
    const cachedRaw = memoryGetItem('currentAnamnesis');
    if (cachedRaw) {
        try {
            cached = JSON.parse(cachedRaw);
        } catch (err) {
            cached = null;
        }
    }
    const questionnaire = getStudentAnamnesisSource(student) || cached?.questionnaire || cached || {};
    const metasObjetivo = sanitizeUserInput(questionnaire?.metas?.objetivo_3_meses || '', { allowNewlines: true, maxLen: 300 });
    return {
        name: sanitizeUserInput(student?.name || cached?.name || memoryGetItem('studentName') || '', { maxLen: 90 }),
        age: sanitizeUserInput(student?.age || cached?.age || '', { maxLen: 3 }),
        gender: sanitizeUserInput(student?.gender || cached?.gender || 'M', { maxLen: 1 }) || 'M',
        weight: sanitizeUserInput(student?.weight || cached?.weight || '', { maxLen: 8 }),
        height: sanitizeUserInput(student?.height || cached?.height || '', { maxLen: 8 }),
        goal: sanitizeUserInput(student?.goal || cached?.goal || metasObjetivo || '', { allowNewlines: true, maxLen: 300 }),
        questionnaire
    };
}

function prefillStudentQuestionnaireForm(payload = {}) {
    const questionnaire = payload?.questionnaire && typeof payload.questionnaire === 'object' ? payload.questionnaire : {};

    setQuestionnaireInputValue('q_nome', payload?.name || '');
    setQuestionnaireInputValue('q_idade', payload?.age || '');
    setQuestionnaireSelectValue('q_genero', payload?.gender || 'M', 'M');
    setQuestionnaireInputValue('q_peso', payload?.weight || '');
    setQuestionnaireInputValue('q_altura', payload?.height || '');

    const metaGoal = sanitizeUserInput(questionnaire?.metas?.objetivo_3_meses || payload?.goal || '', { allowNewlines: true, maxLen: 300 });
    setQuestionnaireInputValue('q_objetivo', metaGoal);
    setQuestionnaireInputValue('q_incomoda', questionnaire?.metas?.incomoda || '');
    setQuestionnaireInputValue('q_consultoria_antes', questionnaire?.metas?.consultoria_antes || '');

    setQuestionnaireRadioValue('q_dor', questionnaire?.saude?.dor || 'nao', 'nao');
    setQuestionnaireInputValue('q_dor_desc', questionnaire?.saude?.dor_desc || '');
    toggleConditional('cond-dor', String(questionnaire?.saude?.dor || 'nao') === 'sim');

    setQuestionnaireCheckboxValues('q_cond', questionnaire?.saude?.condicoes || []);
    setQuestionnaireRadioValue('q_med', questionnaire?.saude?.med || 'nao', 'nao');
    setQuestionnaireInputValue('q_med_desc', questionnaire?.saude?.med_desc || '');
    toggleConditional('cond-med', String(questionnaire?.saude?.med || 'nao') === 'sim');

    setQuestionnaireRadioValue('q_cirurgia', questionnaire?.saude?.cirurgia || 'nao', 'nao');
    setQuestionnaireInputValue('q_cirurgia_desc', questionnaire?.saude?.cirurgia_desc || '');
    toggleConditional('cond-cirurgia', String(questionnaire?.saude?.cirurgia || 'nao') === 'sim');

    setQuestionnaireCheckboxValues('q_restr', questionnaire?.nutricao?.restricoes || []);
    setQuestionnaireInputValue('q_nao_come', questionnaire?.nutricao?.nao_come || '');
    setQuestionnaireRadioValue('q_intestino', questionnaire?.nutricao?.intestino || 'sim', 'sim');
    setQuestionnaireRadioValue('q_refeicoes', questionnaire?.nutricao?.refeicoes || '4', '4');

    setQuestionnaireSliderValue('q_sono', questionnaire?.rotina?.sono || '7', 'val-sono', 'h');
    setQuestionnaireRadioValue('q_descansado', questionnaire?.rotina?.descansado || 'sim', 'sim');
    setQuestionnaireSliderValue('q_estresse', questionnaire?.rotina?.estresse || '5', 'val-estresse', '');
    setQuestionnaireRadioValue('q_fumo', questionnaire?.rotina?.fumo || 'nao', 'nao');
    setQuestionnaireRadioValue('q_alcool', questionnaire?.rotina?.alcool || 'nao', 'nao');
    setQuestionnaireRadioValue('q_trab', questionnaire?.rotina?.trabalho || 'sentado', 'sentado');

    setQuestionnaireInputValue('q_tempo_pratica', questionnaire?.treino?.tempo_pratica || '');
    setQuestionnaireInputValue('q_exercicios_ama', questionnaire?.treino?.exercicios_ama || '');
    setQuestionnaireInputValue('q_exercicios_detesta', questionnaire?.treino?.exercicios_detesta || '');
    setQuestionnaireCheckboxValues('q_dias', questionnaire?.treino?.dias || []);
    setQuestionnaireRadioValue('q_duracao', questionnaire?.treino?.duracao || '60', '60');
}

function openStudentAnamnesisEditor() {
    const { student } = getStudentData();
    if (!student) return;
    closePerfilAnamnesisModal();
    studentQuestionnaireEditContext = { source: 'perfil', returnSection: 'anamnesis' };
    openStudentQuestionnaireScreen(student.name || memoryGetItem('studentName') || '', { preserveContext: true });
    prefillStudentQuestionnaireForm(buildStudentQuestionnairePayload(student));
    showDietRuntimeMessage('Edite suas respostas e salve para atualizar sua anamnese.', 'info');
}

function openPerfilAnamnesisModal() {
    const modal = document.getElementById('perfil-anamnesis-modal');
    const body = document.getElementById('perfil-anamnesis-modal-body');
    const { student } = getStudentData();
    if (!modal || !body) return;
    const anamnesis = getStudentAnamnesisSource(student || {});
    if (!anamnesis) {
        body.innerHTML = '<p style="color:var(--text-muted); margin:0;">A anamnese ainda não foi preenchida.</p>';
    } else {
        const boolMap = { sim: 'Sim', nao: 'Não' };
        const condicoesMap = {
            diabetes: 'Diabetes',
            hipertensao: 'Hipertensão',
            sopro: 'Sopro cardíaco',
            asma: 'Asma',
            artrite: 'Artrite',
            hernia: 'Hérnia de disco'
        };
        const restricoesMap = {
            lactose: 'Lactose',
            gluten: 'Glúten',
            amendoim: 'Amendoim',
            frutos_mar: 'Frutos do mar',
            ovo: 'Ovo',
            soja: 'Soja'
        };
        const diasMap = {
            seg: 'Segunda',
            ter: 'Terça',
            qua: 'Quarta',
            qui: 'Quinta',
            sex: 'Sexta',
            sab: 'Sábado',
            dom: 'Domingo'
        };
        const fumoMap = {
            nao: 'Não fuma',
            ocasional: 'Ocasional',
            diario: 'Diário'
        };
        const alcoolMap = {
            nao: 'Não bebe',
            fds: 'Fim de semana',
            diario: 'Diário'
        };
        const trabalhoMap = {
            sentado: 'Sentado',
            em_pe: 'Em pé',
            movimento: 'Em movimento'
        };
        const refeicoesMap = { '2': '2 refeições', '3': '3 refeições', '4': '4 refeições', '5': '5 refeições', '6': '6 refeições' };
        const duracaoMap = { '30': '30 minutos', '45': '45 minutos', '60': '60 minutos', '75': '75 minutos', '90': '90 minutos' };

        const toText = (value, fallback = 'Não informado') => {
            const safe = sanitizeUserInput(value || '', { allowNewlines: true, maxLen: 320 }).trim();
            return safe || fallback;
        };
        const mapValue = (value, dictionary = {}, fallback = 'Não informado') => {
            const raw = sanitizeUserInput(value || '', { maxLen: 120 }).trim().toLowerCase();
            if (!raw) return fallback;
            return dictionary[raw] || toText(raw, fallback);
        };
        const listValue = (value, dictionary = {}, fallback = 'Não informado') => {
            const items = Array.isArray(value) ? value : [];
            if (!items.length) return fallback;
            const normalized = items
                .map((entry) => mapValue(entry, dictionary, ''))
                .filter(Boolean);
            return normalized.length ? normalized.join(', ') : fallback;
        };
        const yesNo = (value, fallback = 'Não informado') => mapValue(value, boolMap, fallback);
        const formatValueHtml = (value = '') => escHtml(String(value || '')).replace(/\n/g, '<br>');

        const saude = anamnesis.saude || {};
        const nutricao = anamnesis.nutricao || {};
        const rotina = anamnesis.rotina || {};
        const treino = anamnesis.treino || {};
        const metas = anamnesis.metas || {};

        const sections = [
            {
                title: 'Saúde',
                rows: [
                    { label: 'Dor em articulações', value: yesNo(saude.dor) },
                    { label: 'Quais dores', value: toText(saude.dor_desc, saude.dor === 'sim' ? 'Não informado' : 'Sem dor relatada') },
                    { label: 'Condições médicas', value: listValue(saude.condicoes, condicoesMap, 'Nenhuma condição marcada') },
                    { label: 'Uso de medicação contínua', value: yesNo(saude.med) },
                    { label: 'Quais medicamentos', value: toText(saude.med_desc, saude.med === 'sim' ? 'Não informado' : 'Não usa') },
                    { label: 'Já fez cirurgia', value: yesNo(saude.cirurgia) },
                    { label: 'Detalhes da cirurgia', value: toText(saude.cirurgia_desc, saude.cirurgia === 'sim' ? 'Não informado' : 'Nenhuma cirurgia informada') }
                ]
            },
            {
                title: 'Nutrição',
                rows: [
                    { label: 'Restrições alimentares', value: listValue(nutricao.restricoes, restricoesMap, 'Nenhuma restrição marcada') },
                    { label: 'Alimentos que evita', value: toText(nutricao.nao_come) },
                    { label: 'Intestino regular', value: yesNo(nutricao.intestino) },
                    { label: 'Refeições por dia', value: mapValue(nutricao.refeicoes, refeicoesMap) }
                ]
            },
            {
                title: 'Rotina',
                rows: [
                    { label: 'Horas de sono', value: rotina.sono ? `${toText(rotina.sono)} h` : 'Não informado' },
                    { label: 'Acorda descansado', value: yesNo(rotina.descansado) },
                    { label: 'Nível de estresse', value: rotina.estresse ? `${toText(rotina.estresse)}/10` : 'Não informado' },
                    { label: 'Tabagismo', value: mapValue(rotina.fumo, fumoMap) },
                    { label: 'Consumo de álcool', value: mapValue(rotina.alcool, alcoolMap) },
                    { label: 'Estilo de trabalho', value: mapValue(rotina.trabalho, trabalhoMap) }
                ]
            },
            {
                title: 'Treino',
                rows: [
                    { label: 'Tempo de prática', value: toText(treino.tempo_pratica) },
                    { label: 'Exercícios que gosta', value: toText(treino.exercicios_ama) },
                    { label: 'Exercícios que não gosta', value: toText(treino.exercicios_detesta) },
                    { label: 'Dias disponíveis', value: listValue(treino.dias, diasMap) },
                    { label: 'Duração da sessão', value: mapValue(treino.duracao, duracaoMap) }
                ]
            },
            {
                title: 'Metas',
                rows: [
                    { label: 'O que mais incomoda', value: toText(metas.incomoda) },
                    { label: 'Objetivo em 3 meses', value: toText(metas.objetivo_3_meses) },
                    { label: 'Experiência com consultoria', value: toText(metas.consultoria_antes) }
                ]
            }
        ];

        body.innerHTML = `
            <div class="perfil-anamnesis-details">
                ${sections.map((section) => `
                    <article class="perfil-anamnesis-section-card">
                        <header class="perfil-anamnesis-section-head">
                            <h4>${escHtml(section.title)}</h4>
                        </header>
                        <div class="perfil-anamnesis-rows">
                            ${(section.rows || []).map((row) => `
                                <div class="perfil-anamnesis-row">
                                    <span class="perfil-anamnesis-row-label">${escHtml(row.label || '')}</span>
                                    <strong class="perfil-anamnesis-row-value">${formatValueHtml(row.value || 'Não informado')}</strong>
                                </div>
                            `).join('')}
                        </div>
                    </article>
                `).join('')}
            </div>
        `;
    }
    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('active'), 10);
}

function closePerfilAnamnesisModal() {
    const modal = document.getElementById('perfil-anamnesis-modal');
    if (!modal) return;
    modal.classList.remove('active');
    setTimeout(() => { modal.style.display = 'none'; }, 220);
}

function handlePerfilAnamnesisOverlayClick(event) {
    if (event?.target !== event?.currentTarget) return;
    closePerfilAnamnesisModal();
}

async function uploadStudentFileToStorage(file, folder = 'gallery') {
    if (!isSupabaseReady() || typeof window.supabase?.storage?.from !== 'function') {
        return { error: { message: 'Supabase Storage indisponível no momento.' } };
    }
    const userId = String(memoryGetItem('currentUserId') || '').trim();
    if (!userId) return { error: { message: 'Sessão inválida para upload.' } };
    const originalName = sanitizeUserInput(file?.name || 'arquivo', { maxLen: 120 }) || 'arquivo';
    const extRaw = originalName.includes('.') ? originalName.split('.').pop() : '';
    const ext = sanitizeUserInput(extRaw || (file?.type || '').split('/').pop() || 'bin', { maxLen: 12 }).toLowerCase() || 'bin';
    const random = Math.random().toString(36).slice(2, 9);
    const storagePath = `${userId}/${folder}/${Date.now()}-${random}.${ext}`;
    const { error } = await window.supabase.storage
        .from(STUDENT_MEDIA_BUCKET)
        .upload(storagePath, file, {
            cacheControl: '3600',
            upsert: false,
            contentType: file?.type || undefined
        });
    if (error) return { error };
    return { storagePath };
}

async function handleStudentAvatarInput(event) {
    const file = event?.target?.files?.[0];
    if (event?.target) event.target.value = '';
    if (!file) return;

    if (!String(file.type || '').startsWith('image/')) {
        setPerfilMediaStatus('Selecione uma imagem para foto de perfil.', 'error');
        return;
    }
    if (file.size > MAX_STUDENT_IMAGE_BYTES) {
        setPerfilMediaStatus(`A imagem excede 8MB (${formatFileSize(file.size)}).`, 'error');
        return;
    }

    setPerfilMediaStatus('Enviando foto de perfil...', 'loading');
    const upload = await uploadStudentFileToStorage(file, 'avatar');
    if (upload.error || !upload.storagePath) {
        setPerfilMediaStatus(getAuthErrorMessage(upload.error, 'generic'), 'error');
        return;
    }

    const avatarRef = makeStorageRef(STUDENT_MEDIA_BUCKET, upload.storagePath);
    const userId = String(memoryGetItem('currentUserId') || '').trim();
    const { studentId, students, student } = getStudentData();

    const profileUpdate = await upsertOwnProfile({
        id: userId,
        avatar_url: avatarRef
    });
    if (!profileUpdate) {
        setPerfilMediaStatus('Upload concluído, mas falhou ao salvar o perfil.', 'error');
        return;
    }

    if (student) {
        student.avatarRef = avatarRef;
        student.avatar_url = avatarRef;
        const idx = students.findIndex((s) => String(s.id) === String(studentId));
        if (idx >= 0) {
            students[idx] = student;
            saveStudentData(students, { studentId: String(student.id || studentId || '') });
            syncStudentProfileEntity(student);
        }
    }

    memorySetItem('currentUserAvatarRef', avatarRef);
    setPerfilMediaStatus('Foto atualizada com sucesso.', 'success');
    await syncStudentAvatarFromProfile(student || {});
}

async function loadStudentMediaGallery(force = false) {
    const grid = document.getElementById('perfil-media-grid');
    if (!grid) return;
    const userId = String(memoryGetItem('currentUserId') || '').trim();
    if (!userId || !isSupabaseReady() || !entityTablesAvailability.media) {
        studentMediaState.items = [];
        studentMediaState.loading = false;
        studentMediaState.error = userId ? 'Galeria indisponível no momento.' : 'Faça login para carregar sua galeria.';
        renderStudentMediaGallery();
        return;
    }

    const cacheValid = (
        !force
        && studentMediaState.loadedForUser === userId
        && (Date.now() - studentMediaState.loadedAt) < 40 * 60 * 1000
    );
    if (cacheValid) {
        renderStudentMediaGallery();
        return;
    }

    studentMediaState.loading = true;
    studentMediaState.error = '';
    renderStudentMediaGallery();

    const { data, error } = await window.supabase
        .from(SUPABASE_TABLES.studentMedia)
        .select('id,student_user_id,trainer_code,media_type,storage_path,caption,created_at')
        .eq('student_user_id', userId)
        .order('created_at', { ascending: false })
        .limit(120);

    if (error) {
        console.warn('Falha ao carregar galeria do aluno.', error.message || error);
        if (String(error.message || '').toLowerCase().includes('does not exist')) {
            entityTablesAvailability.media = false;
        }
        studentMediaState.loading = false;
        studentMediaState.items = [];
        studentMediaState.error = 'Não foi possível carregar sua galeria agora.';
        renderStudentMediaGallery();
        return;
    }

    const rows = Array.isArray(data) ? data : [];
    const signedRows = await Promise.all(rows.map(async (row) => {
        const ref = makeStorageRef(STUDENT_MEDIA_BUCKET, row.storage_path || '');
        const signedUrl = await resolveStorageRefUrl(ref, 3600);
        return {
            ...row,
            signedUrl
        };
    }));

    studentMediaState.loading = false;
    studentMediaState.items = signedRows.filter((item) => item.signedUrl);
    studentMediaState.loadedForUser = userId;
    studentMediaState.loadedAt = Date.now();
    studentMediaState.error = '';
    renderStudentMediaGallery();
}

function renderStudentMediaGallery() {
    const grid = document.getElementById('perfil-media-grid');
    if (!grid) return;

    if (studentMediaState.loading) {
        grid.innerHTML = `
            <div class="perfil-history-empty" style="grid-column:1/-1;">
                <i class="ph-bold ph-spinner-gap"></i>
                <p>Carregando sua galeria...</p>
            </div>
        `;
        return;
    }

    if (studentMediaState.error) {
        grid.innerHTML = `
            <div class="perfil-history-empty" style="grid-column:1/-1;">
                <i class="ph-bold ph-warning-circle"></i>
                <p>${escHtml(studentMediaState.error)}</p>
            </div>
        `;
        return;
    }

    if (!Array.isArray(studentMediaState.items) || studentMediaState.items.length === 0) {
        grid.innerHTML = `
            <div class="perfil-history-empty" style="grid-column:1/-1;">
                <i class="ph-bold ph-images-square"></i>
                <p>Nenhum arquivo enviado ainda. Envie fotos e vídeos para acompanhar sua evolução.</p>
            </div>
        `;
        return;
    }

    grid.innerHTML = studentMediaState.items.map((item, idx) => {
        const isVideo = item.media_type === 'video';
        const preview = isVideo
            ? `<video src="${escHtml(item.signedUrl)}" muted preload="metadata" playsinline></video>`
            : `<img src="${escHtml(item.signedUrl)}" alt="Mídia ${idx + 1}" loading="lazy" decoding="async">`;
        return `
            <button type="button" class="perfil-media-item" onclick="openPerfilMediaViewer(${idx})">
                ${preview}
                <div class="perfil-media-item-meta">
                    <span class="perfil-media-item-type">
                        <i class="ph-bold ${isVideo ? 'ph-video-camera' : 'ph-image'}"></i>
                        ${isVideo ? 'Vídeo' : 'Imagem'}
                    </span>
                    <span>${formatDate(item.created_at)}</span>
                </div>
            </button>
        `;
    }).join('');
    optimizeMediaElements(grid);
}

async function handleStudentGalleryUpload(event) {
    const file = event?.target?.files?.[0];
    if (event?.target) event.target.value = '';
    if (!file) return;
    const isImage = String(file.type || '').startsWith('image/');
    const isVideo = String(file.type || '').startsWith('video/');
    if (!isImage && !isVideo) {
        setPerfilMediaStatus('Formato inválido. Envie imagem ou vídeo.', 'error');
        return;
    }
    const limit = isImage ? MAX_STUDENT_IMAGE_BYTES : MAX_STUDENT_VIDEO_BYTES;
    if (file.size > limit) {
        setPerfilMediaStatus(
            `Arquivo excede o limite (${isImage ? '8MB imagem' : '30MB vídeo'}): ${formatFileSize(file.size)}.`,
            'error'
        );
        return;
    }

    setPerfilMediaStatus('Enviando arquivo...', 'loading');
    const upload = await uploadStudentFileToStorage(file, 'gallery');
    if (upload.error || !upload.storagePath) {
        setPerfilMediaStatus(getAuthErrorMessage(upload.error, 'generic'), 'error');
        return;
    }

    const userId = String(memoryGetItem('currentUserId') || '').trim();
    const { student } = getStudentData();
    const trainerCode = sanitizeCodeInput(
        student?.trainerCode || student?.trainer_code || memoryGetItem('connectedTrainerCode') || '',
        5
    ) || null;

    const { error } = await window.supabase
        .from(SUPABASE_TABLES.studentMedia)
        .insert({
            student_user_id: userId,
            trainer_code: trainerCode,
            media_type: isVideo ? 'video' : 'image',
            storage_path: upload.storagePath,
            caption: ''
        });

    if (error) {
        console.warn('Falha ao registrar metadado da galeria.', error.message || error);
        await window.supabase.storage.from(STUDENT_MEDIA_BUCKET).remove([upload.storagePath]);
        setPerfilMediaStatus('Upload enviado, mas não foi possível salvar na galeria.', 'error');
        return;
    }

    setPerfilMediaStatus('Arquivo enviado para sua galeria.', 'success');
    await loadStudentMediaGallery(true);
    refreshStudentCheckinViewIfVisible();
}

function openPerfilMediaViewer(index) {
    const item = Array.isArray(studentMediaState.items) ? studentMediaState.items[index] : null;
    const modal = document.getElementById('perfil-media-viewer-modal');
    const body = document.getElementById('perfil-media-viewer-body');
    if (!item || !modal || !body) return;
    activePerfilMediaId = String(item.id || '');
    const isVideo = item.media_type === 'video';
    const mediaHtml = isVideo
        ? `<video src="${escHtml(item.signedUrl)}" controls playsinline></video>`
        : `<img src="${escHtml(item.signedUrl)}" alt="Mídia do aluno">`;
    body.innerHTML = `
        <div class="perfil-media-viewer-content">${mediaHtml}</div>
        <div class="perfil-media-viewer-meta">
            <strong>${isVideo ? 'Vídeo' : 'Imagem'}</strong>
            <span> • ${formatDate(item.created_at)}</span>
        </div>
    `;
    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('active'), 10);
}

function closePerfilMediaViewer() {
    const modal = document.getElementById('perfil-media-viewer-modal');
    if (!modal) return;
    activePerfilMediaId = '';
    modal.classList.remove('active');
    setTimeout(() => { modal.style.display = 'none'; }, 220);
}

async function deleteActivePerfilMedia() {
    if (!activePerfilMediaId) {
        closePerfilMediaViewer();
        return;
    }
    const target = (studentMediaState.items || []).find((item) => String(item.id) === String(activePerfilMediaId));
    if (!target) {
        closePerfilMediaViewer();
        return;
    }
    if (!confirm('Remover este arquivo da galeria?')) return;

    const { error } = await window.supabase
        .from(SUPABASE_TABLES.studentMedia)
        .delete()
        .eq('id', target.id);

    if (error) {
        setPerfilMediaStatus('Não foi possível remover este arquivo.', 'error');
        return;
    }

    await window.supabase.storage.from(STUDENT_MEDIA_BUCKET).remove([target.storage_path]);
    setPerfilMediaStatus('Arquivo removido da galeria.', 'success');
    closePerfilMediaViewer();
    await loadStudentMediaGallery(true);
    refreshStudentCheckinViewIfVisible();
}

function renderPerfilHistory(student) {
    const list = document.getElementById('perfil-history-list');
    if (!list) return;

    const history = student.metricHistory || [];

    if (history.length === 0) {
        list.innerHTML = `
        <div class="perfil-history-empty">
                <i class="ph-bold ph-note-blank"></i>
                <p>Nenhuma alteração registrada ainda. Atualize suas métricas para começar a acompanhar sua evolução.</p>
            </div>
        `;
        return;
    }

    const items = history.slice().reverse().slice(0, 10);
    list.innerHTML = items.map((entry, idx) => {
        const changes = [];
        const prevIdx = history.length - 1 - idx - 1;
        const prev = prevIdx >= 0 ? history[prevIdx] : null;

        if (entry.weight) {
            const delta = prev && prev.weight ? getPercentDelta(entry.weight, prev.weight) : null;
            changes.push({
                label: 'Peso',
                value: `${entry.weight} kg`,
                delta: delta,
                icon: 'ph-barbell'
            });
        }
        if (entry.bodyFat) {
            const delta = prev && prev.bodyFat ? getPercentDelta(entry.bodyFat, prev.bodyFat) : null;
            changes.push({
                label: 'Gordura',
                value: `${entry.bodyFat}% `,
                delta: delta,
                icon: 'ph-fire'
            });
        }
        if (entry.height) {
            changes.push({
                label: 'Altura',
                value: `${entry.height} cm`,
                delta: null,
                icon: 'ph-ruler'
            });
        }

        return `
        <div class="perfil-history-item" style="display: flex; justify-content: space-between; align-items: flex-start; gap: 1rem;">
                <div style="flex: 1;">
                    <div class="history-date">
                        <i class="ph-bold ph-calendar-check"></i>
                        ${formatDate(entry.date)}
                    </div>
                    <div class="history-changes" style="display: flex; flex-wrap: wrap; gap: 0.5rem; margin-top: 0.5rem;">
                        ${changes.map(c => `
                            <div class="history-change-chip" style="background: rgba(255,255,255,0.05); padding: 0.3rem 0.6rem; border-radius: 8px; font-size: 0.85rem; display: flex; align-items: center; gap: 0.4rem; border: 1px solid rgba(255,255,255,0.08);">
                                <i class="ph-bold ${c.icon}" style="color: var(--primary-color);"></i>
                                <span>${c.label}: <strong style="color: var(--text-main);">${c.value}</strong></span>
                                ${c.delta !== null ? `
                                    <span class="history-delta ${parseFloat(c.delta) > 0 ? 'up' : parseFloat(c.delta) < 0 ? 'down' : ''}" style="font-size: 0.75rem; font-weight: 600;">
                                        (${parseFloat(c.delta) > 0 ? '+' : ''}${c.delta}%)
                                    </span>
                                ` : ''}
                            </div>
                        `).join('')}
                    </div>
                </div>
                <button class="btn-delete-history" onclick="confirmDeleteMetric(${history.length - 1 - idx})">
                    <i class="ph-bold ph-trash"></i>
                </button>
            </div>
        `;
    }).join('');
}

function renderPerfilChart() {
    const { student } = getStudentData();
    if (!student) return;

    const history = student.metricHistory || [];
    const canvas = document.getElementById('perfil-weight-chart');
    const emptyEl = document.getElementById('perfil-chart-empty');
    if (!canvas) return;

    const weightData = history.filter(h => h.weight).map(h => ({
        date: formatDateShort(h.date),
        value: parseFloat(h.weight)
    }));

    // Add initial weight if no history
    if (weightData.length === 0 && student.weight) {
        weightData.push({ date: formatDateShort(student.joinedAt), value: parseFloat(student.weight) });
    }

    if (weightData.length < 2) {
        canvas.style.display = 'none';
        if (emptyEl) emptyEl.style.display = 'flex';
        return;
    }

    canvas.style.display = 'block';
    if (emptyEl) emptyEl.style.display = 'none';

    const rangeVal = document.getElementById('perfil-chart-range')?.value || '6';
    const data = rangeVal === 'all' ? weightData : weightData.slice(-parseInt(rangeVal));

    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    canvas.width = canvas.offsetWidth * dpr;
    canvas.height = 220 * dpr;
    ctx.scale(dpr, dpr);
    const W = canvas.offsetWidth;
    const H = 220;

    ctx.clearRect(0, 0, W, H);

    const values = data.map(d => d.value);
    const minV = Math.min(...values) - 2;
    const maxV = Math.max(...values) + 2;
    const rangeV = maxV - minV || 1;

    const padL = 50, padR = 20, padT = 20, padB = 40;
    const chartW = W - padL - padR;
    const chartH = H - padT - padB;

    const points = data.map((d, i) => ({
        x: padL + (i / (data.length - 1)) * chartW,
        y: padT + chartH - ((d.value - minV) / rangeV) * chartH
    }));

    // Grid lines
    ctx.strokeStyle = 'rgba(255,255,255,0.06)';
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
        const y = padT + (i / 4) * chartH;
        ctx.beginPath();
        ctx.moveTo(padL, y);
        ctx.lineTo(W - padR, y);
        ctx.stroke();

        const val = (maxV - (i / 4) * rangeV).toFixed(1);
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        ctx.font = '11px Inter, sans-serif';
        ctx.textAlign = 'right';
        ctx.fillText(val, padL - 8, y + 4);
    }

    // Gradient fill
    const grad = ctx.createLinearGradient(0, padT, 0, H);
    grad.addColorStop(0, 'rgba(163, 230, 53, 0.25)');
    grad.addColorStop(1, 'rgba(163, 230, 53, 0.01)');

    ctx.beginPath();
    ctx.moveTo(points[0].x, H - padB);
    points.forEach(p => ctx.lineTo(p.x, p.y));
    ctx.lineTo(points[points.length - 1].x, H - padB);
    ctx.closePath();
    ctx.fillStyle = grad;
    ctx.fill();

    // Line
    ctx.beginPath();
    ctx.strokeStyle = '#A3E635';
    ctx.lineWidth = 2.5;
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';
    points.forEach((p, i) => i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y));
    ctx.stroke();

    // Dots and labels
    points.forEach((p, i) => {
        ctx.beginPath();
        ctx.arc(p.x, p.y, 4, 0, Math.PI * 2);
        ctx.fillStyle = '#A3E635';
        ctx.fill();
        ctx.beginPath();
        ctx.arc(p.x, p.y, 2, 0, Math.PI * 2);
        ctx.fillStyle = '#121214';
        ctx.fill();

        // Date labels
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.font = '10px Inter, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(data[i].date, p.x, H - padB + 16);
    });
}

function openPerfilUpdateModal(field) {
    _perfilModalField = field;
    const modal = document.getElementById('perfil-update-modal');
    const title = document.getElementById('perfil-modal-title');
    const body = document.getElementById('perfil-modal-body');
    if (!modal || !body) return;

    const { student } = getStudentData();
    if (!student) return;

    let html = '';

    if (field === 'peso') {
        title.textContent = 'Atualizar Peso';
        html = `
        <div class="perfil-modal-field">
                <label>PESO ATUAL (KG)</label>
                <input type="number" step="0.1" id="modal-peso" class="q-input" value="${student.weight || ''}" placeholder="Ex: 78.5">
            </div>
            <div class="perfil-modal-current">
                <span>Valor anterior:</span>
                <strong>${student.weight || '—'} kg</strong>
            </div>
    `;
    } else if (field === 'altura') {
        title.textContent = 'Atualizar Altura';
        html = `
        <div class="perfil-modal-field">
                <label>ALTURA (CM)</label>
                <input type="number" id="modal-altura" class="q-input" value="${student.height || ''}" placeholder="Ex: 175">
            </div>
    `;
    } else if (field === 'gordura') {
        title.textContent = 'Atualizar % Gordura Corporal';
        html = `
        <div class="perfil-modal-field">
                <label>PERCENTUAL DE GORDURA (%)</label>
                <input type="number" step="0.1" id="modal-gordura" class="q-input" value="${student.bodyFat || ''}" placeholder="Ex: 14.2">
            </div>
            <div class="perfil-modal-current">
                <span>Valor anterior:</span>
                <strong>${student.bodyFat || '—'}%</strong>
            </div>
    `;
    } else if (field === 'geral') {
        title.textContent = 'Editar Perfil';
        const safeNameValue = escHtml(sanitizeUserInput(student.name || '', { maxLen: 90 }));
        const safeAgeValue = escHtml(sanitizeUserInput(student.age || '', { maxLen: 3 }));
        const safeGoalValue = escHtml(sanitizeUserInput(student.goal || '', { maxLen: 120 }));
        const safeBio = escHtml(sanitizeUserInput(student.bio || '', { allowNewlines: true, maxLen: 400 }));
        html = `
        <div class="perfil-modal-field">
                <label>NOME</label>
                <input type="text" id="modal-nome" class="q-input" value="${safeNameValue}" placeholder="Seu nome">
            </div>
            <div class="perfil-modal-field">
                <label>IDADE</label>
                <input type="number" id="modal-idade" class="q-input" value="${safeAgeValue}" placeholder="25">
            </div>
            <div class="perfil-modal-field">
                <label>OBJETIVO</label>
                <input type="text" id="modal-objetivo" class="q-input" value="${safeGoalValue}" placeholder="Ex: Hipertrofia">
            </div>
            <div class="perfil-modal-field">
                <label>BIOGRAFIA</label>
                <textarea id="modal-bio" class="q-input perfil-bio-input" rows="4" placeholder="Conte um pouco sobre você">${safeBio}</textarea>
            </div>
    `;
    }

    body.innerHTML = html;
    modal.style.display = 'flex';
    setTimeout(() => modal.classList.add('active'), 10);
}

function closePerfilUpdateModal() {
    const modal = document.getElementById('perfil-update-modal');
    if (!modal) return;
    modal.classList.remove('active');
    setTimeout(() => { modal.style.display = 'none'; }, 300);
}

async function savePerfilUpdate() {
    const { studentId, students, student } = getStudentData();
    if (!student) return;

    if (!student.metricHistory) student.metricHistory = [];

    const now = new Date().toISOString();
    let changed = false;

    if (_perfilModalField === 'peso') {
        const val = parseFloat(document.getElementById('modal-peso')?.value);
        if (!isNaN(val) && val > 0) {
            student.weight = val.toString();
            student.metricHistory.push({
                date: now,
                weight: val,
                bodyFat: parseFloat(student.bodyFat) || null,
                height: parseFloat(student.height) || null
            });
            changed = true;
        }
    } else if (_perfilModalField === 'altura') {
        const val = parseFloat(document.getElementById('modal-altura')?.value);
        if (!isNaN(val) && val > 0) {
            student.height = val.toString();
            student.metricHistory.push({
                date: now,
                weight: parseFloat(student.weight) || null,
                bodyFat: parseFloat(student.bodyFat) || null,
                height: val
            });
            changed = true;
        }
    } else if (_perfilModalField === 'gordura') {
        const val = parseFloat(document.getElementById('modal-gordura')?.value);
        if (!isNaN(val) && val >= 0) {
            student.bodyFat = val.toString();
            student.metricHistory.push({
                date: now,
                weight: parseFloat(student.weight) || null,
                bodyFat: val,
                height: parseFloat(student.height) || null
            });
            changed = true;
        }
    } else if (_perfilModalField === 'geral') {
        const nome = sanitizeUserInput(document.getElementById('modal-nome')?.value, { maxLen: 90 });
        const idadeRaw = parseInt(document.getElementById('modal-idade')?.value, 10);
        const idade = Number.isFinite(idadeRaw) ? String(Math.min(100, Math.max(10, idadeRaw))) : '';
        const objetivo = sanitizeUserInput(document.getElementById('modal-objetivo')?.value, { maxLen: 120 });
        const bio = sanitizeUserInput(document.getElementById('modal-bio')?.value, { allowNewlines: true, maxLen: 400 });
        if (nome) student.name = nome;
        if (idade) student.age = idade;
        if (objetivo) student.goal = objetivo;
        student.bio = bio;
        if (nome) memorySetItem('studentName', nome);
        if (nome) memorySetItem('currentUserName', nome);
        memorySetItem('currentUserBio', bio);
        changed = true;
    }

    if (changed) {
        syncStudentTmbData(student);

        // Update the students array
        const idx = students.findIndex(s => s.id === studentId);
        if (idx !== -1) students[idx] = student;
        saveStudentData(students, { studentId: String(student.id || studentId || '') });
        void syncStudentProfileEntity(student);

        if (_perfilModalField === 'geral') {
            const userId = String(memoryGetItem('currentUserId') || '').trim();
            if (userId) {
                await upsertOwnProfile({
                    id: userId,
                    name: student.name || 'Aluno',
                    bio: student.bio || ''
                });
            }
        }

        closePerfilUpdateModal();
        renderStudentPerfil();
        refreshStudentCheckinViewIfVisible();

        // Also update dashboard name if changed
        const nameEl = document.getElementById('dash-student-name');
        if (nameEl) nameEl.innerText = `Olá, ${(student.name || 'Aluno').split(' ')[0]} `;
        const sideEl = document.getElementById('side-student-name');
        if (sideEl) sideEl.innerText = (student.name || 'Aluno').split(' ')[0];
    }
}

function toggleConditional(id, show) {
    const el = document.getElementById(id);
    if (!el) return;

    if (show) {
        el.classList.add('active');
    } else {
        el.classList.remove('active');
        const input = el.querySelector('input');
        if (input) input.value = ''; // clear when hidden
    }
}

function goToTrainerArea() {
    hideAllScreens();
    document.getElementById('trainer-login-screen').classList.add('active');
}

function goToTrainerCreate() {
    hideAllScreens();
    document.getElementById('trainer-create-screen').classList.add('active');
}

async function connectTrainer() {
    setTrainerEvaluationMode(false);
    const activeUser = await getSupabaseSessionUser();
    if (!activeUser || !isEmailConfirmed(activeUser)) {
        alert('Faça login com e-mail e senha antes de acessar o painel do treinador.');
        window.location.href = 'index.html';
        return;
    }

    const profile = await getProfileByUserId(activeUser.id);
    const roles = normalizeAppRoles(profile?.roles || activeUser?.user_metadata?.roles, profile?.role || activeUser?.user_metadata?.role);
    if (!roles.includes('trainer')) {
        alert('Seu usuário não tem permissão de treinador.');
        window.location.href = 'index.html';
        return;
    }

    let trainerCode = sanitizeCodeInput(profile?.trainer_code || memoryGetItem('currentTrainerCode') || '', 5);
    if (!trainerCode) trainerCode = await generateUniqueTrainerCode();

    const trainerName = sanitizeUserInput(profile?.name || activeUser?.user_metadata?.name || activeUser?.email || 'Treinador', { maxLen: 90 }) || 'Treinador';
    memorySetItem('trainerName', trainerName.split(' ')[0]);
    memorySetItem('currentTrainerCode', trainerCode);
    const profileRoles = normalizeAppRoles(profile?.roles, profile?.role || 'trainer');
    if (!profileRoles.includes('trainer')) profileRoles.unshift('trainer');
    await window.supabase
        .from('profiles')
        .update({ trainer_code: trainerCode, role: 'trainer', roles: profileRoles })
        .eq('id', activeUser.id);
    // Go to dashboard
    hideAllScreens();
    document.getElementById('app').classList.add('wide');
    document.getElementById('trainer-dashboard-screen').classList.add('active');
    await initTrainerDashboard();
}

async function createConsultoria() {
    const activeUser = await getSupabaseSessionUser();
    if (!activeUser) {
        alert('Faça login antes de criar sua consultoria.');
        window.location.href = 'index.html';
        return;
    }
    const profile = await getProfileByUserId(activeUser.id);
    const roles = normalizeAppRoles(profile?.roles || activeUser?.user_metadata?.roles, profile?.role || activeUser?.user_metadata?.role);
    if (!roles.includes('trainer')) {
        alert('Apenas treinadores podem criar consultoria.');
        return;
    }

    const name = sanitizeUserInput(document.getElementById('trainer-name')?.value, { maxLen: 90 });
    const nameInput = document.getElementById('trainer-name');
    if (nameInput) nameInput.value = name;
    const services = document.querySelector('input[name="services"]:checked');

    if (!name.trim() || !services) {
        alert('Preencha todos os dados corretamente.');
        return;
    }

    const firstName = sanitizeUserInput(name.split(' ')[0], { maxLen: 30 }) || 'Coach';
    const newCode = await generateUniqueTrainerCode();

    // Save trainer to "global" list
    const trainers = readStorageJSON('allTrainers', []);
    const trainerPayload = {
        name: name,
        code: newCode,
        consultoriaName: `Consultoria de ${firstName} `,
        services: services.value
    };
    trainers.push(trainerPayload);
    memorySetItem('allTrainers', JSON.stringify(trainers));

    if (isSupabaseReady()) {
        await ensureTrainerExistsRemote(
            newCode,
            trainerPayload.name,
            trainerPayload.consultoriaName
        );
    }

    memorySetItem('trainerName', firstName);
    memorySetItem('currentTrainerCode', newCode);

    document.getElementById('dash-trainer-name').innerText = firstName;
    document.getElementById('dash-trainer-code').innerText = newCode;

    // Go to dashboard
    hideAllScreens();
    document.getElementById('trainer-dashboard-screen').classList.add('active');
    await initTrainerDashboard();
}

// TRAINER DASHBOARD LOGIC (Runs on trainer.html)
async function initTrainerDashboard(options = {}) {
    if (options?.force) {
        trainerDashboardInitPromise = null;
    }
    if (trainerDashboardInitPromise) {
        return trainerDashboardInitPromise;
    }
    const dashboardScreen = document.getElementById('trainer-dashboard-screen');
    const dashboardAlreadyActive = !!dashboardScreen?.classList.contains('active');
    if (!options?.force && dashboardAlreadyActive && (Date.now() - trainerDashboardLastInitAt) < 280) {
        return;
    }

    trainerDashboardInitPromise = (async () => {
        try {
            setTrainerDashboardRuntimeFallback(false);
            migrateStoredStudentsDietSchema();

            const evaluationMode = isTrainerEvaluationModeActive();
            let sessionUser = null;
            let profile = null;
            let trainerNameResolved = EVALUATION_TRAINER_NAME;
            let trainerCodeResolved = EVALUATION_TRAINER_CODE;
            let trainerIdentity = null;

            if (evaluationMode) {
                const demoIdentity = ensureEvaluationDemoData();
                setRuntimeRoleForTestSwitch('trainer');
                trainerIdentity = await setCurrentTrainerIdentity(demoIdentity || buildEvaluationTrainerIdentity(), {
                    code: EVALUATION_TRAINER_CODE,
                    name: EVALUATION_TRAINER_NAME,
                    services: 'ambos'
                });
            } else {
                sessionUser = await getSupabaseSessionUser();
                if (!sessionUser) {
                    hideAllScreens();
                    const trainerLoginScreen = document.getElementById('trainer-login-screen');
                    if (trainerLoginScreen) trainerLoginScreen.classList.add('active');
                    syncEvaluationShortcutVisibility();
                    return true;
                }

                profile = await getProfileByUserId(sessionUser.id);
                const sessionRoles = normalizeAppRoles(profile?.roles || sessionUser?.user_metadata?.roles, profile?.role || sessionUser?.user_metadata?.role);
                if (!sessionRoles.includes('trainer')) {
                    alert('Acesso restrito ao treinador.');
                    window.location.href = 'index.html';
                    return true;
                }

                trainerNameResolved = sanitizeUserInput(profile?.name || sessionUser?.user_metadata?.name || memoryGetItem('trainerName') || 'Treinador', { maxLen: 90 }) || 'Treinador';
                trainerCodeResolved = sanitizeCodeInput(profile?.trainer_code || memoryGetItem('currentTrainerCode') || '', 5);
                if (!trainerCodeResolved) {
                    trainerCodeResolved = await generateUniqueTrainerCode();
                    const updateRoles = normalizeAppRoles(profile?.roles, profile?.role || 'trainer');
                    if (!updateRoles.includes('trainer')) updateRoles.unshift('trainer');
                    await window.supabase
                        .from('profiles')
                        .update({ trainer_code: trainerCodeResolved, role: 'trainer', roles: updateRoles })
                        .eq('id', sessionUser.id);
                }
                const resolvedIdentity = await resolveCurrentTrainerIdentity({
                    sessionUser,
                    trainerCode: trainerCodeResolved,
                    fallbackName: trainerNameResolved
                });
                trainerIdentity = await setCurrentTrainerIdentity(resolvedIdentity, {
                    code: trainerCodeResolved,
                    name: trainerNameResolved
                });
            }

            const trainerCode = sanitizeCodeInput(trainerIdentity?.code || trainerCodeResolved || '', 5) || '00000';
            const refreshTrainerFromRemote = async ({ showPendingFeedback = false } = {}) => {
                if (!trainerCode || trainerCode === '00000') return true;
                if (trainerDashboardManualRefreshPromise) {
                    return trainerDashboardManualRefreshPromise;
                }
                trainerDashboardManualRefreshPromise = (async () => {
                    if (showPendingFeedback) {
                        setStudentSyncState('pending', 'Atualizando dados...');
                    }
                    await syncStudentsFromSupabase(trainerCode);
                    return true;
                })()
                    .catch((error) => {
                        console.warn('Falha ao atualizar dados do treinador.', error);
                        if (showPendingFeedback) {
                            setStudentSyncState('error', 'Falha ao atualizar dados');
                        }
                        return false;
                    })
                    .finally(() => {
                        trainerDashboardManualRefreshPromise = null;
                    });
                return trainerDashboardManualRefreshPromise;
            };

            const dashboardScreen = document.getElementById('trainer-dashboard-screen');
            if (dashboardScreen) {
                hideAllScreens();
                const app = document.getElementById('app');
                if (app) app.classList.add('wide');
                dashboardScreen.classList.add('active');
            }

            loadTrainerSettingsToUI();
            applyTrainerDashboardStaticCopy();

            const root = document.getElementById('trainer-dashboard-screen');
            if (root && !root.dataset.menuInit) {
                root.addEventListener('click', (evt) => {
                    const menu = document.getElementById('trainer-profile-menu');
                    const triggers = Array.from(document.querySelectorAll('.profile-menu-trigger'));
                    if (!menu) return;
                    const clickedInsideMenu = menu.contains(evt.target);
                    const clickedTrigger = triggers.some((trigger) => trigger && trigger.contains(evt.target));
                    if (!clickedInsideMenu && !clickedTrigger) closeTrainerProfileMenu();
                });
                document.addEventListener('keydown', (evt) => {
                    if (evt.key === 'Escape') closeTrainerProfileMenu();
                });
                root.dataset.menuInit = '1';
            }

            const mobileProfileNavBtn = document.getElementById('m-nav-profile');
            if (mobileProfileNavBtn) {
                mobileProfileNavBtn.onclick = () => switchDashView('config', { focusProfileStudio: true });
            }

            const bootCycle = ++trainerDashboardBootCycle;
            setTrainerDashboardRuntimeFallback(false);
            runTrainerDashboardInitialRenderCycle(bootCycle);
            runDeferredTrainerDashboardBootTasks({
                evaluationMode,
                trainerCode,
                refreshTrainerFromRemote,
                cycle: bootCycle
            });
            return true;
        } catch (error) {
            console.error('Falha ao iniciar painel do treinador.', error);
            setTrainerDashboardRuntimeFallback(true, 'Falha ao carregar o painel. Verifique sua conexão e tente novamente.');
            return false;
        }
    })()
        .finally(() => {
            trainerDashboardLastInitAt = Date.now();
            trainerDashboardInitPromise = null;
        });

    return trainerDashboardInitPromise;
}

function getTrainerSettingsScopedKey() {
    const currentUserId = String(memoryGetItem('currentUserId') || '').trim();
    if (currentUserId) return `${TRAINER_SETTINGS_KEY}:${currentUserId}`;
    const trainerCode = sanitizeCodeInput(
        memoryGetItem('currentTrainerCode') || memoryGetItem('trainerCodeDefault') || '',
        5
    );
    if (trainerCode) return `${TRAINER_SETTINGS_KEY}:${trainerCode}`;
    return TRAINER_SETTINGS_KEY;
}

function readTrainerSettingsByKey(key) {
    const value = readStorageJSON(key, null);
    if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
    return value;
}

function loadTrainerSettings() {
    const defaults = {
        displayName: '',
        consultoriaName: '',
        headline: '',
        handle: '',
        bio: '',
        services: 'treino',
        specialties: [],
        socialLinks: { instagram: '', whatsapp: '', website: '' },
        paymentSettings: {
            enabled: false,
            recipientName: '',
            monthlyAmountDefault: '',
            pixCopyPaste: '',
            pixQrImage: '',
            instructions: ''
        },
        ctaLabel: '',
        ctaUrl: '',
        themePreset: TRAINER_THEME_PRESETS[0],
        unitSystem: 'metric',
        macroFormula: 'mifflin',
        notifyEmail: true,
        notifyPush: true,
        studentLimit: '',
        profilePhoto: '',
        profileCover: '',
        brandLogo: '',
        billingStartDate: '',
        billingMonthlyAmount: '',
        billingCurrentStatus: 'pendente',
        billingCurrentPaidAt: '',
        billingNotes: '',
        billingHistory: []
    };
    const scopedKey = getTrainerSettingsScopedKey();
    const trainerCode = sanitizeCodeInput(
        memoryGetItem('currentTrainerCode') || memoryGetItem('trainerCodeDefault') || '',
        5
    );
    const fallbackKeys = [];
    fallbackKeys.push(scopedKey);
    if (trainerCode) fallbackKeys.push(`${TRAINER_SETTINGS_KEY}:${trainerCode}`);
    fallbackKeys.push(TRAINER_SETTINGS_KEY);

    let stored = null;
    let sourceKey = '';
    fallbackKeys.forEach((key) => {
        if (stored) return;
        const candidate = readTrainerSettingsByKey(key);
        if (candidate) {
            stored = candidate;
            sourceKey = key;
        }
    });

    if (!stored) stored = {};
    if (sourceKey && sourceKey !== scopedKey && scopedKey !== TRAINER_SETTINGS_KEY) {
        memorySetItem(scopedKey, JSON.stringify(stored));
    }

    const specialties = Array.isArray(stored.specialties) ? stored.specialties : [];
    const socialLinks = normalizeTrainerSocialLinks(stored.socialLinks || {});
    const paymentSettings = normalizeTrainerPaymentSettings(
        stored.paymentSettings || extractTrainerPaymentSettingsFromSocialLinks(stored.socialLinks || {})
    );
    const billingHistory = Array.isArray(stored.billingHistory) ? stored.billingHistory : [];
    const services = normalizeTrainerServices(stored.services || defaults.services);
    const themePreset = normalizeTrainerThemePreset(stored.themePreset || defaults.themePreset);
    const ctaLabel = sanitizeUserInput(stored.ctaLabel || '', { maxLen: 80 });
    const ctaUrl = sanitizeStrictUrl(stored.ctaUrl || '', { maxLen: 320, allowStorage: false });
    const profilePhoto = typeof stored.profilePhoto === 'string' ? stored.profilePhoto : '';
    const profileCover = typeof stored.profileCover === 'string' ? stored.profileCover : '';
    const brandLogo = typeof stored.brandLogo === 'string' ? stored.brandLogo : '';
    return {
        ...defaults,
        ...stored,
        services,
        themePreset,
        ctaLabel,
        ctaUrl,
        profilePhoto,
        profileCover,
        brandLogo,
        specialties,
        socialLinks,
        paymentSettings,
        billingHistory
    };
}

function updateTrainerSettings(partial) {
    const current = loadTrainerSettings();
    const next = { ...current, ...partial };
    memorySetItem(getTrainerSettingsScopedKey(), JSON.stringify(next));
    return next;
}

async function getLoggedTrainerUserRecord() {
    const sessionUser = await getSupabaseSessionUser();
    if (!sessionUser) return null;
    const profile = await getProfileByUserId(sessionUser.id);
    const roles = normalizeAppRoles(profile?.roles || sessionUser?.user_metadata?.roles, profile?.role || sessionUser?.user_metadata?.role);
    if (!roles.includes('trainer')) return null;
    return { sessionUser, profile };
}

function setTrainerPasswordFeedback(message, type = '') {
    const feedback = document.getElementById('trainer-password-feedback');
    if (!feedback) return;
    feedback.textContent = message || '';
    feedback.classList.remove('success', 'error');
    if (type) feedback.classList.add(type);
}

async function changeTrainerPassword() {
    const currentPass = document.getElementById('trainer-current-password')?.value || '';
    const nextPass = document.getElementById('trainer-new-password')?.value || '';
    const confirmPass = document.getElementById('trainer-confirm-password')?.value || '';

    const loginRecord = await getLoggedTrainerUserRecord();
    if (!loginRecord) {
        setTrainerPasswordFeedback('Nao foi possivel identificar a conta do treinador logado.', 'error');
        return;
    }
    if (!currentPass || !nextPass || !confirmPass) {
        setTrainerPasswordFeedback('Preencha senha atual, nova senha e confirmacao.', 'error');
        return;
    }
    const hasLetter = /[A-Za-z]/.test(nextPass);
    const hasNumber = /\d/.test(nextPass);
    if (nextPass.length < 8 || !hasLetter || !hasNumber) {
        setTrainerPasswordFeedback('A nova senha precisa ter no minimo 8 caracteres com letras e numeros.', 'error');
        return;
    }
    if (nextPass !== confirmPass) {
        setTrainerPasswordFeedback('A confirmacao da nova senha nao confere.', 'error');
        return;
    }

    if (typeof window.supabase?.auth?.signInWithPassword !== 'function') {
        setTrainerPasswordFeedback('Supabase Auth indisponivel.', 'error');
        return;
    }

    const email = sanitizeEmailInput(loginRecord.sessionUser?.email || '');
    const reauth = await window.supabase.auth.signInWithPassword({
        email,
        password: currentPass
    });
    if (reauth?.error) {
        setTrainerPasswordFeedback('A senha atual esta incorreta.', 'error');
        return;
    }

    const { error: updateError } = await window.supabase.auth.updateUser({
        password: nextPass
    });
    if (updateError) {
        setTrainerPasswordFeedback(updateError.message || 'Nao foi possivel alterar a senha.', 'error');
        return;
    }

    setTrainerPasswordFeedback('Senha alterada com sucesso.', 'success');

    const currentInput = document.getElementById('trainer-current-password');
    const newInput = document.getElementById('trainer-new-password');
    const confirmInput = document.getElementById('trainer-confirm-password');
    if (currentInput) currentInput.value = '';
    if (newInput) newInput.value = '';
    if (confirmInput) confirmInput.value = '';
    handleTrainerPasswordInputFeedback();
}

function parseISODateSafe(value) {
    if (!value) return null;
    const date = new Date(`${value}T00:00:00`);
    if (Number.isNaN(date.getTime())) return null;
    return date;
}

function formatCompetence(date) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    return `${year}-${month}`;
}

function getConsultoriaMonthIndex(startDate, refDate = new Date()) {
    if (!startDate) return 0;
    const months = (refDate.getFullYear() - startDate.getFullYear()) * 12 + (refDate.getMonth() - startDate.getMonth());
    return months >= 0 ? months + 1 : 0;
}

function getNextBillingDueDate(startDate, monthIndex) {
    if (!startDate || monthIndex <= 0) return null;
    const due = new Date(startDate);
    due.setMonth(due.getMonth() + monthIndex);
    return due;
}

function formatPtDate(date) {
    if (!date) return '-';
    return date.toLocaleDateString('pt-BR');
}

function normalizeBillingStatus(status) {
    if (status === 'pago' || status === 'atrasado' || status === 'pendente') return status;
    return 'pendente';
}

function setSettingsSavebarState(state = 'clean', customMessage = '') {
    studentConfigSaveState = state;
    const bar = document.getElementById('settings-sticky-savebar');
    const label = document.getElementById('settings-savebar-status');
    const btn = document.getElementById('settings-savebar-btn');
    if (!bar || !label || !btn) return;

    const map = {
        clean: 'Sem alterações pendentes',
        dirty: 'Alterações pendentes nesta configuração',
        saving: 'Salvando alterações...',
        saved: 'Tudo salvo com sucesso',
        error: 'Erro ao salvar. Tente novamente'
    };
    bar.dataset.state = state;
    label.textContent = customMessage || map[state] || map.clean;

    if (state === 'saving') {
        btn.disabled = true;
        btn.innerHTML = '<i class="ph-bold ph-spinner-gap"></i> Salvando...';
    } else if (state === 'saved') {
        btn.disabled = false;
        btn.innerHTML = '<i class="ph-bold ph-check"></i> Salvo';
    } else if (state === 'error') {
        btn.disabled = false;
        btn.innerHTML = '<i class="ph-bold ph-warning-circle"></i> Tentar novamente';
    } else {
        btn.disabled = false;
        btn.innerHTML = '<i class="ph-bold ph-floppy-disk"></i> Salvar Alterações';
    }
    setTopSaveButtonState(state);
}

function setTopSaveButtonState(state = 'clean') {
    document.querySelectorAll('.btn-save-plan').forEach((btn) => {
        btn.classList.remove('is-dirty', 'is-saving', 'is-saved', 'is-error');
        if (state === 'dirty') {
            btn.classList.add('is-dirty');
            btn.innerHTML = '<i class="ph-bold ph-floppy-disk"></i> Salvar Alterações';
            return;
        }
        if (state === 'saving') {
            btn.classList.add('is-saving');
            btn.innerHTML = '<i class="ph-bold ph-spinner-gap"></i> Salvando...';
            return;
        }
        if (state === 'saved') {
            btn.classList.add('is-saved');
            btn.innerHTML = '<i class="ph-bold ph-check"></i> Salvo';
            return;
        }
        if (state === 'error') {
            btn.classList.add('is-error');
            btn.innerHTML = '<i class="ph-bold ph-warning-circle"></i> Tentar novamente';
            return;
        }
        btn.innerHTML = '<i class="ph-bold ph-floppy-disk"></i> Salvar Alterações';
    });
}

function markStudentConfigDirty() {
    studentConfigDirty = true;
    setSettingsSavebarState('dirty');
}

function signalStudentPlanDirty() {
    trainerPlanEditRevision += 1;
    markStudentConfigDirty();
    queueStudentPlanLocalAutosave(520);
    renderTrainerDemoStudentPreview();
}

function clearStudentConfigDirty() {
    studentConfigDirty = false;
    setSettingsSavebarState('clean');
    renderTrainerDemoStudentPreview();
}

function setStudentBillingInlineFeedback(message, type = '') {
    const el = document.getElementById('student-billing-inline-feedback');
    if (!el) return;
    el.classList.remove('success', 'error', 'info');
    if (type) el.classList.add(type);
    el.textContent = message || '';
}

function togglePasswordVisibility(inputId, btn) {
    const input = document.getElementById(inputId);
    if (!input || !btn) return;
    const isPassword = input.type === 'password';
    input.type = isPassword ? 'text' : 'password';
    btn.innerHTML = isPassword ? '<i class="ph-bold ph-eye-slash"></i>' : '<i class="ph-bold ph-eye"></i>';
}

function handleTrainerPasswordInputFeedback() {
    const nextPass = document.getElementById('trainer-new-password')?.value || '';
    const confirmPass = document.getElementById('trainer-confirm-password')?.value || '';
    const hint = document.getElementById('trainer-password-hint');
    if (!hint) return;
    const hasLetter = /[A-Za-z]/.test(nextPass);
    const hasNumber = /\d/.test(nextPass);
    if (!nextPass) {
        hint.textContent = 'Use pelo menos 8 caracteres com letras e números.';
        return;
    }
    if (nextPass.length < 8 || !hasLetter || !hasNumber) {
        hint.textContent = 'Senha fraca: inclua letras, números e mínimo de 8 caracteres.';
        return;
    }
    if (confirmPass && nextPass !== confirmPass) {
        hint.textContent = 'A confirmação ainda não corresponde à nova senha.';
        return;
    }
    hint.textContent = 'Senha forte. Você pode confirmar a alteração.';
}

function initStudentConfigUXBindings() {
    if (document.documentElement.dataset.studentConfigUxBound === '1') return;
    const fields = [
        'student-billing-start-date',
        'student-billing-current-status',
        'student-billing-monthly-amount',
        'student-billing-current-paid-at',
        'student-billing-notes'
    ];
    fields.forEach((id) => {
        const el = document.getElementById(id);
        if (!el) return;
        const evt = el.tagName === 'SELECT' ? 'change' : 'input';
        el.addEventListener(evt, () => {
            markStudentConfigDirty();
            if (id === 'student-billing-current-status' || id === 'student-billing-start-date') refreshStudentBillingSummaryUI();
        });
    });
    document.documentElement.dataset.studentConfigUxBound = '1';
}

function getStudentBillingData(student = {}) {
    return {
        billingStartDate: sanitizeUserInput(student?.billingStartDate || '', { maxLen: 10 }),
        billingMonthlyAmount: sanitizeUserInput(student?.billingMonthlyAmount || '', { maxLen: 14 }),
        billingCurrentStatus: normalizeBillingStatus(student?.billingCurrentStatus || 'pendente'),
        billingCurrentPaidAt: sanitizeUserInput(student?.billingCurrentPaidAt || '', { maxLen: 10 }),
        billingNotes: sanitizeUserInput(student?.billingNotes || '', { allowNewlines: true, maxLen: 400 }),
        billingHistory: Array.isArray(student?.billingHistory) ? student.billingHistory : []
    };
}

function getLegacyTrainerBillingFallback() {
    const settings = loadTrainerSettings();
    if (!settings) return null;
    const hasAnyLegacyField = !!(settings.billingStartDate || settings.billingMonthlyAmount || settings.billingCurrentPaidAt || settings.billingNotes
        || (Array.isArray(settings.billingHistory) && settings.billingHistory.length));
    if (!hasAnyLegacyField) return null;
    return {
        billingStartDate: settings.billingStartDate || '',
        billingMonthlyAmount: settings.billingMonthlyAmount || '',
        billingCurrentStatus: normalizeBillingStatus(settings.billingCurrentStatus || 'pendente'),
        billingCurrentPaidAt: settings.billingCurrentPaidAt || '',
        billingNotes: settings.billingNotes || '',
        billingHistory: Array.isArray(settings.billingHistory) ? settings.billingHistory : []
    };
}

function normalizeBillingHistoryItem(item = {}) {
    return {
        competence: sanitizeUserInput(item.competence || '', { maxLen: 7 }),
        status: normalizeBillingStatus(item.status || 'pendente'),
        paidAt: item.paidAt || '',
        updatedAt: item.updatedAt || ''
    };
}

function getStudentBillingSnapshot(student, refDate = new Date()) {
    const billing = getStudentBillingData(student);
    const startDate = parseISODateSafe(billing.billingStartDate);
    const monthIndex = getConsultoriaMonthIndex(startDate, refDate);
    const nextDue = getNextBillingDueDate(startDate, monthIndex);
    const status = normalizeBillingStatus(billing.billingCurrentStatus || 'pendente');
    const statusLabel = status.charAt(0).toUpperCase() + status.slice(1);
    return {
        ...billing,
        startDate,
        monthIndex,
        monthLabel: monthIndex > 0 ? `${monthIndex}º mês` : 'Não iniciado',
        nextDue,
        nextDueLabel: nextDue ? formatPtDate(nextDue) : '-',
        status,
        statusLabel
    };
}

function getBillingBadgeClass(status) {
    if (status === 'pago') return 'success';
    if (status === 'atrasado') return 'danger';
    return 'warning';
}

function getBillingSummaryBadge(snapshot) {
    const month = snapshot?.monthIndex > 0 ? `${snapshot.monthIndex}º mês` : 'Sem início';
    const status = snapshot?.statusLabel || 'Pendente';
    return `${month} · ${status}`;
}

function renderBillingHistory(history) {
    const list = document.getElementById('student-billing-history-list');
    if (!list) return;
    const safeHistory = Array.isArray(history) ? history : [];
    if (safeHistory.length === 0) {
        list.innerHTML = '<div class="settings-history-row empty"><span>Nenhum evento de pagamento registrado.</span></div>';
        return;
    }
    const monthFilter = document.getElementById('student-billing-history-month')?.value || '';
    const yearFilter = document.getElementById('student-billing-history-year')?.value || '';
    const sorted = [...safeHistory]
        .map(normalizeBillingHistoryItem)
        .filter((item) => {
            const [year = '', month = ''] = String(item.competence || '').split('-');
            if (yearFilter && year !== yearFilter) return false;
            if (monthFilter && month !== monthFilter) return false;
            return true;
        })
        .sort((a, b) => String(b?.competence || '').localeCompare(String(a?.competence || '')));
    if (sorted.length === 0) {
        list.innerHTML = '<div class="settings-history-row empty"><span>Nenhum registro encontrado com os filtros atuais.</span></div>';
        return;
    }
    list.innerHTML = sorted.slice(0, 12).map((item) => {
        const status = normalizeBillingStatus(item?.status);
        const paidAt = item?.paidAt ? formatPtDate(new Date(item.paidAt)) : '-';
        return `
            <div class="settings-history-row">
                <span>${escapeHTML(item?.competence || '-')}</span>
                <span>${paidAt}</span>
                <span class="status ${status}">${status}</span>
            </div>
        `;
    }).join('');
}

function renderTrainerAnamnesisTab(student = {}) {
    const container = document.getElementById('trainer-anamnesis-content');
    if (!container) return;
    const anamnesis = getStudentAnamnesisSource(student || {});
    if (!anamnesis || typeof anamnesis !== 'object') {
        container.innerHTML = `
            <div class="empty-state-card active" style="margin-top:0;border:none;">
                <i class="ph-fill ph-clipboard-text" style="color:var(--text-muted)"></i>
                <div class="empty-info">
                    <h3>Anamnese não encontrada</h3>
                    <p>O aluno ainda não finalizou o questionário completo.</p>
                </div>
            </div>
        `;
        return;
    }

    const boolMap = { sim: 'Sim', nao: 'Não' };
    const condicoesMap = {
        diabetes: 'Diabetes',
        hipertensao: 'Hipertensão',
        sopro: 'Sopro cardíaco',
        asma: 'Asma',
        artrite: 'Artrite',
        hernia: 'Hérnia de disco'
    };
    const restricoesMap = {
        lactose: 'Lactose',
        gluten: 'Glúten',
        amendoim: 'Amendoim',
        frutos_mar: 'Frutos do mar',
        ovo: 'Ovo',
        soja: 'Soja'
    };
    const diasMap = {
        seg: 'Segunda',
        ter: 'Terça',
        qua: 'Quarta',
        qui: 'Quinta',
        sex: 'Sexta',
        sab: 'Sábado',
        dom: 'Domingo'
    };
    const fumoMap = { nao: 'Não fuma', ocasional: 'Ocasional', diario: 'Diário' };
    const alcoolMap = { nao: 'Não bebe', fds: 'Fim de semana', diario: 'Diário' };
    const trabalhoMap = { sentado: 'Sentado', em_pe: 'Em pé', movimento: 'Em movimento' };
    const refeicoesMap = { '2': '2 refeições', '3': '3 refeições', '4': '4 refeições', '5': '5 refeições', '6': '6 refeições' };
    const duracaoMap = { '30': '30 minutos', '45': '45 minutos', '60': '60 minutos', '75': '75 minutos', '90': '90 minutos' };

    const toText = (value, fallback = 'Não informado') => {
        const safe = sanitizeUserInput(value || '', { allowNewlines: true, maxLen: 320 }).trim();
        return safe || fallback;
    };
    const mapValue = (value, dictionary = {}, fallback = 'Não informado') => {
        const raw = sanitizeUserInput(value || '', { maxLen: 120 }).trim().toLowerCase();
        if (!raw) return fallback;
        return dictionary[raw] || toText(raw, fallback);
    };
    const listValue = (value, dictionary = {}, fallback = 'Não informado') => {
        const items = Array.isArray(value) ? value : [];
        if (!items.length) return fallback;
        const normalized = items
            .map((entry) => mapValue(entry, dictionary, ''))
            .filter(Boolean);
        return normalized.length ? normalized.join(', ') : fallback;
    };
    const yesNo = (value, fallback = 'Não informado') => mapValue(value, boolMap, fallback);
    const formatValueHtml = (value = '') => escHtml(String(value || '')).replace(/\n/g, '<br>');

    const saude = anamnesis.saude || {};
    const nutricao = anamnesis.nutricao || {};
    const rotina = anamnesis.rotina || {};
    const treino = anamnesis.treino || {};
    const metas = anamnesis.metas || {};

    const sections = [
        {
            title: 'Saúde',
            rows: [
                { label: 'Dor em articulações', value: yesNo(saude.dor) },
                { label: 'Quais dores', value: toText(saude.dor_desc, saude.dor === 'sim' ? 'Não informado' : 'Sem dor relatada') },
                { label: 'Condições médicas', value: listValue(saude.condicoes, condicoesMap, 'Nenhuma condição marcada') },
                { label: 'Uso de medicação contínua', value: yesNo(saude.med) },
                { label: 'Quais medicamentos', value: toText(saude.med_desc, saude.med === 'sim' ? 'Não informado' : 'Não usa') },
                { label: 'Já fez cirurgia', value: yesNo(saude.cirurgia) },
                { label: 'Detalhes da cirurgia', value: toText(saude.cirurgia_desc, saude.cirurgia === 'sim' ? 'Não informado' : 'Nenhuma cirurgia informada') }
            ]
        },
        {
            title: 'Nutrição',
            rows: [
                { label: 'Restrições alimentares', value: listValue(nutricao.restricoes, restricoesMap, 'Nenhuma restrição marcada') },
                { label: 'Alimentos que evita', value: toText(nutricao.nao_come) },
                { label: 'Intestino regular', value: yesNo(nutricao.intestino) },
                { label: 'Refeições por dia', value: mapValue(nutricao.refeicoes, refeicoesMap) }
            ]
        },
        {
            title: 'Rotina',
            rows: [
                { label: 'Horas de sono', value: rotina.sono ? `${toText(rotina.sono)} h` : 'Não informado' },
                { label: 'Acorda descansado', value: yesNo(rotina.descansado) },
                { label: 'Nível de estresse', value: rotina.estresse ? `${toText(rotina.estresse)}/10` : 'Não informado' },
                { label: 'Tabagismo', value: mapValue(rotina.fumo, fumoMap) },
                { label: 'Consumo de álcool', value: mapValue(rotina.alcool, alcoolMap) },
                { label: 'Estilo de trabalho', value: mapValue(rotina.trabalho, trabalhoMap) }
            ]
        },
        {
            title: 'Treino',
            rows: [
                { label: 'Tempo de prática', value: toText(treino.tempo_pratica) },
                { label: 'Exercícios que gosta', value: toText(treino.exercicios_ama) },
                { label: 'Exercícios que não gosta', value: toText(treino.exercicios_detesta) },
                { label: 'Dias disponíveis', value: listValue(treino.dias, diasMap) },
                { label: 'Duração da sessão', value: mapValue(treino.duracao, duracaoMap) }
            ]
        },
        {
            title: 'Metas',
            rows: [
                { label: 'O que mais incomoda', value: toText(metas.incomoda) },
                { label: 'Objetivo em 3 meses', value: toText(metas.objetivo_3_meses) },
                { label: 'Experiência com consultoria', value: toText(metas.consultoria_antes) }
            ]
        }
    ];

    container.innerHTML = `
        <div class="trainer-anamnesis-grid">
            ${sections.map((section) => `
                <article class="trainer-anamnesis-section">
                    <header class="trainer-anamnesis-section-head">
                        <h4>${escHtml(section.title)}</h4>
                    </header>
                    <div class="trainer-anamnesis-rows">
                        ${(section.rows || []).map((row) => `
                            <div class="trainer-anamnesis-row">
                                <span class="trainer-anamnesis-row-label">${escHtml(row.label || '')}</span>
                                <strong class="trainer-anamnesis-row-value">${formatValueHtml(row.value || 'Não informado')}</strong>
                            </div>
                        `).join('')}
                    </div>
                </article>
            `).join('')}
        </div>
    `;
}

function getTrainerPaymentRequestStatusClass(status = '') {
    const normalized = normalizePaymentRequestStatus(status);
    if (normalized === 'aprovado') return 'approved';
    if (normalized === 'recusado') return 'rejected';
    return 'pending';
}

function renderStudentPaymentRequestsForTrainer(student = {}) {
    const container = document.getElementById('student-payment-requests-list');
    if (!container) return;
    const requests = normalizeStudentPaymentRequests(student?.paymentRequests || student?.payment_requests || []);
    if (!requests.length) {
        container.innerHTML = '<div class="settings-payment-request-empty">Nenhuma solicitação enviada pelo aluno até agora.</div>';
        return;
    }

    container.innerHTML = requests.map((request) => {
        const statusClass = getTrainerPaymentRequestStatusClass(request.status);
        const requestIdEncoded = encodeURIComponent(String(request.id || ''));
        const requestedAt = formatStudentDateLabel(request.requestedAt);
        const reviewedAt = request.reviewedAt ? formatStudentDateLabel(request.reviewedAt) : '--';
        const amountLabel = request.amount ? formatStudentCurrencyBRL(request.amount) : 'Não informado';
        return `
            <div class="settings-payment-request-row state-${statusClass}">
                <div class="settings-payment-request-head">
                    <strong>${escHtml(formatStudentCompetenceLabel(request.competence || '') || '--')}</strong>
                    <span class="settings-payment-request-status ${statusClass}">${escHtml(getPaymentRequestStatusLabel(request.status))}</span>
                </div>
                <div class="settings-payment-request-meta">
                    <span>Valor: ${escHtml(amountLabel)}</span>
                    <span>Solicitado em: ${escHtml(requestedAt)}</span>
                    <span>Revisado em: ${escHtml(reviewedAt)}</span>
                </div>
                ${request.reviewNote ? `<p class="settings-payment-request-note">${escHtml(request.reviewNote)}</p>` : ''}
                ${request.status === 'aguardando_confirmacao' ? `
                    <div class="settings-payment-request-actions">
                        <button class="btn-secondary btn-sm settings-local-btn" type="button" onclick="reviewStudentPaymentRequest('${requestIdEncoded}','aprovado')">
                            <i class="ph-bold ph-check-circle"></i> Confirmar
                        </button>
                        <button class="btn-secondary btn-sm settings-local-btn danger" type="button" onclick="reviewStudentPaymentRequest('${requestIdEncoded}','recusado')">
                            <i class="ph-bold ph-x-circle"></i> Recusar
                        </button>
                    </div>
                ` : ''}
            </div>
        `;
    }).join('');
}

function reviewStudentPaymentRequest(requestIdEncoded = '', decision = 'aprovado') {
    const requestId = decodeURIComponent(String(requestIdEncoded || '').trim());
    if (!requestId) return;
    const targetDecision = String(decision || '').toLowerCase() === 'recusado' ? 'recusado' : 'aprovado';
    const selection = resolveCurrentTrainerStudentSelection();
    if (selection.idx < 0 || !selection.student) return;

    const students = selection.students;
    const student = { ...(students[selection.idx] || {}) };
    const requests = normalizeStudentPaymentRequests(student.paymentRequests || student.payment_requests || []);
    const requestIdx = requests.findIndex((request) => String(request?.id || '') === requestId);
    if (requestIdx < 0) {
        setStudentBillingInlineFeedback('Solicitação não encontrada para revisão.', 'error');
        return;
    }
    if (requests[requestIdx].status !== 'aguardando_confirmacao') {
        setStudentBillingInlineFeedback('Essa solicitação já foi revisada.', 'info');
        return;
    }

    const nowIso = new Date().toISOString();
    const note = targetDecision === 'aprovado'
        ? 'Pagamento confirmado pelo treinador.'
        : 'Solicitação recusada pelo treinador.';
    requests[requestIdx] = normalizeStudentPaymentRequest({
        ...requests[requestIdx],
        status: targetDecision,
        reviewedAt: nowIso,
        reviewNote: note
    });

    student.paymentRequests = requests;
    student.payment_requests = requests;

    if (targetDecision === 'aprovado') {
        const request = requests[requestIdx];
        const history = Array.isArray(student.billingHistory) ? [...student.billingHistory] : [];
        const competence = sanitizeUserInput(request.competence || '', { maxLen: 7 });
        if (competence) {
            const historyEntry = normalizeBillingHistoryItem({
                competence,
                status: 'pago',
                paidAt: nowIso,
                updatedAt: nowIso
            });
            const historyIdx = history.findIndex((item) => String(item?.competence || '') === competence);
            if (historyIdx >= 0) history[historyIdx] = { ...history[historyIdx], ...historyEntry };
            else history.push(historyEntry);
        }
        student.billingHistory = history;
        student.billingCurrentStatus = 'pago';
        student.billingCurrentPaidAt = nowIso.slice(0, 10);
        if (!sanitizePixAmountText(student.billingMonthlyAmount || '') && request.amount) {
            student.billingMonthlyAmount = sanitizePixAmountText(request.amount);
        }
    }

    students[selection.idx] = student;
    currentStudentIdx = selection.idx;
    currentTrainerStudentId = String(student.id || currentTrainerStudentId || '');
    saveStudentData(students, { studentId: String(student.id || '') });
    loadStudentBillingConfigTab(student, { preserveDirty: true });
    setStudentBillingInlineFeedback(
        targetDecision === 'aprovado'
            ? 'Solicitação confirmada e financeiro atualizado.'
            : 'Solicitação recusada.',
        targetDecision === 'aprovado' ? 'success' : 'info'
    );
    updateTrainerStats(document.getElementById('alunos-search')?.value || document.getElementById('global-search')?.value || '');
}

function refreshBillingSummaryUI() {
    refreshStudentBillingSummaryUI();
}

function refreshStudentBillingSummaryUI() {
    const startValue = document.getElementById('student-billing-start-date')?.value || '';
    const statusValue = normalizeBillingStatus(document.getElementById('student-billing-current-status')?.value || 'pendente');
    const monthLabel = document.getElementById('student-billing-month-label');
    const statusLabel = document.getElementById('student-billing-status-label');
    const dueLabel = document.getElementById('student-billing-next-due-label');
    const summaryCard = document.getElementById('student-billing-summary-card');
    const startDate = parseISODateSafe(startValue);
    const monthIndex = getConsultoriaMonthIndex(startDate);
    if (monthLabel) monthLabel.textContent = monthIndex > 0 ? `${monthIndex}º mês` : 'Não iniciado';
    if (statusLabel) statusLabel.textContent = statusValue.charAt(0).toUpperCase() + statusValue.slice(1);
    if (summaryCard) summaryCard.dataset.state = statusValue;

    const nextDue = getNextBillingDueDate(startDate, monthIndex);
    if (dueLabel) dueLabel.textContent = nextDue ? formatPtDate(nextDue) : '-';
}

function markCurrentBillingCyclePaid() {
    markCurrentStudentBillingCyclePaid();
}

function markCurrentStudentBillingCyclePaid() {
    const selection = resolveCurrentTrainerStudentSelection();
    if (selection.idx < 0 || !selection.student) return;
    const payBtn = document.getElementById('student-billing-pay-btn');
    if (payBtn) {
        payBtn.disabled = true;
        payBtn.innerHTML = '<i class="ph-bold ph-spinner-gap"></i> Marcando...';
    }
    setStudentBillingInlineFeedback('Atualizando status do ciclo...', 'info');
    try {
        const startValue = document.getElementById('student-billing-start-date')?.value || '';
        const startDate = parseISODateSafe(startValue);
        if (!startDate) {
            setStudentBillingInlineFeedback('Defina a data de início da consultoria para continuar.', 'error');
            return;
        }
        const monthIndex = getConsultoriaMonthIndex(startDate);
        if (monthIndex <= 0) {
            setStudentBillingInlineFeedback('A data de início ainda não permite registrar o ciclo atual.', 'error');
            return;
        }

        const today = new Date();
        const competenceDate = new Date(startDate);
        competenceDate.setMonth(competenceDate.getMonth() + (monthIndex - 1));
        const competence = formatCompetence(competenceDate);

        const students = selection.students;
        const student = students[selection.idx];
        if (!student) return;
        const current = getStudentBillingData(student);
        const history = Array.isArray(current.billingHistory) ? [...current.billingHistory] : [];
        const existingIdx = history.findIndex((item) => item?.competence === competence);
        const entry = {
            competence,
            status: 'pago',
            paidAt: today.toISOString(),
            updatedAt: today.toISOString()
        };
        if (existingIdx >= 0) {
            history[existingIdx] = { ...history[existingIdx], ...entry };
        } else {
            history.push(entry);
        }

        const paidDateInput = document.getElementById('student-billing-current-paid-at');
        if (paidDateInput && !paidDateInput.value) {
            const yyyy = today.getFullYear();
            const mm = String(today.getMonth() + 1).padStart(2, '0');
            const dd = String(today.getDate()).padStart(2, '0');
            paidDateInput.value = `${yyyy}-${mm}-${dd}`;
        }

        student.billingCurrentStatus = 'pago';
        student.billingCurrentPaidAt = paidDateInput?.value || '';
        student.billingHistory = history;
        students[selection.idx] = student;
        currentStudentIdx = selection.idx;
        currentTrainerStudentId = String(student.id || currentTrainerStudentId || '');
        saveStudentData(students, { studentId: String(student.id || '') });
        loadStudentBillingConfigTab(student);
        setStudentBillingInlineFeedback('Ciclo atualizado como pago com sucesso.', 'success');
        updateTrainerStats(document.getElementById('alunos-search')?.value || document.getElementById('global-search')?.value || '');
    } catch (error) {
        console.error('Failed to mark billing cycle paid', error);
        setStudentBillingInlineFeedback('Erro ao atualizar ciclo. Tente novamente.', 'error');
    } finally {
        if (payBtn) {
            payBtn.disabled = false;
            payBtn.textContent = 'Marcar ciclo como pago';
        }
    }
}

function populateStudentBillingYearFilter(history = []) {
    const select = document.getElementById('student-billing-history-year');
    if (!select) return;
    const currentValue = select.value || '';
    const years = Array.from(new Set((history || [])
        .map((item) => String(item?.competence || '').split('-')[0])
        .filter((year) => /^\d{4}$/.test(year))))
        .sort((a, b) => Number(b) - Number(a));
    select.innerHTML = `<option value="">Todos os anos</option>${years.map((year) => `<option value="${year}">${year}</option>`).join('')}`;
    if (currentValue && years.includes(currentValue)) select.value = currentValue;
}

function clearStudentBillingHistoryFilters() {
    const month = document.getElementById('student-billing-history-month');
    const year = document.getElementById('student-billing-history-year');
    if (month) month.value = '';
    if (year) year.value = '';
    applyStudentBillingHistoryFilters();
}

function applyStudentBillingHistoryFilters() {
    if (currentStudentIdx === null) return;
    const students = readStorageJSON('trainerStudents', []);
    const student = students[currentStudentIdx];
    if (!student) return;
    const billing = getStudentBillingData(student);
    renderBillingHistory(billing.billingHistory);
}

function loadStudentBillingConfigTab(student = {}, options = {}) {
    let billing = getStudentBillingData(student);
    const hasStudentBilling = !!(billing.billingStartDate || billing.billingMonthlyAmount || billing.billingCurrentPaidAt || billing.billingNotes || (billing.billingHistory || []).length);
    if (!hasStudentBilling) {
        const legacy = getLegacyTrainerBillingFallback();
        if (legacy) billing = { ...billing, ...legacy };
    }
    const start = document.getElementById('student-billing-start-date');
    if (start) start.value = billing.billingStartDate || '';
    const status = document.getElementById('student-billing-current-status');
    if (status) status.value = normalizeBillingStatus(billing.billingCurrentStatus);
    const amount = document.getElementById('student-billing-monthly-amount');
    if (amount) amount.value = billing.billingMonthlyAmount || '';
    const paidAt = document.getElementById('student-billing-current-paid-at');
    if (paidAt) paidAt.value = billing.billingCurrentPaidAt || '';
    const notes = document.getElementById('student-billing-notes');
    if (notes) notes.value = billing.billingNotes || '';
    populateStudentBillingYearFilter(billing.billingHistory);
    renderBillingHistory(billing.billingHistory);
    renderStudentPaymentRequestsForTrainer(student);
    refreshStudentBillingSummaryUI();
    setStudentBillingInlineFeedback('');
    if (options?.preserveDirty !== true) clearStudentConfigDirty();
    initStudentConfigUXBindings();
}

function getTrainerProfileStudioThemeSelection() {
    const selected = document.querySelector('input[name="trainer-theme-preset"]:checked');
    return normalizeTrainerThemePreset(selected?.value || TRAINER_THEME_PRESETS[0]);
}

function setTrainerProfileStudioThemeSelection(value = TRAINER_THEME_PRESETS[0]) {
    const normalized = normalizeTrainerThemePreset(value);
    const selected = document.querySelector(`input[name="trainer-theme-preset"][value="${normalized}"]`);
    if (selected) selected.checked = true;
}

function syncTrainerServicePresetUI(value = '') {
    const normalized = normalizeTrainerServices(value || document.getElementById('trainer-services')?.value || 'treino');
    document.querySelectorAll('#trainer-services-buttons [data-service]').forEach((button) => {
        const isActive = button.getAttribute('data-service') === normalized;
        button.classList.toggle('is-active', isActive);
        button.setAttribute('aria-pressed', isActive ? 'true' : 'false');
    });
}

function setTrainerServicePreset(value = 'treino') {
    const normalized = normalizeTrainerServices(value);
    const input = document.getElementById('trainer-services');
    if (input) input.value = normalized;
    syncTrainerServicePresetUI(normalized);
    syncTrainerProfileStudioLiveUI();
}

function addTrainerSpecialtyPreset(tag = '') {
    const value = sanitizeUserInput(tag, { maxLen: 40 });
    if (!value) return;
    if (trainerProfileDraftSpecialties.includes(value)) {
        showTrainerRuntimeMessage(`${value} já está nas especialidades.`, 'info');
        return;
    }
    trainerProfileDraftSpecialties = normalizeTrainerSpecialtiesList([...trainerProfileDraftSpecialties, value]);
    renderTrainerSpecialties(trainerProfileDraftSpecialties);
    syncTrainerProfileStudioLiveUI();
}

function setTrainerCtaPreset(label = '') {
    const safeLabel = sanitizeUserInput(label, { maxLen: 80 });
    const labelInput = document.getElementById('trainer-cta-label');
    if (labelInput) labelInput.value = safeLabel;
    const urlInput = document.getElementById('trainer-cta-url');
    const whatsappValue = document.getElementById('trainer-whatsapp')?.value || '';
    const phone = String(whatsappValue || '').replace(/\D/g, '');
    if (urlInput && safeLabel.toLowerCase().includes('whatsapp') && phone.length >= 10 && !String(urlInput.value || '').trim()) {
        urlInput.value = `https://wa.me/${phone}`;
    }
    syncTrainerProfileStudioLiveUI();
}

function calculateTrainerProfileCompleteness(stateLike = {}) {
    const state = stateLike || {};
    const socialLinks = normalizeTrainerSocialLinks(state.socialLinks || {});
    const checks = [
        !!sanitizeUserInput(state.displayName || '', { maxLen: 90 }),
        !!sanitizeUserInput(state.consultoriaName || '', { maxLen: 120 }),
        !!sanitizeUserInput(state.headline || '', { maxLen: 120 }),
        !!sanitizeUserInput(state.bio || '', { allowNewlines: true, maxLen: 400 }),
        !!normalizeTrainerHandle(state.handle || ''),
        !!normalizeTrainerServices(state.services || ''),
        normalizeTrainerSpecialtiesList(state.specialties || []).length > 0,
        !!(socialLinks.instagram || socialLinks.whatsapp || socialLinks.website),
        !!String(state.profilePhoto || '').trim(),
        !!String(state.profileCover || '').trim()
    ];
    const filled = checks.filter(Boolean).length;
    return Math.round((filled / checks.length) * 100);
}

function getTrainerHubStudentMetrics() {
    const students = readStorageJSON('trainerStudents', []);
    const code = getCurrentTrainerInviteCode();
    const scoped = code && code !== '00000'
        ? students.filter((student) => getStudentTrainerCodeValue(student) === code)
        : students;
    const active = scoped.filter((student) => student?.active && !student?.pending).length;
    const pending = scoped.filter((student) => student?.pending).length;
    return { total: scoped.length, active, pending };
}

function refreshTrainerHubUI(stateLike = null) {
    if (!document.getElementById('trainer-hub-operation')) return;
    const payload = getTrainerAccessPayload();
    const state = stateLike || (() => {
        try {
            if (document.getElementById('trainer-display-name')) return collectTrainerProfileStudioState();
        } catch {
            // Fallback below when the form is not ready.
        }
        return buildTrainerProfileStudioDraftFromSources(loadTrainerSettings(), currentTrainerIdentity || {});
    })();
    const metrics = getTrainerHubStudentMetrics();
    const completion = calculateTrainerProfileCompleteness(state);
    const hubDisplayName = sanitizeUserInput(state.displayName || payload.displayName, { maxLen: 90 }) || payload.displayName;
    const hubConsultoriaName = sanitizeUserInput(state.consultoriaName || payload.consultoriaName, { maxLen: 120 }) || payload.consultoriaName;

    const setText = (id, text) => {
        const el = document.getElementById(id);
        if (el) el.textContent = text;
    };
    setText('trainer-hub-consultoria', hubConsultoriaName);
    setText('trainer-hub-display-name', hubDisplayName);
    setText('trainer-hub-code', payload.code);
    setText('trainer-access-code', payload.code);
    setText('trainer-hub-students', String(metrics.total));
    setText('trainer-hub-active', String(metrics.active));
    setText('trainer-hub-pending', String(metrics.pending));
    setText('trainer-hub-progress-label', `${completion}%`);
    setText('trainer-access-message', `Aluno entra pelo app e informa o código ${payload.code} para solicitar vínculo.`);

    const accessLinkInput = document.getElementById('trainer-access-link');
    if (accessLinkInput) accessLinkInput.value = payload.link;
    const progress = document.getElementById('trainer-hub-progress');
    if (progress) progress.style.width = `${completion}%`;
    syncTrainerServicePresetUI(state.services);
}

function buildTrainerProfileStudioDraftFromSources(settings = loadTrainerSettings(), identity = currentTrainerIdentity || {}) {
    const displayName = sanitizeUserInput(settings.displayName || identity.displayName || identity.name || '', { maxLen: 90 })
        || sanitizeUserInput(identity.displayName || identity.name || memoryGetItem('trainerName') || 'Treinador', { maxLen: 90 })
        || 'Treinador';
    const firstName = sanitizeUserInput(displayName.split(' ')[0], { maxLen: 30 }) || 'Treinador';
    const consultoriaName = sanitizeUserInput(settings.consultoriaName || identity.consultoriaName || '', { maxLen: 120 }) || `Consultoria de ${firstName}`;
    const headline = sanitizeUserInput(settings.headline || identity.headline || '', { maxLen: 120 });
    const handle = normalizeTrainerHandle(settings.handle || identity.handle || suggestTrainerHandleFromName(displayName));
    const bio = sanitizeUserInput(settings.bio || identity.bio || '', { allowNewlines: true, maxLen: 400 });
    const services = normalizeTrainerServices(settings.services || identity.services || 'treino');
    const specialties = (Array.isArray(settings.specialties) && settings.specialties.length)
        ? normalizeTrainerSpecialtiesList(settings.specialties)
        : normalizeTrainerSpecialtiesList(identity.specialties || []);
    const socialLinks = normalizeTrainerSocialLinks({
        ...normalizeTrainerSocialLinks(identity.socialLinks || {}),
        ...normalizeTrainerSocialLinks(settings.socialLinks || {})
    });
    const paymentSettings = normalizeTrainerPaymentSettings(
        settings.paymentSettings
        || identity.paymentSettings
        || extractTrainerPaymentSettingsFromSocialLinks(identity.socialLinks || {})
    );
    const ctaLabel = sanitizeUserInput(settings.ctaLabel || identity.ctaLabel || '', { maxLen: 80 }) || 'Falar no WhatsApp';
    const ctaUrl = sanitizeUserInput(settings.ctaUrl || identity.ctaUrl || '', { maxLen: 320 });
    const themePreset = normalizeTrainerThemePreset(settings.themePreset || identity.themePreset || TRAINER_THEME_PRESETS[0]);

    return {
        displayName,
        consultoriaName,
        headline,
        handle,
        bio,
        services,
        specialties,
        socialLinks,
        paymentSettings,
        ctaLabel,
        ctaUrl,
        themePreset,
        profilePhoto: settings.profilePhoto || identity.avatarPreview || identity.avatarUrl || '',
        profileCover: settings.profileCover || identity.coverPreview || identity.coverUrl || '',
        brandLogo: settings.brandLogo || '',
        studentLimit: sanitizeUserInput(settings.studentLimit || '', { maxLen: 6 }),
        unitSystem: settings.unitSystem === 'imperial' ? 'imperial' : 'metric',
        macroFormula: sanitizeUserInput(settings.macroFormula || 'mifflin', { maxLen: 30 }) || 'mifflin',
        notifyEmail: !!settings.notifyEmail,
        notifyPush: !!settings.notifyPush
    };
}

function collectTrainerProfileStudioState() {
    const displayName = sanitizeUserInput(document.getElementById('trainer-display-name')?.value || '', { maxLen: 90 }) || 'Treinador';
    const firstName = sanitizeUserInput(displayName.split(' ')[0], { maxLen: 30 }) || 'Treinador';
    const consultoriaName = sanitizeUserInput(document.getElementById('trainer-consultoria-name')?.value || '', { maxLen: 120 }) || `Consultoria de ${firstName}`;
    const headline = sanitizeUserInput(document.getElementById('trainer-headline')?.value || '', { maxLen: 120 });
    const handle = normalizeTrainerHandle(document.getElementById('trainer-handle')?.value || '');
    const bio = sanitizeUserInput(document.getElementById('trainer-bio')?.value || '', { allowNewlines: true, maxLen: 400 });
    const services = normalizeTrainerServices(document.getElementById('trainer-services')?.value || 'treino');
    const specialties = normalizeTrainerSpecialtiesList(trainerProfileDraftSpecialties || []);
    const socialLinks = normalizeTrainerSocialLinks({
        instagram: document.getElementById('trainer-instagram')?.value || '',
        whatsapp: document.getElementById('trainer-whatsapp')?.value || '',
        website: document.getElementById('trainer-website')?.value || ''
    });
    const paymentSettings = normalizeTrainerPaymentSettings({
        enabled: !!document.getElementById('trainer-pix-enabled')?.checked,
        recipientName: document.getElementById('trainer-pix-recipient')?.value || '',
        monthlyAmountDefault: document.getElementById('trainer-pix-monthly-amount')?.value || '',
        pixCopyPaste: document.getElementById('trainer-pix-copy-paste')?.value || '',
        pixQrImage: trainerProfileDraftMedia?.pixQrImage || '',
        instructions: document.getElementById('trainer-pix-instructions')?.value || ''
    });
    const ctaLabel = sanitizeUserInput(document.getElementById('trainer-cta-label')?.value || '', { maxLen: 80 });
    const ctaUrlRaw = sanitizeUserInput(document.getElementById('trainer-cta-url')?.value || '', { maxLen: 320 }).trim();
    const ctaUrl = ctaUrlRaw ? sanitizeStrictUrl(ctaUrlRaw, { maxLen: 320, allowStorage: false }) : '';
    const themePreset = getTrainerProfileStudioThemeSelection();
    const unitSystem = document.querySelector('input[name="unit-system"]:checked')?.value === 'imperial' ? 'imperial' : 'metric';

    return {
        displayName,
        consultoriaName,
        headline,
        handle,
        bio,
        services,
        specialties,
        socialLinks,
        paymentSettings,
        ctaLabel,
        ctaUrlRaw,
        ctaUrl,
        themePreset,
        profilePhoto: trainerProfileDraftMedia.profilePhoto || '',
        profileCover: trainerProfileDraftMedia.profileCover || '',
        brandLogo: trainerProfileDraftMedia.brandLogo || '',
        studentLimit: sanitizeUserInput(document.getElementById('trainer-student-limit')?.value || '', { maxLen: 6 }),
        unitSystem,
        macroFormula: sanitizeUserInput(document.getElementById('trainer-macro-formula')?.value || 'mifflin', { maxLen: 30 }) || 'mifflin',
        notifyEmail: !!document.getElementById('notif-email')?.checked,
        notifyPush: !!document.getElementById('notif-push')?.checked
    };
}

function serializeTrainerProfileStudioState(stateLike = {}) {
    const safe = {
        displayName: sanitizeUserInput(stateLike.displayName || '', { maxLen: 90 }),
        consultoriaName: sanitizeUserInput(stateLike.consultoriaName || '', { maxLen: 120 }),
        headline: sanitizeUserInput(stateLike.headline || '', { maxLen: 120 }),
        handle: normalizeTrainerHandle(stateLike.handle || ''),
        bio: sanitizeUserInput(stateLike.bio || '', { allowNewlines: true, maxLen: 400 }),
        services: normalizeTrainerServices(stateLike.services || ''),
        specialties: normalizeTrainerSpecialtiesList(stateLike.specialties || []),
        socialLinks: normalizeTrainerSocialLinks(stateLike.socialLinks || {}),
        paymentSettings: normalizeTrainerPaymentSettings(stateLike.paymentSettings || {}),
        ctaLabel: sanitizeUserInput(stateLike.ctaLabel || '', { maxLen: 80 }),
        ctaUrlRaw: sanitizeUserInput(stateLike.ctaUrlRaw || '', { maxLen: 320 }).trim(),
        themePreset: normalizeTrainerThemePreset(stateLike.themePreset || ''),
        profilePhoto: String(stateLike.profilePhoto || ''),
        profileCover: String(stateLike.profileCover || ''),
        brandLogo: String(stateLike.brandLogo || ''),
        studentLimit: sanitizeUserInput(stateLike.studentLimit || '', { maxLen: 6 }),
        unitSystem: stateLike.unitSystem === 'imperial' ? 'imperial' : 'metric',
        macroFormula: sanitizeUserInput(stateLike.macroFormula || 'mifflin', { maxLen: 30 }) || 'mifflin',
        notifyEmail: !!stateLike.notifyEmail,
        notifyPush: !!stateLike.notifyPush
    };
    return JSON.stringify(safe);
}

function setTrainerProfileSavebarState(state = 'clean', customMessage = '') {
    const bar = document.getElementById('trainer-profile-savebar');
    const label = document.getElementById('trainer-profile-savebar-status');
    const btn = document.getElementById('trainer-profile-savebar-btn');
    if (!bar || !label || !btn) return;

    const map = {
        clean: 'Sem alterações pendentes',
        dirty: 'Alterações pendentes no perfil',
        saving: 'Salvando perfil...',
        saved: 'Perfil salvo com sucesso',
        error: 'Salvo localmente. Falha no sync remoto.'
    };
    bar.dataset.state = state;
    label.textContent = customMessage || map[state] || map.clean;

    if (state === 'saving') {
        btn.disabled = true;
        btn.innerHTML = '<i class="ph-bold ph-spinner-gap"></i> Salvando...';
    } else if (state === 'saved') {
        btn.disabled = false;
        btn.innerHTML = '<i class="ph-bold ph-check"></i> Salvo';
    } else if (state === 'error') {
        btn.disabled = false;
        btn.innerHTML = '<i class="ph-bold ph-warning-circle"></i> Tentar sync novamente';
    } else {
        btn.disabled = false;
        btn.innerHTML = '<i class="ph-bold ph-floppy-disk"></i> Salvar perfil';
    }
}

function updateTrainerProfileDirtyState(forceState = '') {
    if (forceState === 'clean') {
        trainerProfileDraftDirty = false;
        setTrainerProfileSavebarState('clean');
        return;
    }
    const snapshot = serializeTrainerProfileStudioState(collectTrainerProfileStudioState());
    const isDirty = snapshot !== trainerProfileDraftBaseSnapshot;
    trainerProfileDraftDirty = isDirty || trainerProfileDraftHasRemoteError;
    if (trainerProfileDraftDirty) {
        setTrainerProfileSavebarState(trainerProfileDraftHasRemoteError ? 'error' : 'dirty');
    } else {
        setTrainerProfileSavebarState('clean');
    }
}

function hasTrainerProfilePendingChanges() {
    return !!trainerProfileDraftDirty;
}

function discardTrainerProfileDraftChanges() {
    trainerProfileDraftHasRemoteError = false;
    loadTrainerSettingsToUI();
}

function focusTrainerProfileForm() {
    const anchor = document.getElementById('trainer-profile-form-anchor');
    const focusField = document.getElementById('trainer-display-name')
        || document.getElementById('trainer-consultoria-name')
        || document.getElementById('trainer-bio');
    if (anchor) anchor.scrollIntoView({ behavior: 'smooth', block: 'start' });
    if (focusField) setTimeout(() => focusField.focus(), 120);
}

function setActiveTrainerConfigNavTarget(sectionId = '') {
    const safeId = String(sectionId || '').trim();
    const navButtons = document.querySelectorAll('#view-config .trainer-config-nav-btn');
    navButtons.forEach((button) => {
        const isActive = String(button?.dataset?.target || '') === safeId;
        button.classList.toggle('is-active', isActive);
        button.setAttribute('aria-pressed', isActive ? 'true' : 'false');
    });
}

function scrollTrainerConfigSection(sectionId = '') {
    const safeId = String(sectionId || '').trim();
    const target = document.getElementById(safeId);
    if (!target) return;
    setActiveTrainerConfigNavTarget(safeId);
    target.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function ensureTrainerConfigSectionNav() {
    const root = document.getElementById('view-config');
    if (!root || root.dataset.sectionNavBound === '1') return;
    root.dataset.sectionNavBound = '1';

    const supportedIds = TRAINER_CONFIG_SECTION_IDS.filter((id) => !!document.getElementById(id));
    if (!supportedIds.length || typeof window.IntersectionObserver !== 'function') return;

    const observer = new IntersectionObserver((entries) => {
        let bestEntry = null;
        entries.forEach((entry) => {
            if (!entry.isIntersecting) return;
            if (!bestEntry || entry.intersectionRatio > bestEntry.intersectionRatio) {
                bestEntry = entry;
            }
        });
        if (bestEntry?.target?.id) {
            setActiveTrainerConfigNavTarget(bestEntry.target.id);
        }
    }, { root: null, threshold: [0.2, 0.4, 0.65], rootMargin: '-15% 0px -45% 0px' });

    supportedIds.forEach((id) => {
        const section = document.getElementById(id);
        if (section) observer.observe(section);
    });
}

function setTrainerProfileInlineStatus(message = '', type = '') {
    const status = document.getElementById('trainer-profile-inline-status');
    if (!status) return;
    const safeMessage = sanitizeUserInput(message || '', { maxLen: 240 });
    status.textContent = safeMessage;
    status.classList.remove('info', 'success', 'error');
    if (type) status.classList.add(type);
    status.style.display = safeMessage ? 'inline-flex' : 'none';
}

function clearTrainerProfileFieldValidation() {
    ['trainer-cta-url', 'trainer-whatsapp', 'trainer-website'].forEach((fieldId) => {
        const field = document.getElementById(fieldId);
        if (field) field.classList.remove('field-invalid');
    });
}

function applyTrainerProfileFieldValidation(issues = []) {
    clearTrainerProfileFieldValidation();
    (Array.isArray(issues) ? issues : []).forEach((issue) => {
        const field = document.getElementById(issue?.field || '');
        if (field) field.classList.add('field-invalid');
    });
}

function validateTrainerProfileStudioState(state = {}, options = {}) {
    const live = !!options.live;
    const issues = [];

    const websiteRaw = sanitizeUserInput(document.getElementById('trainer-website')?.value || '', { maxLen: 320 }).trim();
    if (websiteRaw && !sanitizeStrictUrl(websiteRaw, { maxLen: 320, allowStorage: false })) {
        issues.push({
            field: 'trainer-website',
            message: 'Website inválido. Use um link completo (https://...).'
        });
    }

    const whatsappRaw = sanitizeUserInput(document.getElementById('trainer-whatsapp')?.value || '', { maxLen: 25 }).trim();
    if (whatsappRaw) {
        const digits = whatsappRaw.replace(/\D/g, '');
        if (digits.length > 0 && digits.length < 10) {
            issues.push({
                field: 'trainer-whatsapp',
                message: 'WhatsApp incompleto. Use DDD + número.'
            });
        }
    }

    if (state.ctaUrlRaw && !state.ctaUrl) {
        issues.push({
            field: 'trainer-cta-url',
            message: 'Link do CTA inválido. Use formato https://...'
        });
    }

    applyTrainerProfileFieldValidation(issues);

    if (issues.length > 0) {
        setTrainerProfileInlineStatus(issues[0].message, 'error');
        return { ok: false, issues, message: issues[0].message };
    }

    if (live && trainerProfileDraftDirty) {
        setTrainerProfileInlineStatus('Tudo certo para salvar.', 'success');
    } else if (!live) {
        setTrainerProfileInlineStatus('');
    }

    return { ok: true, issues: [], message: '' };
}

function renderTrainerSpecialties(tags) {
    const container = document.getElementById('trainer-specialty-tags');
    if (!container) return;
    if (!tags || tags.length === 0) {
        container.innerHTML = '<span class="settings-empty">Nenhuma especialidade adicionada.</span>';
        return;
    }
    container.innerHTML = tags.map((tag) => `
        <span class="settings-tag">
            ${escapeHTML(tag)}
            <button type="button" onclick="removeTrainerSpecialty('${tag.replace(/'/g, "\\'")}')">
                <i class="ph-bold ph-x"></i>
            </button>
        </span>
    `).join('');
}

function renderTrainerProfileStudioPreview(stateLike = {}) {
    const state = stateLike || collectTrainerProfileStudioState();
    const safeDisplayName = sanitizeUserInput(state.displayName || 'Treinador', { maxLen: 90 }) || 'Treinador';
    const safeHandle = normalizeTrainerHandle(state.handle || '');
    const safeHeadline = sanitizeUserInput(state.headline || '', { maxLen: 120 });
    const safeConsultoria = sanitizeUserInput(state.consultoriaName || '', { maxLen: 120 }) || `Consultoria de ${(safeDisplayName.split(' ')[0] || 'Treinador')}`;
    const safeBio = sanitizeUserInput(state.bio || '', { allowNewlines: true, maxLen: 400 }) || 'Complete seu perfil para aparecer para novos alunos.';
    const safeCtaLabel = sanitizeUserInput(state.ctaLabel || '', { maxLen: 80 }) || 'Chamada principal';
    const safeTheme = normalizeTrainerThemePreset(state.themePreset || TRAINER_THEME_PRESETS[0]);
    const safeServices = getTrainerServicesLabel(state.services);
    const safeSpecialties = normalizeTrainerSpecialtiesList(state.specialties || []);
    const safeSocialLinks = normalizeTrainerSocialLinks(state.socialLinks || {});
    const safePaymentSettings = normalizeTrainerPaymentSettings(state.paymentSettings || {});
    const socialChips = [];
    if (safeSocialLinks.instagram) socialChips.push('<span class="social-chip"><i class="ph-bold ph-instagram-logo"></i> Instagram</span>');
    if (safeSocialLinks.whatsapp) socialChips.push('<span class="social-chip"><i class="ph-bold ph-whatsapp-logo"></i> WhatsApp</span>');
    if (safeSocialLinks.website) socialChips.push('<span class="social-chip"><i class="ph-bold ph-globe"></i> Website</span>');
    const ctaHref = state.ctaUrl || '';

    const card = document.getElementById('trainer-profile-preview-card');
    if (card) {
        card.classList.remove('theme-neon-lime', 'theme-ocean-blue', 'theme-graphite');
        card.classList.add(`theme-${safeTheme}`);
    }
    const cover = document.getElementById('trainer-profile-preview-cover');
    if (cover) cover.style.backgroundImage = state.profileCover ? `url("${escHtml(state.profileCover)}")` : '';

    const avatar = document.getElementById('trainer-profile-preview-avatar');
    if (avatar) {
        avatar.innerHTML = state.profilePhoto
            ? `<img src="${escHtml(state.profilePhoto)}" alt="Avatar do treinador" loading="lazy" decoding="async">`
            : '<i class="ph-bold ph-user"></i>';
    }

    const nameEl = document.getElementById('trainer-profile-preview-name');
    if (nameEl) nameEl.textContent = safeDisplayName;
    const handleEl = document.getElementById('trainer-profile-preview-handle');
    if (handleEl) handleEl.textContent = safeHandle ? `@${safeHandle}` : '@treinador';
    const consultoriaEl = document.getElementById('trainer-profile-preview-consultoria');
    if (consultoriaEl) consultoriaEl.textContent = safeConsultoria;
    const headlineEl = document.getElementById('trainer-profile-preview-headline');
    if (headlineEl) headlineEl.textContent = safeHeadline || 'Headline profissional';
    const bioEl = document.getElementById('trainer-profile-preview-bio');
    if (bioEl) bioEl.textContent = safeBio;

    const servicesEl = document.getElementById('trainer-profile-preview-services');
    if (servicesEl) servicesEl.innerHTML = `<span class="social-chip">${escapeHTML(safeServices)}</span>`;

    const specialtiesEl = document.getElementById('trainer-profile-preview-specialties');
    if (specialtiesEl) {
        specialtiesEl.innerHTML = safeSpecialties.length
            ? safeSpecialties.map((tag) => `<span class="social-chip">${escapeHTML(tag)}</span>`).join('')
            : '<span class="settings-empty">Sem especialidades</span>';
    }

    const socialEl = document.getElementById('trainer-profile-preview-social');
    if (socialEl) {
        socialEl.innerHTML = socialChips.length
            ? socialChips.join('')
            : '<span class="settings-empty">Sem links sociais</span>';
    }

    const ctaEl = document.getElementById('trainer-profile-preview-cta');
    if (ctaEl) {
        ctaEl.textContent = safeCtaLabel;
        if (ctaHref) ctaEl.setAttribute('href', ctaHref);
        else ctaEl.setAttribute('href', '#');
    }

    const paymentStatusEl = document.getElementById('trainer-profile-preview-payment-status');
    const paymentHintEl = document.getElementById('trainer-profile-preview-payment-hint');
    const paymentQrEl = document.getElementById('trainer-profile-preview-payment-qr');
    if (paymentStatusEl) {
        const hasCorePixData = !!(safePaymentSettings.pixCopyPaste || safePaymentSettings.pixQrImage);
        paymentStatusEl.textContent = safePaymentSettings.enabled && hasCorePixData
            ? 'Pix ativo para cobrança'
            : 'Pix ainda não configurado';
    }
    if (paymentHintEl) {
        const fallbackHint = safePaymentSettings.instructions || 'Defina valor, chave copia-e-cola e QR para facilitar pagamentos.';
        paymentHintEl.textContent = fallbackHint;
    }
    if (paymentQrEl) {
        const qrImage = sanitizeImageDataUrl(safePaymentSettings.pixQrImage, { maxLen: 3_200_000 })
            || sanitizeStrictUrl(safePaymentSettings.pixQrImage, { maxLen: 4_000, allowStorage: true });
        if (qrImage) {
            paymentQrEl.innerHTML = `<img src="${escHtml(qrImage)}" alt="QR Code Pix" loading="lazy" decoding="async">`;
        } else {
            paymentQrEl.innerHTML = '<i class="ph-bold ph-qr-code"></i><span>Sem QR</span>';
        }
    }
    refreshTrainerHubUI(state);
}

function syncTrainerProfileStudioLiveUI() {
    const draft = collectTrainerProfileStudioState();
    renderTrainerProfileStudioPreview(draft);
    applyTrainerBranding({
        ...loadTrainerSettings(),
        ...draft,
        socialLinks: draft.socialLinks,
        specialties: draft.specialties
    });
    updateTrainerProfileDirtyState();
}

function handleTrainerProfileStudioInputEvent() {
    if (trainerProfileStudioSyncLock) return;
    syncTrainerProfileStudioLiveUI();
    validateTrainerProfileStudioState(collectTrainerProfileStudioState(), { live: true });
}

function bindTrainerProfileStudioBindings() {
    const configView = document.getElementById('view-config');
    if (!configView || configView.dataset.profileStudioBound === '1') return;
    configView.addEventListener('input', handleTrainerProfileStudioInputEvent);
    configView.addEventListener('change', handleTrainerProfileStudioInputEvent);

    const specialtyInput = document.getElementById('trainer-specialty-input');
    if (specialtyInput) {
        specialtyInput.addEventListener('keydown', (event) => {
            if (event.key !== 'Enter') return;
            event.preventDefault();
            addTrainerSpecialty();
        });
    }
    configView.dataset.profileStudioBound = '1';
}

function addTrainerSpecialty() {
    const input = document.getElementById('trainer-specialty-input');
    if (!input) return;
    const value = sanitizeUserInput(input.value, { maxLen: 40 });
    if (!value) return;
    if (trainerProfileDraftSpecialties.includes(value)) {
        input.value = '';
        return;
    }
    trainerProfileDraftSpecialties = normalizeTrainerSpecialtiesList([...trainerProfileDraftSpecialties, value]);
    renderTrainerSpecialties(trainerProfileDraftSpecialties);
    input.value = '';
    syncTrainerProfileStudioLiveUI();
}

function removeTrainerSpecialty(tag) {
    trainerProfileDraftSpecialties = normalizeTrainerSpecialtiesList(
        (trainerProfileDraftSpecialties || []).filter((item) => item !== tag)
    );
    renderTrainerSpecialties(trainerProfileDraftSpecialties);
    syncTrainerProfileStudioLiveUI();
}

function showTrainerProfileMediaMessage(message, type = 'info') {
    if (!message) return;
    if (typeof showDietRuntimeMessage === 'function') {
        showDietRuntimeMessage(message, type);
        return;
    }
    console.info(message);
}

async function readTrainerImageForProfile(file, { maxSize = 1500, quality = 0.84 } = {}) {
    if (!file) return '';
    if (file.size > MAX_TRAINER_MEDIA_BYTES) {
        showTrainerProfileMediaMessage(`Imagem maior que ${formatFileSize(MAX_TRAINER_MEDIA_BYTES)}. Envie um arquivo menor.`, 'error');
        return '';
    }
    if (!String(file.type || '').toLowerCase().startsWith('image/')) {
        showTrainerProfileMediaMessage('Formato inválido. Envie uma imagem.', 'error');
        return '';
    }
    try {
        const compressed = await compressImageToDataUrl(file, maxSize, quality);
        return sanitizeImageDataUrl(compressed, { maxLen: 3_200_000 }) || '';
    } catch (error) {
        console.warn('Trainer media compression failed, fallback to original', error);
        const rawDataUrl = await fileToDataUrl(file);
        return sanitizeImageDataUrl(String(rawDataUrl || ''), { maxLen: 3_200_000 }) || '';
    }
}

function renderTrainerPixQrPreview(imageValue = '') {
    const preview = document.getElementById('trainer-pix-qr-preview');
    if (!preview) return;
    const safeImage = sanitizeImageDataUrl(imageValue, { maxLen: 3_200_000 })
        || sanitizeStrictUrl(imageValue, { maxLen: 4_000, allowStorage: true });
    if (safeImage) {
        preview.style.backgroundImage = `url('${safeImage}')`;
        preview.classList.add('has-image');
        preview.textContent = '';
    } else {
        preview.style.backgroundImage = '';
        preview.classList.remove('has-image');
        preview.textContent = 'Sem QR';
    }
}

