function resolveCurrentTrainerStudentSelection(studentsInput = null) {
    const students = normalizeStudentsDietSchema(
        Array.isArray(studentsInput) ? studentsInput : readStorageJSON('trainerStudents', [])
    );
    let idx = -1;
    const selectedId = String(currentTrainerStudentId || '').trim();
    if (selectedId) {
        idx = students.findIndex((student) => String(student?.id || '') === selectedId);
    }
    if (idx < 0 && Number.isInteger(currentStudentIdx) && currentStudentIdx >= 0 && currentStudentIdx < students.length) {
        idx = currentStudentIdx;
    }
    if (idx < 0) {
        return { students, idx: -1, student: null, studentId: selectedId };
    }
    if (!canCurrentTrainerAccessStudent(students[idx])) {
        currentStudentIdx = null;
        currentTrainerStudentId = null;
        return { students, idx: -1, student: null, studentId: selectedId };
    }
    currentStudentIdx = idx;
    currentTrainerStudentId = String(students[idx]?.id || selectedId || '');
    return {
        students,
        idx,
        student: students[idx] || null,
        studentId: currentTrainerStudentId
    };
}

function persistCurrentTrainerStudentDraft(options = {}) {
    const syncModeRaw = String(options?.syncMode || 'local-only').trim().toLowerCase();
    const syncMode = ['local-only', 'batched', 'immediate'].includes(syncModeRaw) ? syncModeRaw : 'local-only';
    const syncDelayMs = parseInt(options?.syncDelayMs, 10) || BATCHED_STUDENTS_SYNC_DEFAULT_DELAY_MS;
    const expectedRevision = Number.isFinite(parseIntegerSafe(options?.expectedRevision))
        ? parseIntegerSafe(options.expectedRevision)
        : null;
    if (expectedRevision !== null && expectedRevision !== trainerPlanEditRevision) {
        return null;
    }
    const selection = resolveCurrentTrainerStudentSelection();
    if (selection.idx < 0 || !selection.student) return null;
    const selectedStudentId = String(selection.student?.id || '').trim();
    const canSkipUnchangedLocalSave = (
        syncMode === 'local-only'
        && expectedRevision === null
        && selectedStudentId
        && trainerPlanLastPersisted.studentId === selectedStudentId
        && trainerPlanLastPersisted.revision === trainerPlanEditRevision
    );
    if (canSkipUnchangedLocalSave) {
        return {
            students: selection.students,
            student: selection.student,
            idx: selection.idx
        };
    }

    const student = { ...(selection.student || {}) };
    student.workoutBlocks = JSON.parse(JSON.stringify(Array.isArray(workoutBlocks) ? workoutBlocks : []));
    student.mealBlocks = JSON.parse(JSON.stringify(Array.isArray(mealBlocks) ? mealBlocks : []));
    student.cardioPlan = JSON.parse(JSON.stringify(normalizeCardioPlanShape(trainerCardioPlan)));
    student.waterPlan = JSON.parse(JSON.stringify(normalizeWaterPlanShape(trainerWaterPlan)));
    student.routine = JSON.parse(JSON.stringify(normalizeRoutineShape(trainerRoutinePlan)));
    const dietMeta = (student.dietMeta && typeof student.dietMeta === 'object')
        ? { ...student.dietMeta }
        : {};
    const kcalInput = document.getElementById('diet-kcal-meta');
    const proteinInput = document.getElementById('diet-protein-meta');
    const carbInput = document.getElementById('diet-carb-meta');
    const fatInput = document.getElementById('diet-fat-meta');
    if (kcalInput) dietMeta.kcal = kcalInput.value || '';
    if (proteinInput) dietMeta.protein = proteinInput.value || '';
    if (carbInput) dietMeta.carb = carbInput.value || '';
    if (fatInput) dietMeta.fat = fatInput.value || '';
    student.dietMeta = dietMeta;
    applyTrainerDeftStateToStudent(student);
    student._localPlanRevision = trainerPlanEditRevision;
    student._localPlanUpdatedAt = new Date().toISOString();

    selection.students[selection.idx] = student;
    const persistResult = saveStudentData(selection.students, {
        syncMode,
        syncDelayMs,
        studentId: String(student.id || ''),
        expectedRevision
    });
    if (persistResult?.ok !== false && persistResult?.localOk !== false) {
        trainerPlanLastPersisted = {
            studentId: String(student.id || ''),
            revision: trainerPlanEditRevision
        };
    }
    renderTrainerDemoStudentPreview();
    return {
        students: selection.students,
        student,
        idx: selection.idx
    };
}

function queueStudentPlanLocalAutosave(delayMs = 360) {
    if (currentStudentIdx === null && !currentTrainerStudentId) return;
    if (workoutPlanAutosaveTimer) clearTimeout(workoutPlanAutosaveTimer);
    const sequence = ++trainerAutosaveSequence;
    const revisionSnapshot = trainerPlanEditRevision;
    const parsedDelay = parseInt(delayMs, 10) || 360;
    const safeDelay = hasStoragePressure()
        ? Math.max(900, parsedDelay)
        : Math.max(260, parsedDelay);
    workoutPlanAutosaveTimer = setTimeout(() => {
        if (sequence !== trainerAutosaveSequence) return;
        persistCurrentTrainerStudentDraft({ syncMode: 'local-only', expectedRevision: revisionSnapshot });
    }, safeDelay);
}

function normalizeText(value) {
    return (value || '')
        .toString()
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '');
}

function escapeHTML(str) {
    if (!str) return '';
    return String(str)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
}

function isTrainerDemoBenchActive() {
    return isTrainerEvaluationModeActive()
        && String(currentTrainerStudentId || '').trim() === String(ADMIN_STUDENT_CODE)
        && !!document.getElementById('trainer-student-profile-screen');
}

function setTrainerDemoSplitMode(active = false) {
    const enabled = !!active;
    const screen = document.getElementById('trainer-student-profile-screen');
    const layout = screen?.querySelector?.('.prof-editor-layout');
    const preview = document.getElementById('trainer-demo-student-preview');
    if (screen) screen.classList.toggle('trainer-demo-split-mode', enabled);
    if (layout) layout.classList.toggle('demo-split-active', enabled);
    if (!enabled && preview) preview.innerHTML = '';
}

function getTrainerDemoDietMetaDraft(baseMeta = {}) {
    const dietMeta = baseMeta && typeof baseMeta === 'object' ? { ...baseMeta } : {};
    const fieldMap = {
        kcal: 'diet-kcal-meta',
        protein: 'diet-protein-meta',
        carb: 'diet-carb-meta',
        fat: 'diet-fat-meta'
    };
    Object.entries(fieldMap).forEach(([key, id]) => {
        const input = document.getElementById(id);
        if (input) dietMeta[key] = input.value || '';
    });
    return dietMeta;
}

function getTrainerDemoStudentPreviewSnapshot() {
    if (!isTrainerDemoBenchActive()) return null;
    const selection = resolveCurrentTrainerStudentSelection();
    const storedDemoStudent = readStorageJSON('trainerStudents', [])
        .find((student) => String(student?.id || '') === String(ADMIN_STUDENT_CODE));
    const baseStudent = selection.student || storedDemoStudent || {};
    if (String(baseStudent?.id || ADMIN_STUDENT_CODE) !== String(ADMIN_STUDENT_CODE)) return null;
    return {
        ...baseStudent,
        id: ADMIN_STUDENT_CODE,
        name: ADMIN_STUDENT_NAME,
        trainerCode: EVALUATION_TRAINER_CODE,
        workoutBlocks: JSON.parse(JSON.stringify(Array.isArray(workoutBlocks) ? workoutBlocks : [])),
        mealBlocks: JSON.parse(JSON.stringify(Array.isArray(mealBlocks) ? mealBlocks : [])),
        cardioPlan: JSON.parse(JSON.stringify(normalizeCardioPlanShape(trainerCardioPlan))),
        waterPlan: JSON.parse(JSON.stringify(normalizeWaterPlanShape(trainerWaterPlan))),
        routine: JSON.parse(JSON.stringify(normalizeRoutineShape(trainerRoutinePlan))),
        dietMeta: getTrainerDemoDietMetaDraft(baseStudent.dietMeta || {}),
        _previewDirty: studentConfigDirty
    };
}

function formatTrainerDemoPreviewTimestamp(value) {
    const raw = value || new Date().toISOString();
    const date = new Date(raw);
    if (!Number.isFinite(date.getTime())) return 'agora';
    return date.toLocaleString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
    });
}

function buildTrainerDemoMetricCard(iconClass, label, value, hint = '') {
    return `
        <div class="demo-student-preview-metric">
            <i class="ph-bold ${iconClass}"></i>
            <span>${escapeHTML(label)}</span>
            <strong>${escapeHTML(value)}</strong>
            ${hint ? `<small>${escapeHTML(hint)}</small>` : ''}
        </div>
    `;
}

function buildTrainerDemoPreviewEmpty(message) {
    return `<div class="demo-student-preview-empty">${escapeHTML(message)}</div>`;
}

function buildTrainerDemoWorkoutPreview(blocks = []) {
    const safeBlocks = Array.isArray(blocks) ? blocks : [];
    if (safeBlocks.length === 0) {
        return buildTrainerDemoPreviewEmpty('Nenhum treino configurado ainda.');
    }
    return safeBlocks.slice(0, 4).map((block, idx) => {
        const exercises = Array.isArray(block?.exercises) ? block.exercises : [];
        const names = exercises
            .slice(0, 3)
            .map((exercise) => sanitizeUserInput(exercise?.nome || exercise?.name || 'Exercício', { maxLen: 60 }))
            .filter(Boolean);
        const extraCount = Math.max(0, exercises.length - names.length);
        const exerciseLine = names.length
            ? `${names.join(', ')}${extraCount ? ` +${extraCount}` : ''}`
            : 'Sem exercícios';
        return `
            <div class="demo-preview-list-item">
                <strong>${escapeHTML(sanitizeUserInput(block?.name || `Treino ${idx + 1}`, { maxLen: 80 }))}</strong>
                <span>${escapeHTML(`${exercises.length} exercício${exercises.length === 1 ? '' : 's'}`)}</span>
                <p>${escapeHTML(exerciseLine)}</p>
            </div>
        `;
    }).join('');
}

function buildTrainerDemoMealPreview(meals = []) {
    const safeMeals = Array.isArray(meals) ? meals : [];
    if (safeMeals.length === 0) {
        return buildTrainerDemoPreviewEmpty('Nenhuma refeição configurada ainda.');
    }
    return safeMeals.slice(0, 4).map((meal, idx) => {
        const items = Array.isArray(meal?.items) ? meal.items : [];
        const kcal = Math.round(items.reduce((total, item) => {
            const itemKcal = parseDecimalSafe(item?.kcal)
                || ((parseDecimalSafe(item?.prot) * 4) + (parseDecimalSafe(item?.carb) * 4) + (parseDecimalSafe(item?.gord) * 9));
            return total + (Number.isFinite(itemKcal) ? itemKcal : 0);
        }, 0));
        const names = items
            .slice(0, 3)
            .map((item) => sanitizeUserInput(item?.nome || item?.name || 'Alimento', { maxLen: 50 }))
            .filter(Boolean);
        const extraCount = Math.max(0, items.length - names.length);
        const itemLine = names.length
            ? `${names.join(', ')}${extraCount ? ` +${extraCount}` : ''}`
            : 'Sem alimentos';
        return `
            <div class="demo-preview-list-item">
                <strong>${escapeHTML(sanitizeUserInput(meal?.name || `Refeição ${idx + 1}`, { maxLen: 80 }))}</strong>
                <span>${escapeHTML(`${kcal} kcal`)}</span>
                <p>${escapeHTML(itemLine)}</p>
            </div>
        `;
    }).join('');
}

function buildTrainerDemoCardioPreview(cardioPlan = {}) {
    const cardio = normalizeCardioPlanShape(cardioPlan);
    const activeDays = (cardio.days || []).filter((day) => hasCardioPlanDayData(day));
    if (activeDays.length === 0 && !cardio.coachRecommendation) {
        return buildTrainerDemoPreviewEmpty('Cardio sem prescrição específica.');
    }
    const daysHtml = activeDays.slice(0, 4).map((day) => {
        const duration = sanitizeUserInput(day?.durationMin || '', { maxLen: 8 });
        const type = sanitizeUserInput(day?.type || 'Cardio', { maxLen: 80 });
        const intensityMeta = getCardioIntensityMeta(day?.intensityKey);
        const zoneMeta = getCardioZoneMeta(day?.zoneKey || cardio.baseZoneKey);
        return `
            <div class="demo-preview-list-item compact">
                <strong>${escapeHTML(day?.dayLabel || 'Dia')}</strong>
                <span>${escapeHTML(duration ? `${duration} min` : 'Livre')}</span>
                <p>${escapeHTML(`${type} · ${intensityMeta.shortLabel} · ${zoneMeta.key.toUpperCase()}`)}</p>
            </div>
        `;
    }).join('');
    return `
        <div class="demo-preview-note">
            Meta semanal: <strong>${escapeHTML(`${cardio.weeklyGoalMin || 120} min`)}</strong>
            ${cardio.coachRecommendation ? `<p>${escapeHTML(cardio.coachRecommendation)}</p>` : ''}
        </div>
        ${daysHtml || ''}
    `;
}

function buildTrainerDemoRoutinePreview(routine = {}) {
    const normalized = normalizeRoutineShape(routine);
    const habits = (normalized.habits || []).filter((habit) => habit.active !== false);
    const reminders = (normalized.reminders || []).filter((reminder) => reminder.active !== false);
    if (habits.length === 0 && reminders.length === 0) {
        return buildTrainerDemoPreviewEmpty('Rotina sem hábitos ou lembretes.');
    }
    return [...habits.map((habit) => ({ ...habit, kind: 'Hábito' })), ...reminders.map((reminder) => ({ ...reminder, kind: 'Lembrete' }))]
        .slice(0, 4)
        .map((item) => `
            <div class="demo-preview-list-item compact">
                <strong>${escapeHTML(item.title || item.kind)}</strong>
                <span>${escapeHTML(item.timeHHmm || '--:--')}</span>
                <p>${escapeHTML(`${item.kind} · ${item.recurrenceType === 'weekdays' ? 'dias fixos' : 'todos os dias'}`)}</p>
            </div>
        `).join('');
}

function renderTrainerDemoStudentPreview() {
    const root = document.getElementById('trainer-demo-student-preview');
    if (!root) return;
    const active = isTrainerDemoBenchActive();
    setTrainerDemoSplitMode(active);
    if (!active) return;

    const student = getTrainerDemoStudentPreviewSnapshot();
    if (!student) {
        root.innerHTML = buildTrainerDemoPreviewEmpty('Abra o Aluno Teste para ver a prévia.');
        return;
    }

    const blocks = Array.isArray(student.workoutBlocks) ? student.workoutBlocks : [];
    const meals = Array.isArray(student.mealBlocks) ? student.mealBlocks : [];
    const cardio = normalizeCardioPlanShape(student.cardioPlan);
    const water = normalizeWaterPlanShape(student.waterPlan);
    const routine = normalizeRoutineShape(student.routine);
    const exerciseCount = blocks.reduce((total, block) => total + (Array.isArray(block?.exercises) ? block.exercises.length : 0), 0);
    const foodCount = meals.reduce((total, meal) => total + (Array.isArray(meal?.items) ? meal.items.length : 0), 0);
    const cardioDays = (cardio.days || []).filter((day) => hasCardioPlanDayData(day));
    const waterCtx = resolveStudentWaterGoalContext(student, water);
    const activeHabits = (routine.habits || []).filter((habit) => habit.active !== false).length;
    const activeReminders = (routine.reminders || []).filter((reminder) => reminder.active !== false).length;
    const dietMeta = student.dietMeta || {};
    const statusText = student._previewDirty ? 'Rascunho' : 'Salvo no sandbox';
    const statusClass = student._previewDirty ? 'is-draft' : 'is-saved';
    const lastUpdate = formatTrainerDemoPreviewTimestamp(student._localPlanUpdatedAt || student.updatedAt || student.updated_at);

    root.innerHTML = `
        <div class="demo-student-preview-head">
            <div>
                <span class="demo-preview-kicker">Bancada de teste</span>
                <h3>Prévia do aluno</h3>
                <p>${escapeHTML(student.name || ADMIN_STUDENT_NAME)}</p>
            </div>
            <span class="demo-student-preview-status ${statusClass}">${escapeHTML(statusText)}</span>
        </div>

        <div class="demo-student-preview-metrics">
            ${buildTrainerDemoMetricCard('ph-barbell', 'Treino', `${blocks.length} bloco${blocks.length === 1 ? '' : 's'}`, `${exerciseCount} exercícios`)}
            ${buildTrainerDemoMetricCard('ph-fork-knife', 'Dieta', `${meals.length} refeiç${meals.length === 1 ? 'ão' : 'ões'}`, `${foodCount} alimentos`)}
            ${buildTrainerDemoMetricCard('ph-gauge', 'Cardio', `${cardioDays.length} dia${cardioDays.length === 1 ? '' : 's'}`, `${cardio.weeklyGoalMin || 120} min/sem`)}
            ${buildTrainerDemoMetricCard('ph-drop', 'Água', `${waterCtx.goalMl} ml`, `${formatWaterLiters(waterCtx.goalMl)} L`)}
        </div>

        <section class="demo-student-preview-section is-workout">
            <div class="demo-preview-section-title">
                <i class="ph-bold ph-barbell"></i>
                <span>Treino do aluno</span>
            </div>
            ${buildTrainerDemoWorkoutPreview(blocks)}
        </section>

        <section class="demo-student-preview-section is-diet">
            <div class="demo-preview-section-title">
                <i class="ph-bold ph-fork-knife"></i>
                <span>Dieta e macros</span>
            </div>
            <div class="demo-preview-macro-strip">
                <span>${escapeHTML(dietMeta.kcal || '--')} kcal</span>
                <span>${escapeHTML(dietMeta.protein || '--')}g P</span>
                <span>${escapeHTML(dietMeta.carb || '--')}g C</span>
                <span>${escapeHTML(dietMeta.fat || '--')}g G</span>
            </div>
            ${buildTrainerDemoMealPreview(meals)}
        </section>

        <section class="demo-student-preview-section is-cardio">
            <div class="demo-preview-section-title">
                <i class="ph-bold ph-gauge"></i>
                <span>Cardio</span>
            </div>
            ${buildTrainerDemoCardioPreview(cardio)}
        </section>

        <section class="demo-student-preview-section is-routine">
            <div class="demo-preview-section-title">
                <i class="ph-bold ph-calendar-check"></i>
                <span>Água e rotina</span>
            </div>
            <div class="demo-preview-note">
                Água: <strong>${escapeHTML(`${waterCtx.goalMl} ml/dia`)}</strong>
                <p>${escapeHTML(water.notes || waterCtx.originLabel)}</p>
            </div>
            <div class="demo-preview-note">
                Rotina: <strong>${escapeHTML(`${activeHabits} hábitos · ${activeReminders} lembretes`)}</strong>
            </div>
            ${buildTrainerDemoRoutinePreview(routine)}
        </section>

        <div class="demo-student-preview-footer">
            Última atualização: ${escapeHTML(lastUpdate)}
        </div>
    `;
}

function setTrainerProfileText(id, value) {
    const el = document.getElementById(id);
    if (el) el.textContent = value;
}

function parsePositiveNumber(value) {
    const parsed = parseDecimalSafe(value);
    return parsed > 0 ? parsed : null;
}

function formatProfileNumber(value, decimals = 0) {
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) return '--';
    const fixed = Number.isInteger(parsed) ? String(parsed) : parsed.toFixed(decimals);
    return fixed.replace('.', ',');
}

function formatProfileDateSafe(value, fallback = '--') {
    if (!value) return fallback;
    const date = new Date(value);
    if (!Number.isFinite(date.getTime())) return fallback;
    return formatDate(value).trim();
}

function getTrainerStudentStatusMeta(student = {}) {
    if (student.pending === true) {
        return { label: 'Pendente', className: 'warning' };
    }
    if (student.active === false) {
        return { label: 'Inativo', className: 'inactive' };
    }
    return { label: 'Ativo', className: 'active' };
}

function getTrainerStudentGenderLabel(value) {
    const normalized = normalizeText(value);
    if (normalized === 'm' || normalized.startsWith('masc')) return 'Masculino';
    if (normalized === 'f' || normalized.startsWith('fem')) return 'Feminino';
    return 'Não informado';
}

function getTrainerStudentMetricHistory(student = {}) {
    const history = Array.isArray(student.metricHistory) ? student.metricHistory.slice() : [];
    const currentWeight = parsePositiveNumber(student.weight || student.currentWeight);
    const currentHeight = parsePositiveNumber(student.height);
    const currentBodyFat = parsePositiveNumber(student.bodyFat || student.currentBF);
    if (currentWeight || currentHeight || currentBodyFat) {
        const latest = history[history.length - 1] || {};
        const latestDate = latest.date ? new Date(latest.date) : null;
        const currentDate = new Date();
        const hasFreshCurrent = latestDate && Number.isFinite(latestDate.getTime())
            && latestDate.toISOString().slice(0, 10) === currentDate.toISOString().slice(0, 10);
        if (!hasFreshCurrent) {
            history.push({
                date: student.updatedAt || student._localPlanUpdatedAt || student.joinedAt || currentDate.toISOString(),
                weight: currentWeight,
                height: currentHeight,
                bodyFat: currentBodyFat
            });
        }
    }
    return history
        .filter((entry) => entry && typeof entry === 'object')
        .sort((a, b) => {
            const aTime = new Date(a.date || 0).getTime();
            const bTime = new Date(b.date || 0).getTime();
            return (Number.isFinite(aTime) ? aTime : 0) - (Number.isFinite(bTime) ? bTime : 0);
        });
}

function getTrainerStudentCurrentBodyFat(student = {}, history = null) {
    const direct = parsePositiveNumber(student.bodyFat || student.currentBF);
    if (direct) return direct;
    const items = Array.isArray(history) ? history : getTrainerStudentMetricHistory(student);
    for (let i = items.length - 1; i >= 0; i -= 1) {
        const value = parsePositiveNumber(items[i]?.bodyFat);
        if (value) return value;
    }
    return null;
}

function getTrainerStudentActivityProfile(student = {}, anamnesis = null) {
    const explicit = sanitizeUserInput(
        student.activityLevel
        || student.activity
        || student.nivelAtividade
        || student.activity_level
        || student.prof_atividade
        || anamnesis?.rotina?.atividade
        || anamnesis?.rotina?.nivel_atividade
        || '',
        { maxLen: 120 }
    );
    if (explicit) {
        const normalized = normalizeText(explicit);
        let multiplier = null;
        if (normalized.includes('sedent')) multiplier = 1.2;
        else if (normalized.includes('leve')) multiplier = 1.375;
        else if (normalized.includes('moder')) multiplier = 1.55;
        else if (normalized.includes('alto') || normalized.includes('intenso')) multiplier = 1.725;
        return { label: explicit, hint: 'Informado no perfil', multiplier };
    }

    const days = Array.isArray(anamnesis?.treino?.dias) ? anamnesis.treino.dias.filter(Boolean).length : 0;
    if (days > 0) {
        return {
            label: `${days} dia${days === 1 ? '' : 's'}/semana`,
            hint: 'Dias disponíveis na anamnese',
            multiplier: null
        };
    }

    const workStyle = normalizeText(anamnesis?.rotina?.trabalho || '');
    const workMap = {
        sentado: 'Trabalho sentado',
        em_pe: 'Trabalho em pé',
        movimento: 'Trabalho em movimento'
    };
    if (workStyle && workMap[workStyle]) {
        return { label: workMap[workStyle], hint: 'Rotina de trabalho', multiplier: null };
    }

    return { label: 'Não informado', hint: 'Sem dado de atividade na anamnese', multiplier: null };
}

function getTrainerStudentLatestWorkouts(studentId) {
    const safeId = String(studentId || '');
    if (!safeId) return [];
    return readStorageJSON('workoutHistory', [])
        .filter((entry) => String(entry?.ID_Usuario || '') === safeId)
        .sort((a, b) => {
            const aTime = new Date(a?.Data_Treino || a?.date || 0).getTime();
            const bTime = new Date(b?.Data_Treino || b?.date || 0).getTime();
            return (Number.isFinite(bTime) ? bTime : 0) - (Number.isFinite(aTime) ? aTime : 0);
        });
}

function renderTrainerStudentHeader(student = {}) {
    const safeName = sanitizeUserInput(student.name || student.id || 'Aluno', { maxLen: 90 }) || 'Aluno';
    const status = getTrainerStudentStatusMeta(student);
    const nameEl = document.getElementById('prof-id-name');
    if (nameEl) {
        nameEl.textContent = safeName;
        const badge = document.createElement('span');
        badge.className = `badge ${status.className === 'inactive' ? 'inactive' : status.className}`;
        badge.textContent = status.label;
        nameEl.append(document.createTextNode(' '), badge);
    }

    const goalEl = document.getElementById('prof-goal');
    const safeGoal = sanitizeUserInput(student.goal || '', { maxLen: 120 }) || 'Sem objetivo definido';
    if (goalEl) {
        const normalizedGoal = normalizeText(safeGoal);
        const icon = document.createElement('i');
        icon.className = normalizedGoal.includes('perder') || normalizedGoal.includes('emagrec')
            ? 'ph-fill ph-fire'
            : 'ph-fill ph-barbell';
        icon.style.color = normalizedGoal.includes('perder') || normalizedGoal.includes('emagrec')
            ? '#ef4444'
            : 'var(--primary-color)';
        goalEl.replaceChildren(icon, document.createTextNode(` ${safeGoal}`));
    }
}

function renderTrainerProfileBadges(student = {}, activity = {}, latestWorkoutDate = null) {
    const container = document.getElementById('prof-overview-badges');
    if (!container) return;
    const status = getTrainerStudentStatusMeta(student);
    const activityMeta = getStudentActivityMeta(student);
    const badges = [
        { label: status.label, className: status.className },
        { label: activityMeta.statusText, className: activityMeta.badgeClass },
        { label: activity.label || 'Atividade não informada', className: 'neutral' }
    ];
    if (student.assessmentPending || student.pendingEvaluation) {
        badges.push({ label: 'Avaliação pendente', className: 'warning' });
    }
    if (latestWorkoutDate) {
        badges.push({ label: `Último treino ${formatRelativeDays(Math.max(0, diffDays(latestWorkoutDate, new Date())))}`, className: 'neutral' });
    }
    container.innerHTML = badges.map((badge) => `
        <span class="student-profile-badge ${escapeHTML(badge.className)}">${escapeHTML(badge.label)}</span>
    `).join('');
}

function renderTrainerProfileProgress(student = {}, history = []) {
    const list = document.getElementById('trainer-profile-progress-list');
    if (!list) return;
    const items = history.slice(-5).reverse();
    if (!items.length) {
        list.innerHTML = `
            <div class="student-profile-empty">
                <i class="ph-bold ph-chart-line-up"></i>
                <p>Sem medidas registradas para acompanhar evolução.</p>
            </div>
        `;
        return;
    }
    list.innerHTML = items.map((entry, index) => {
        const originalIndex = history.length - 1 - index;
        const prev = originalIndex > 0 ? history[originalIndex - 1] : null;
        const weight = parsePositiveNumber(entry.weight);
        const bodyFat = parsePositiveNumber(entry.bodyFat);
        const height = parsePositiveNumber(entry.height);
        const weightDelta = weight && prev?.weight ? getPercentDelta(weight, parseFloat(prev.weight)) : null;
        const bodyFatDelta = bodyFat && prev?.bodyFat ? getPercentDelta(bodyFat, parseFloat(prev.bodyFat)) : null;
        return `
            <div class="trainer-profile-progress-row">
                <div>
                    <strong>${escapeHTML(formatProfileDateSafe(entry.date, 'Sem data'))}</strong>
                    <span>${weight ? `${formatProfileNumber(weight, 1)} kg` : '-- kg'}${height ? ` · ${formatProfileNumber(height, 0)} cm` : ''}${bodyFat ? ` · ${formatProfileNumber(bodyFat, 1)}% gordura` : ''}</span>
                </div>
                <div class="trainer-profile-progress-deltas">
                    ${weightDelta !== null ? `<span class="${parseFloat(weightDelta) > 0 ? 'up' : parseFloat(weightDelta) < 0 ? 'down' : ''}">${parseFloat(weightDelta) > 0 ? '+' : ''}${escapeHTML(weightDelta)}% peso</span>` : '<span>Primeiro registro</span>'}
                    ${bodyFatDelta !== null ? `<span class="${parseFloat(bodyFatDelta) > 0 ? 'up' : parseFloat(bodyFatDelta) < 0 ? 'down' : ''}">${parseFloat(bodyFatDelta) > 0 ? '+' : ''}${escapeHTML(bodyFatDelta)}% gordura</span>` : ''}
                </div>
            </div>
        `;
    }).join('');
}

function renderTrainerProfileAdherence(student = {}, latestWorkouts = []) {
    const grid = document.getElementById('trainer-profile-adherence-grid');
    if (!grid) return;
    const now = new Date();
    const last30Start = new Date(now);
    last30Start.setDate(last30Start.getDate() - 30);
    const workouts30 = latestWorkouts.filter((entry) => {
        const date = new Date(entry?.Data_Treino || entry?.date || 0);
        return Number.isFinite(date.getTime()) && date >= last30Start;
    }).length;
    const planCount = Array.isArray(student.workoutBlocks) ? student.workoutBlocks.length : 0;
    const routine = normalizeRoutineShape(student.routine);
    const dueHabits = routine.habits.filter((habit) => isHabitDueToday(habit));
    const checkins = getTodayCheckinsMap(routine);
    const doneHabits = dueHabits.filter((habit) => checkins.has(String(habit.id || ''))).length;
    let dietLabel = 'Sem dieta registrada';
    if (typeof getDietDailyCompletion === 'function') {
        try {
            const completion = getDietDailyCompletion(student, getTodayDateKey());
            dietLabel = completion.total > 0 ? `${completion.done}/${completion.total} itens hoje (${completion.percent}%)` : 'Sem check-ins de dieta hoje';
        } catch (err) {
            dietLabel = 'Dieta sem dados de aderência';
        }
    }
    const billing = getStudentBillingSnapshot(student);

    const items = [
        { icon: 'ph-barbell', label: 'Treinos em 30 dias', value: String(workouts30), hint: planCount ? `${planCount} bloco${planCount === 1 ? '' : 's'} prescritos` : 'Sem plano de treino' },
        { icon: 'ph-check-square', label: 'Hábitos de hoje', value: `${doneHabits}/${dueHabits.length}`, hint: dueHabits.length ? 'Check-ins da rotina' : 'Sem hábitos para hoje' },
        { icon: 'ph-fork-knife', label: 'Dieta hoje', value: dietLabel, hint: 'Aderência do plano alimentar' },
        { icon: 'ph-currency-dollar', label: 'Financeiro', value: billing.statusLabel, hint: billing.monthLabel }
    ];

    grid.innerHTML = items.map((item) => `
        <article class="trainer-profile-adherence-card">
            <i class="ph-bold ${escapeHTML(item.icon)}"></i>
            <span>${escapeHTML(item.label)}</span>
            <strong>${escapeHTML(item.value)}</strong>
            <small>${escapeHTML(item.hint)}</small>
        </article>
    `).join('');
}

function renderTrainerProfileAlerts(student = {}, anamnesis = null) {
    const list = document.getElementById('trainer-profile-alerts-list');
    if (!list) return;
    const alerts = [];
    if (!anamnesis) {
        alerts.push({ type: 'warning', text: 'Anamnese ainda não encontrada.' });
    } else {
        const saude = anamnesis.saude || {};
        const rotina = anamnesis.rotina || {};
        const nutricao = anamnesis.nutricao || {};
        if (saude.dor === 'sim') alerts.push({ type: 'danger', text: `Dor/limitação: ${sanitizeUserInput(saude.dor_desc || 'detalhe não informado', { maxLen: 140 })}` });
        if (saude.med === 'sim') alerts.push({ type: 'warning', text: `Medicação contínua: ${sanitizeUserInput(saude.med_desc || 'detalhe não informado', { maxLen: 140 })}` });
        if (saude.cirurgia === 'sim') alerts.push({ type: 'warning', text: `Histórico de cirurgia: ${sanitizeUserInput(saude.cirurgia_desc || 'detalhe não informado', { maxLen: 140 })}` });
        if (Array.isArray(saude.condicoes) && saude.condicoes.length) alerts.push({ type: 'danger', text: `Condições médicas: ${saude.condicoes.map((item) => sanitizeUserInput(item, { maxLen: 40 })).join(', ')}` });
        if (Array.isArray(nutricao.restricoes) && nutricao.restricoes.length) alerts.push({ type: 'warning', text: `Restrições alimentares: ${nutricao.restricoes.map((item) => sanitizeUserInput(item, { maxLen: 40 })).join(', ')}` });
        const stress = parseIntegerSafe(rotina.estresse);
        if (stress >= 7) alerts.push({ type: 'warning', text: `Estresse alto: ${stress}/10.` });
        const sleep = parseDecimalSafe(rotina.sono);
        if (sleep > 0 && sleep < 6) alerts.push({ type: 'warning', text: `Sono baixo: ${formatProfileNumber(sleep, 1)}h por noite.` });
    }
    if (!studentHasWorkoutPlan(student)) alerts.push({ type: 'warning', text: 'Aluno ainda sem plano de treino estruturado.' });
    if (!Array.isArray(student.mealBlocks) || student.mealBlocks.length === 0) alerts.push({ type: 'warning', text: 'Aluno ainda sem plano alimentar.' });
    if (student.assessmentPending || student.pendingEvaluation) alerts.push({ type: 'info', text: 'Avaliação do treinador pendente.' });

    if (!alerts.length) {
        list.innerHTML = `
            <div class="student-profile-empty success">
                <i class="ph-bold ph-check-circle"></i>
                <p>Nenhum alerta relevante no momento.</p>
            </div>
        `;
        return;
    }

    list.innerHTML = alerts.slice(0, 8).map((alert) => `
        <div class="trainer-profile-alert ${escapeHTML(alert.type)}">
            <i class="ph-bold ${alert.type === 'danger' ? 'ph-warning-octagon' : alert.type === 'info' ? 'ph-info' : 'ph-warning-circle'}"></i>
            <span>${escapeHTML(alert.text)}</span>
        </div>
    `).join('');
}

function renderTrainerProfileNotes(student = {}) {
    const list = document.getElementById('trainer-profile-notes-list');
    if (!list) return;
    const notes = [];
    const pushNote = (label, value) => {
        const text = sanitizeUserInput(value || '', { allowNewlines: true, maxLen: 280 }).trim();
        if (text) notes.push({ label, text });
    };
    pushNote('Treinador', student.trainerNotes || student.coachNotes || student.notes || student.privateNotes);
    const progressLogs = Array.isArray(student.progressLogs) ? student.progressLogs : [];
    const latestProgress = progressLogs[progressLogs.length - 1];
    if (latestProgress?.notes) pushNote(`Evolução ${formatProfileDateSafe(latestProgress.date, '')}`.trim(), latestProgress.notes);
    pushNote('Cardio', student.cardioPlan?.coachRecommendation);
    pushNote('Água', student.waterPlan?.notes);
    pushNote('Financeiro', student.billingNotes);

    if (!notes.length) {
        list.innerHTML = `
            <div class="student-profile-empty">
                <i class="ph-bold ph-note-pencil"></i>
                <p>Sem observações rápidas registradas para este aluno.</p>
            </div>
        `;
        return;
    }

    list.innerHTML = notes.slice(0, 5).map((note) => `
        <article class="trainer-profile-note">
            <span>${escapeHTML(note.label)}</span>
            <p>${escapeHTML(note.text).replace(/\n/g, '<br>')}</p>
        </article>
    `).join('');
}

function renderTrainerStudentProfileOverview(student = {}) {
    if (!student || typeof student !== 'object') return;
    const safeName = sanitizeUserInput(student.name || student.id || 'Aluno', { maxLen: 90 }) || 'Aluno';
    const safeGoal = sanitizeUserInput(student.goal || '', { maxLen: 120 }) || 'Objetivo não informado.';
    const anamnesis = getStudentAnamnesisSource(student);
    const history = getTrainerStudentMetricHistory(student);
    const latestMetric = history[history.length - 1] || {};
    const prevMetric = history.length > 1 ? history[history.length - 2] : null;
    const weight = parsePositiveNumber(student.weight || latestMetric.weight);
    const height = parsePositiveNumber(student.height || latestMetric.height);
    const bodyFat = getTrainerStudentCurrentBodyFat(student, history);
    const age = parseIntegerSafe(student.age);
    const tmbCalc = calcTMBMifflin(weight, height, age, student.gender);
    const activity = getTrainerStudentActivityProfile(student, anamnesis);
    const dietKcal = parsePositiveNumber(student.dietMeta?.kcal);
    const registeredKcal = parsePositiveNumber(student.dailyKcal || student.gastoDiario || student.dailyCalories);
    const estimatedKcal = (!registeredKcal && !dietKcal && tmbCalc > 0 && activity.multiplier)
        ? Math.round(tmbCalc * activity.multiplier)
        : null;
    const calorieTarget = registeredKcal || dietKcal || estimatedKcal;
    const calorieHint = registeredKcal
        ? 'Registrado no aluno'
        : dietKcal
            ? 'Meta do plano alimentar'
            : estimatedKcal
                ? 'Estimado pela atividade'
                : 'Sem meta definida';
    const imc = weight && height ? parseFloat(calcIMC(weight, height)) : null;
    const weightDelta = weight && prevMetric?.weight ? getPercentDelta(weight, parseFloat(prevMetric.weight)) : null;
    const latestWorkouts = getTrainerStudentLatestWorkouts(student.id);
    const latestWorkout = latestWorkouts[0] || null;
    const latestWorkoutDate = latestWorkout
        ? new Date(latestWorkout.Data_Treino || latestWorkout.date || 0)
        : getLastWorkoutDateForStudent(student);
    const validLatestWorkoutDate = latestWorkoutDate && Number.isFinite(latestWorkoutDate.getTime()) ? latestWorkoutDate : null;

    renderTrainerStudentHeader(student);
    setTrainerProfileText('prof-overview-name', safeName);
    setTrainerProfileText('prof-overview-goal', safeGoal);
    setTrainerProfileText('prof-idade', age > 0 ? `${age} anos` : '--');
    setTrainerProfileText('prof-idade-hint', student.joinedAt ? `Aluno desde ${formatProfileDateSafe(student.joinedAt)}` : 'Nascimento não informado');
    setTrainerProfileText('prof-peso', weight ? `${formatProfileNumber(weight, 1)} kg` : '--');
    setTrainerProfileText('prof-peso-delta', weightDelta !== null ? `${parseFloat(weightDelta) > 0 ? '+' : ''}${weightDelta}% desde a última medida` : 'Sem histórico');
    setTrainerProfileText('prof-altura', height ? `${formatProfileNumber(height, 0)} cm` : '--');
    setTrainerProfileText('prof-imc', imc ? `IMC ${formatProfileNumber(imc, 1)} · ${getIMCLabel(imc)}` : 'IMC não calculado');
    setTrainerProfileText('prof-genero', getTrainerStudentGenderLabel(student.gender));
    setTrainerProfileText('prof-bodyfat', bodyFat ? `${formatProfileNumber(bodyFat, 1)}% gordura corporal` : 'Gordura não informada');
    setTrainerProfileText('prof-tmb', tmbCalc > 0 ? `${Math.round(tmbCalc)} kcal` : '--');
    setTrainerProfileText('prof-gasto', calorieTarget ? `${Math.round(calorieTarget)} kcal` : '--');
    setTrainerProfileText('prof-gasto-hint', calorieHint);
    setTrainerProfileText('prof-atividade', activity.label);
    setTrainerProfileText('prof-atividade-hint', activity.hint);
    setTrainerProfileText('prof-ultimo-treino', validLatestWorkoutDate ? formatRelativeDays(Math.max(0, diffDays(validLatestWorkoutDate, new Date()))) : '--');
    setTrainerProfileText(
        'prof-ultimo-treino-hint',
        latestWorkout
            ? `${formatProfileDateSafe(latestWorkout.Data_Treino || latestWorkout.date)} · ${sanitizeUserInput(latestWorkout.Nome_Treino || latestWorkout.title || 'Treino', { maxLen: 90 }) || 'Treino'}`
            : 'Sem registros'
    );
    renderTrainerProfileBadges(student, activity, validLatestWorkoutDate);
    renderTrainerProfileProgress(student, history);
    renderTrainerProfileAdherence(student, latestWorkouts);
    renderTrainerProfileAlerts(student, anamnesis);
    renderTrainerProfileNotes(student);
}


function openStudentProfileById(studentId) {
    openStudentProfile(studentId);
}

function openStudentProfile(studentRef) {
    if (isFullTabsResetModeEnabled()) {
        alert('Modo reset total ativo. O conteúdo das abas está desativado.');
        return;
    }
    const selection = resolveTrainerStudentByRef(studentRef);
    const s = selection.student;
    if (!s) {
        alert('Aluno não encontrado para este treinador.');
        return;
    }

    currentStudentIdx = selection.idx;
    currentTrainerStudentId = String(s.id || selection.studentId || '') || null;

    // Load existing plan data
    workoutBlocks = s.workoutBlocks ? JSON.parse(JSON.stringify(s.workoutBlocks)) : [];
    mealBlocks = s.mealBlocks ? JSON.parse(JSON.stringify(s.mealBlocks)) : [];
    trainerCardioPlan = normalizeCardioPlanShape(s.cardioPlan);
    trainerWaterPlan = normalizeWaterPlanShape(s.waterPlan);
    trainerRoutinePlan = normalizeRoutineShape(s.routine);
    resetTrainerWorkoutUiRuntimeState();
    loadTrainerDeftState(s);
    trainerDeftUiState.openDayEditor = '';
    trainerDeftUiState.dayEditorDraft = null;
    trainerDeftUiState.dayEditorExpandedMeals = {};
    trainerDeftUiState.dayEditorDragMealIdx = -1;
    trainerDeftUiState.dayEditorDropMealIdx = -1;
    trainerDeftUiState.foodPicker = {
        open: false,
        dayKey: '',
        mealIdx: -1,
        optionKey: 'A',
        itemIdx: -1,
        mode: 'add',
        query: ''
    };
    trainerDeftUiState.copyWizard = {
        open: false,
        step: 1,
        sourceKey: 'base',
        targetKeys: []
    };
    trainerDeftUiState.periodEditor = {
        open: false,
        periodId: '',
        draft: null
    };

    // Calculate TMB (Mifflin-St Jeor)
    const tmbCalc = calcTMBMifflin(s.weight, s.height, s.age, s.gender);
    const activity = getTrainerStudentActivityProfile(s, getStudentAnamnesisSource(s));
    const registeredKcal = parsePositiveNumber(s.dailyKcal || s.gastoDiario || s.dailyCalories);
    const dietKcal = parsePositiveNumber(s.dietMeta?.kcal);
    const kcalCalc = registeredKcal || dietKcal || (tmbCalc > 0 && activity.multiplier ? Math.round(tmbCalc * activity.multiplier) : 0);
    renderTrainerStudentProfileOverview(s);

    // Diet meta
    const activePeriod = getTrainerDeftActiveDietPeriod(trainerDeftState || {}, s);
    const diet = s.dietMeta || {};
    const dm = (id, val) => { const el = document.getElementById(id); if (el) el.value = val || ''; };
    dm('diet-kcal-meta', activePeriod?.kcal || diet.kcal);
    dm('diet-protein-meta', activePeriod?.protein || diet.protein);
    dm('diet-carb-meta', activePeriod?.carb || diet.carb);
    dm('diet-fat-meta', activePeriod?.fat || diet.fat);
    const tmbEl = document.getElementById('diet-tmb-value');
    if (tmbEl) tmbEl.textContent = tmbCalc > 0 ? `${Math.round(tmbCalc)} kcal` : '--';
    const gastoEl = document.getElementById('diet-gasto-value');
    if (gastoEl) gastoEl.textContent = kcalCalc > 0 ? `${kcalCalc} kcal` : '--';

    // Switch screens
    document.getElementById('trainer-dashboard-screen').classList.remove('active');
    document.getElementById('trainer-student-profile-screen').classList.add('active');
    document.body.classList.add('trainer-student-editor-open');
    setTrainerDemoSplitMode(isTrainerDemoBenchActive());

    // Render workout and open Perfil tab
    renderWorkoutBlocks();
    renderMeals();
    renderTrainerCardioPlanEditor();
    renderTrainerWaterPlanEditor();
    renderTrainerRoutineSettingsEditor();
    renderTrainerAnamnesisTab(s);
    loadStudentBillingConfigTab(s);
    clearStudentConfigDirty();
    switchProfileTab('perfil');
    renderTrainerWorkoutHistory(currentTrainerStudentId);
    renderTrainerDemoStudentPreview();
}

function openStudentProfileTab(studentRef, tabName, event) {
    if (event) event.stopPropagation();
    openStudentProfile(studentRef);
    setTimeout(() => {
        if (tabName) switchProfileTab(tabName);
    }, 0);
}

function openStudentTrainingEditor(studentRef, event) {
    if (event) event.stopPropagation();
    openStudentProfileTab(studentRef, 'treino');
}

function closeStudentProfile() {
    if (studentConfigDirty) {
        persistCurrentTrainerStudentDraft({ syncMode: 'local-only' });
    }
    setTrainerDemoSplitMode(false);
    document.body.classList.remove('trainer-student-editor-open');
    document.getElementById('trainer-student-profile-screen').classList.remove('active');
    document.getElementById('trainer-dashboard-screen').classList.add('active');
    currentStudentIdx = null;
    currentTrainerStudentId = null;
    trainerDeftState = null;
    trainerDeftUiState.openDayEditor = '';
    trainerDeftUiState.dayEditorDraft = null;
    trainerDeftUiState.foodPicker.open = false;
    trainerDeftUiState.copyWizard.open = false;
    trainerDeftUiState.periodEditor.open = false;
    trainerDeftUiState.periodEditor.periodId = '';
    trainerDeftUiState.periodEditor.draft = null;
    resetTrainerWorkoutUiRuntimeState();
}

